const DATA = [
  // ── lv1 (英検4級・中学基礎) ── 12問
  { id: "g001", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "She ___ a student at this school.", ja: "彼女はこの学校の生徒です。", answer: "is", choices: ["is","am","are","be","do"], expl: "主語がShe（三人称単数）なのでbe動詞はis。", rule: "be動詞の人称一致", kp: ["She → is"] },
  { id: "g002", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "They ___ soccer every Sunday.", ja: "彼らは毎週日曜にサッカーをする。", answer: "play", choices: ["play","plays","playing","played","to play"], expl: "主語がThey（複数）なので三単現のsは不要。every Sundayは現在の習慣。", rule: "一般動詞の現在形", kp: ["They → 原形"] },
  { id: "g003", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "I ___ breakfast this morning.", ja: "今朝、朝食を食べた。", answer: "had", choices: ["had","have","has","having","am having"], expl: "this morningは過去の時点を指すので過去形had。", rule: "過去形", kp: ["this morning → 過去形"] },
  { id: "g004", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "We ___ to the park tomorrow.", ja: "明日、公園に行く予定です。", answer: "will go", choices: ["will go","went","go","going","goes"], expl: "tomorrowは未来の時点。will + 動詞の原形で未来を表す。", rule: "未来形 will", kp: ["tomorrow → will"] },
  { id: "g005", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "Please look ___ this word in the dictionary.", ja: "この単語を辞書で調べてください。", answer: "up", choices: ["up","at","for","on","in"], expl: "look up = 調べる。look at = 見る、look for = 探す。", rule: "句動詞 look up", kp: ["look up = 調べる"] },
  { id: "g006", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "He is good ___ math.", ja: "彼は数学が得意だ。", answer: "at", choices: ["at","in","for","on","of"], expl: "be good at ~ = ～が得意。前置詞atが正解。", rule: "be good at", kp: ["good at = 得意"] },
  { id: "g007", diff: "lv1", axis: "logic", tags: ["eiken4"], stem: "___ you like coffee or tea?", ja: "コーヒーと紅茶、どちらが好きですか？", answer: "Do", choices: ["Do","Are","Is","Does","Can"], expl: "主語がyouで一般動詞likeの疑問文→Do you ...?", rule: "一般動詞の疑問文", kp: ["you + 一般動詞 → Do"] },
  { id: "g008", diff: "lv1", axis: "logic", tags: ["eiken4"], stem: "This is the book ___ I bought yesterday.", ja: "これは私が昨日買った本です。", answer: "that", choices: ["that","what","who","where","when"], expl: "先行詞がthe book（もの）で、関係代名詞の目的格。thatまたはwhichが正解。", rule: "関係代名詞 that（もの）", kp: ["もの → that/which"] },
  { id: "g009", diff: "lv1", axis: "trap", tags: ["eiken4"], stem: "There ___ many books on the shelf.", ja: "棚にはたくさんの本がある。", answer: "are", choices: ["are","is","have","has","be"], expl: "There is/are構文。booksが複数形なのでareが正解。", rule: "There is/are", kp: ["複数名詞 → are"] },
  { id: "g010", diff: "lv1", axis: "trap", tags: ["eiken4"], stem: "My brother ___ not like vegetables.", ja: "兄は野菜が好きではない。", answer: "does", choices: ["does","do","is","has","was"], expl: "三人称単数（my brother）の一般動詞の否定文→does not。", rule: "三単現の否定文", kp: ["三人称単数 → does not"] },
  { id: "g011", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "The children ___ playing in the garden now.", ja: "子どもたちは今庭で遊んでいる。", answer: "are", choices: ["are","is","was","were","be"], expl: "childrenは複数形、nowは現在進行形のシグナル→are playing。", rule: "現在進行形", kp: ["now + 複数 → are -ing"] },
  { id: "g012", diff: "lv1", axis: "logic", tags: ["eiken4"], stem: "I want something ___ drink.", ja: "何か飲み物がほしい。", answer: "to", choices: ["to","for","of","in","at"], expl: "something to drink = 飲むための何か。不定詞の形容詞的用法。", rule: "不定詞の形容詞的用法", kp: ["something to + 動詞原形"] },
  // ── lv2 (英検3級・高校入試) ── 15問
  { id: "g013", diff: "lv2", axis: "tense", tags: ["eiken3","juken"], stem: "She ___ in Tokyo since 2020.", ja: "彼女は2020年から東京に住んでいる。", answer: "has lived", choices: ["has lived","lived","lives","is living","was living"], expl: "since 2020は現在完了の継続用法のシグナル。主語がSheなのでhas lived。", rule: "現在完了（継続）", kp: ["since → 現在完了"] },
  { id: "g014", diff: "lv2", axis: "tense", tags: ["eiken3","juken"], stem: "I ___ already ___ lunch when he called.", ja: "彼が電話してきたとき、私はすでに昼食を食べ終えていた。", answer: "had ... eaten", choices: ["had ... eaten","have ... eaten","was ... eating","did ... eat","am ... eating"], expl: "calledより前に完了→過去完了 had eaten。alreadyが完了を示唆。", rule: "過去完了", kp: ["過去より前 → had + pp"] },
  { id: "g015", diff: "lv2", axis: "form", tags: ["eiken3","juken"], stem: "This cake was ___ by my mother.", ja: "このケーキは母が作ったものです。", answer: "made", choices: ["made","make","making","makes","to make"], expl: "was + 過去分詞で受動態。make → made。", rule: "受動態", kp: ["was/were + 過去分詞"] },
  { id: "g016", diff: "lv2", axis: "form", tags: ["eiken3","juken"], stem: "He speaks English ___ than his brother.", ja: "彼は兄よりも上手に英語を話す。", answer: "better", choices: ["better","good","best","well","more good"], expl: "well（上手に）の比較級はbetter。more goodは不可。", rule: "不規則比較級", kp: ["well → better → best"] },
  { id: "g017", diff: "lv2", axis: "vocab", tags: ["eiken3","toeic"], stem: "I'm looking forward ___ seeing you again.", ja: "またお会いできるのを楽しみにしています。", answer: "to", choices: ["to","for","at","in","of"], expl: "look forward to + 動名詞（-ing）。toは前置詞なので後ろは名詞/動名詞。", rule: "look forward to -ing", kp: ["forward to + -ing"] },
  { id: "g018", diff: "lv2", axis: "vocab", tags: ["eiken3","juken"], stem: "She is interested ___ Japanese culture.", ja: "彼女は日本文化に興味がある。", answer: "in", choices: ["in","at","on","for","to"], expl: "be interested in ~ = ～に興味がある。", rule: "be interested in", kp: ["interested in"] },
  { id: "g019", diff: "lv2", axis: "logic", tags: ["eiken3","juken"], stem: "The man ___ is standing over there is my uncle.", ja: "あそこに立っている男性は私の叔父です。", answer: "who", choices: ["who","which","what","where","whom"], expl: "先行詞がThe man（人）で主格→who。", rule: "関係代名詞 who（主格）", kp: ["人 + 主格 → who"] },
  { id: "g020", diff: "lv2", axis: "logic", tags: ["eiken3","juken"], stem: "If it ___ tomorrow, we will stay home.", ja: "明日雨が降ったら、家にいます。", answer: "rains", choices: ["rains","will rain","rained","is raining","rain"], expl: "時・条件を表す副詞節の中ではwillを使わず現在形。", rule: "時・条件の副詞節では現在形", kp: ["if節 → 現在形"] },
  { id: "g021", diff: "lv2", axis: "trap", tags: ["eiken3","juken"], stem: "I have ___ been to Kyoto.", ja: "私は一度も京都に行ったことがない。", answer: "never", choices: ["never","ever","already","yet","just"], expl: "「一度も～ない」= have never + 過去分詞。経験の否定。", rule: "現在完了（経験の否定）", kp: ["have never + pp"] },
  { id: "g022", diff: "lv2", axis: "trap", tags: ["eiken3","toeic"], stem: "He made me ___ the report again.", ja: "彼は私にレポートを書き直させた。", answer: "write", choices: ["write","to write","writing","wrote","written"], expl: "使役動詞 make + O + 原形不定詞。toは不要。", rule: "使役動詞 make + O + 原形", kp: ["make + O + 原形"] },
  { id: "g023", diff: "lv2", axis: "tense", tags: ["eiken3","juken"], stem: "When I arrived, the movie ___ already ___.", ja: "私が到着したとき、映画はすでに始まっていた。", answer: "had ... started", choices: ["had ... started","has ... started","was ... starting","did ... start","is ... starting"], expl: "arrived（過去）より前に映画が始まっていた→過去完了。", rule: "過去完了", kp: ["過去より前の完了 → had + pp"] },
  { id: "g024", diff: "lv2", axis: "form", tags: ["eiken3","juken"], stem: "The news ___ very surprising.", ja: "そのニュースはとても驚くべきものだった。", answer: "was", choices: ["was","were","are","have been","has"], expl: "newsは不可算名詞で単数扱い→was。", rule: "不可算名詞は単数扱い", kp: ["news → 単数"] },
  { id: "g025", diff: "lv2", axis: "logic", tags: ["eiken3","juken"], stem: "I don't know ___ he will come or not.", ja: "彼が来るかどうか分からない。", answer: "whether", choices: ["whether","what","that","which","how"], expl: "whether ... or not = ～かどうか。ifも使えるがor notの直前はwhether。", rule: "whether ... or not", kp: ["～かどうか → whether"] },
  { id: "g026", diff: "lv2", axis: "vocab", tags: ["eiken3","toeic"], stem: "Could you ___ me a favor?", ja: "お願いがあるのですが。", answer: "do", choices: ["do","make","give","take","have"], expl: "do someone a favor = 頼みを聞く。定型表現。", rule: "do a favor", kp: ["do me a favor"] },
  { id: "g027", diff: "lv2", axis: "trap", tags: ["eiken3","juken"], stem: "Neither Tom ___ Jerry was at the party.", ja: "トムもジェリーもパーティーにいなかった。", answer: "nor", choices: ["nor","or","and","but","with"], expl: "neither A nor B = AもBも～ない。neitherとnorはペア。", rule: "neither A nor B", kp: ["neither → nor"] },
  // ── lv3 (英検準2級・TOEIC 400-600) ── 13問
  { id: "g028", diff: "lv3", axis: "tense", tags: ["eikenpre2","toeic"], stem: "By the time you arrive, I ___ the work.", ja: "あなたが到着するまでに、私は仕事を終えているでしょう。", answer: "will have finished", choices: ["will have finished","will finish","have finished","finished","am finishing"], expl: "By the time + 現在形 → 主節は未来完了。未来のある時点までの完了。", rule: "未来完了", kp: ["By the time → will have + pp"] },
  { id: "g029", diff: "lv3", axis: "tense", tags: ["eikenpre2","toeic"], stem: "She ___ for three hours when I got home.", ja: "私が帰宅したとき、彼女は3時間勉強していた。", answer: "had been studying", choices: ["had been studying","has been studying","was studying","studied","has studied"], expl: "過去のある時点まで継続していた動作→過去完了進行形。for three hoursが継続を示す。", rule: "過去完了進行形", kp: ["過去の時点まで継続 → had been -ing"] },
  { id: "g030", diff: "lv3", axis: "form", tags: ["eikenpre2","toeic"], stem: "The report needs to be ___ by Friday.", ja: "そのレポートは金曜日までに提出される必要がある。", answer: "submitted", choices: ["submitted","submit","submitting","submits","submission"], expl: "need to be + 過去分詞 = ～される必要がある（受動態の不定詞）。", rule: "受動態の不定詞", kp: ["to be + 過去分詞"] },
  { id: "g031", diff: "lv3", axis: "form", tags: ["eikenpre2","toeic","juken"], stem: "The ___ of the new policy was announced yesterday.", ja: "新しい方針の導入が昨日発表された。", answer: "introduction", choices: ["introduction","introduce","introducing","introduced","introductory"], expl: "冠詞Theの後ろなので名詞が必要。introduce（動詞）→ introduction（名詞）。", rule: "品詞変換（動詞→名詞）", kp: ["The ___ of → 名詞"] },
  { id: "g032", diff: "lv3", axis: "vocab", tags: ["eikenpre2","toeic"], stem: "The meeting was postponed ___ the heavy rain.", ja: "大雨のため会議は延期された。", answer: "due to", choices: ["due to","because","although","despite","unless"], expl: "due to + 名詞 = ～のため。becauseの後は節(S+V)が必要。", rule: "due to + 名詞", kp: ["due to + 名詞 vs because + 節"] },
  { id: "g033", diff: "lv3", axis: "vocab", tags: ["eikenpre2","toeic"], stem: "Please refrain ___ using your phone during the meeting.", ja: "会議中は携帯電話の使用をお控えください。", answer: "from", choices: ["from","to","of","for","in"], expl: "refrain from -ing = ～を控える。", rule: "refrain from -ing", kp: ["refrain from"] },
  { id: "g034", diff: "lv3", axis: "logic", tags: ["eikenpre2","toeic","juken"], stem: "___ hard he tried, he couldn't solve the problem.", ja: "どんなに頑張っても、彼はその問題を解けなかった。", answer: "However", choices: ["However","Whatever","Whenever","Wherever","Although"], expl: "However + 形容詞/副詞 + S + V = どんなに～しても。hardは副詞。", rule: "複合関係副詞 however", kp: ["However + 副詞/形容詞"] },
  { id: "g035", diff: "lv3", axis: "logic", tags: ["eikenpre2","juken"], stem: "The city ___ I was born is very small.", ja: "私が生まれた町はとても小さい。", answer: "where", choices: ["where","which","that","what","when"], expl: "先行詞がThe city（場所）で、born in the city→関係副詞where。", rule: "関係副詞 where", kp: ["場所 → where"] },
  { id: "g036", diff: "lv3", axis: "trap", tags: ["eikenpre2","toeic"], stem: "I suggest that he ___ the meeting.", ja: "彼がその会議に出席することを提案する。", answer: "attend", choices: ["attend","attends","attended","attending","will attend"], expl: "suggest that + S + 原形（仮定法現在）。三単現のsは付かない。", rule: "仮定法現在（suggest/recommend）", kp: ["suggest that S + 原形"] },
  { id: "g037", diff: "lv3", axis: "trap", tags: ["eikenpre2","toeic","juken"], stem: "The number of students ___ increasing every year.", ja: "学生の数は毎年増加している。", answer: "is", choices: ["is","are","have been","were","has"], expl: "The number of ~ = ～の数（単数扱い）。A number of ~（多くの）は複数扱い。", rule: "The number of（単数）vs A number of（複数）", kp: ["The number of → 単数"] },
  { id: "g038", diff: "lv3", axis: "tense", tags: ["eikenpre2","toeic"], stem: "The project ___ completed by next Monday.", ja: "そのプロジェクトは来週の月曜日までに完了しているだろう。", answer: "will have been", choices: ["will have been","will be","has been","was","is being"], expl: "by next Monday（未来の期限）+ 受動態 → will have been + pp（未来完了受動態）。", rule: "未来完了受動態", kp: ["by 未来 + 受動 → will have been + pp"] },
  { id: "g039", diff: "lv3", axis: "form", tags: ["eikenpre2","toeic"], stem: "She found the lecture very ___.", ja: "彼女はその講義をとても退屈だと思った。", answer: "boring", choices: ["boring","bored","bore","boredom","boringly"], expl: "物・事が主語の場合は-ing形（boring）。人が感情を感じる場合は-ed形（bored）。ここではthe lectureが退屈→boring。", rule: "-ing形容詞 vs -ed形容詞", kp: ["物 → -ing, 人 → -ed"] },
  { id: "g040", diff: "lv3", axis: "vocab", tags: ["eikenpre2","toeic"], stem: "He succeeded ___ passing the exam.", ja: "彼は試験に合格した。", answer: "in", choices: ["in","to","at","for","on"], expl: "succeed in -ing = ～に成功する。succeed to ～は「～を継承する」の意味。", rule: "succeed in -ing", kp: ["succeed in = 成功する"] },
  // ── lv4 (英検2級・TOEIC 600-800) ── 7問
  { id: "g041", diff: "lv4", axis: "tense", tags: ["eiken2","toeic"], stem: "If I ___ about the meeting, I would have attended.", ja: "もし会議のことを知っていたら、出席していたのに。", answer: "had known", choices: ["had known","knew","have known","know","would know"], expl: "過去の事実に反する仮定→仮定法過去完了。If + had + pp, ... would have + pp。", rule: "仮定法過去完了", kp: ["If + had pp → would have pp"] },
  { id: "g042", diff: "lv4", axis: "form", tags: ["eiken2","toeic","juken"], stem: "___ from the top of the mountain, the city looked beautiful.", ja: "山頂から見ると、その街は美しく見えた。", answer: "Seen", choices: ["Seen","Seeing","See","Having seen","To see"], expl: "分詞構文。the city is seen（受動）→ Seen from ...。主語はthe city。", rule: "分詞構文（受動）", kp: ["受動の意味 → 過去分詞で開始"] },
  { id: "g043", diff: "lv4", axis: "logic", tags: ["eiken2","toeic"], stem: "Not only ___ he speak English, but he also speaks French.", ja: "彼は英語を話すだけでなく、フランス語も話す。", answer: "does", choices: ["does","do","is","can","has"], expl: "Not only + 倒置（疑問文の語順）。三単現なのでdoes he speak。", rule: "Not only の倒置", kp: ["Not only + 倒置"] },
  { id: "g044", diff: "lv4", axis: "vocab", tags: ["eiken2","toeic"], stem: "The manager insisted ___ seeing the documents himself.", ja: "マネージャーは自分で書類を確認することを主張した。", answer: "on", choices: ["on","in","to","for","at"], expl: "insist on -ing = ～することを主張する。", rule: "insist on -ing", kp: ["insist on"] },
  { id: "g045", diff: "lv4", axis: "trap", tags: ["eiken2","toeic"], stem: "I would rather you ___ smoking in this room.", ja: "この部屋ではタバコを吸わないでほしい。", answer: "didn't smoke", choices: ["didn't smoke","don't smoke","not smoke","won't smoke","hadn't smoked"], expl: "would rather + S + 過去形 = Sに～してほしい（仮定法）。否定はdidn't。", rule: "would rather S + 過去形", kp: ["would rather S + 過去形"] },
  { id: "g046", diff: "lv4", axis: "trap", tags: ["eiken2","toeic","juken"], stem: "It is high time we ___ a decision.", ja: "そろそろ決断すべき時だ。", answer: "made", choices: ["made","make","will make","have made","making"], expl: "It is (high) time + S + 過去形 = そろそろ～すべき時だ（仮定法）。", rule: "It is time S + 過去形", kp: ["It is time → 過去形"] },
  { id: "g047", diff: "lv4", axis: "logic", tags: ["eiken2","juken"], stem: "Had I known the truth, I ___ differently.", ja: "真実を知っていたら、違う行動をしていただろう。", answer: "would have acted", choices: ["would have acted","will act","would act","have acted","had acted"], expl: "Had I known = If I had known（ifの省略による倒置）。帰結節はwould have + pp。", rule: "仮定法過去完了（倒置）", kp: ["Had S + pp → would have + pp"] },
  // ── lv5 (英検準1級・TOEIC 800+) ── 3問
  { id: "g048", diff: "lv5", axis: "vocab", tags: ["eikenpre1","toeic"], stem: "The new regulation will come ___ effect next month.", ja: "新しい規制は来月施行される。", answer: "into", choices: ["into","in","to","on","with"], expl: "come into effect = 施行される、発効する。定型表現。", rule: "come into effect", kp: ["come into effect = 発効する"] },
  { id: "g049", diff: "lv5", axis: "trap", tags: ["eikenpre1","toeic"], stem: "Hardly ___ the presentation when the fire alarm went off.", ja: "プレゼンを始めたばかりで、火災報知器が鳴った。", answer: "had he begun", choices: ["had he begun","he had begun","has he begun","did he begin","he began"], expl: "Hardly + 倒置 + when ... = ～するやいなや。Hardly + had S + pp。", rule: "Hardly had S + pp when ...", kp: ["Hardly → 倒置 + 過去完了"] },
  { id: "g050", diff: "lv5", axis: "logic", tags: ["eikenpre1","toeic"], stem: "Were it not ___ his help, we could not have succeeded.", ja: "彼の助けがなかったら、成功できなかっただろう。", answer: "for", choices: ["for","of","to","with","by"], expl: "Were it not for ~ = If it were not for ~（もし～がなければ）。仮定法の倒置形。", rule: "Were it not for（仮定法倒置）", kp: ["Were it not for = もし～がなければ"] },
  { id: "g051", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "She ___ to school by bike yesterday.", ja: "彼女は昨日、自転車で学校へ行きました。", answer: "went", choices: ["went", "goes", "go", "is going", "has gone"], expl: "「yesterday（昨日）」は過去を示すシグナルなので過去形が必要。goの過去形は不規則変化でwent。", rule: "Simple Past Tense", kp: ["yesterdayは過去形のシグナル", "goの過去形はwent（不規則変化）"] },
  { id: "g052", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "My father ___ home late last night.", ja: "私の父は昨夜、遅く帰宅しました。", answer: "came", choices: ["came", "comes", "come", "is coming", "has come"], expl: "「last night（昨夜）」が過去を示すため過去形が必要。comeの過去形は不規則変化でcame。", rule: "Simple Past Tense", kp: ["last ~は過去形のシグナル", "comeの過去形はcame（不規則変化）"] },
  { id: "g053", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "There ___ a cat under the table.", ja: "テーブルの下に猫が1匹います。", answer: "is", choices: ["is", "are", "have", "has", "be"], expl: "「a cat（単数名詞）」が後に続くため、There is を使う。There haveという形は存在しない。", rule: "There is/are (Existential)", kp: ["There is + 単数名詞", "後続の名詞が単数か複数かで is/are を選ぶ"] },
  { id: "g054", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "Look! The baby ___ in her crib right now.", ja: "見て！赤ちゃんが今、ベビーベッドで眠っています。", answer: "is sleeping", choices: ["is sleeping", "sleeps", "sleeping", "are sleeping", "sleep"], expl: "「right now（今まさに）」は現在進行形のシグナル。主語がThe baby（単数）なのでis + -ingを使う。", rule: "Present Continuous", kp: ["right nowは現在進行形のシグナル", "単数主語 → is + V-ing"] },
  { id: "g055", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "We ___ dinner at the moment. Please call back later.", ja: "私たちは今夕食中です。後でかけ直してください。", answer: "are having", choices: ["are having", "have", "is having", "having", "had"], expl: "「at the moment（今この瞬間）」は現在進行形のシグナル。主語がWe（複数）なのでare + -ingを使う。", rule: "Present Continuous", kp: ["at the momentは現在進行形のシグナル", "複数主語 → are + V-ing"] },
  { id: "g056", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "She is not very good ___ cooking.", ja: "彼女は料理があまり得意ではありません。", answer: "at", choices: ["at", "in", "for", "with", "on"], expl: "「be good at ～」で「～が得意」という意味。inやforとは組み合わせない固定表現。", rule: "Be Good At + Noun/Gerund", kp: ["be good at = ～が得意", "good at / bad at / surprised at など前置詞は固定"] },
  { id: "g057", diff: "lv1", axis: "logic", tags: ["eiken4"], stem: "___ your sister play the piano?", ja: "あなたのお姉さんはピアノを弾きますか？", answer: "Does", choices: ["Does", "Do", "Is", "Has", "Are"], expl: "主語がyour sister（三人称単数）で一般動詞playを使うため、疑問文はDoesを使う。その後の動詞は原形のまま。", rule: "Yes/No Questions with Do/Does", kp: ["三人称単数の一般動詞疑問文 → Does + S + V(原形)", "be動詞とdo/doesは混在させない"] },
  { id: "g058", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "The window ___ broken by the strong wind.", ja: "窓は強風によって割られました。", answer: "was", choices: ["was", "is", "were", "be", "been"], expl: "受動態はbe動詞 + 過去分詞の形。文脈が過去（強風で割られた）なので過去形のwasを使う。", rule: "Passive Voice", kp: ["受動態 = be動詞 + 過去分詞", "時制に合わせたbe動詞の形を選ぶ"] },
  { id: "g059", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "English ___ spoken in many countries around the world.", ja: "英語は世界中の多くの国々で話されています。", answer: "is spoken", choices: ["is spoken", "speaks", "spoken", "is speak", "was spoken"], expl: "「話される」という受動の意味で現在の事実を述べているため is + 過去分詞(spoken)を使う。", rule: "Passive Voice", kp: ["受動態 = be動詞 + 過去分詞", "be動詞なしでは受動態にならない"] },
  { id: "g060", diff: "lv2", axis: "trap", tags: ["eiken3", "toeic", "juken"], stem: "The coach let the players ___ a break after the game.", ja: "コーチは試合後に選手たちを休憩させました。", answer: "take", choices: ["take", "to take", "taking", "took", "taken"], expl: "使役動詞letの後は目的語 + 原形不定詞（toなし）。「let + O + 動詞の原形」が正しい形。", rule: "Causative: Make + Object + Base Form", kp: ["let/make/have + O + 動詞の原形（toは不要）", "toを入れるのが典型的な誤り"] },
  { id: "g061", diff: "lv2", axis: "logic", tags: ["eiken3", "juken"], stem: "Neither the manager ___ the staff was informed about the change.", ja: "マネージャーもスタッフも、その変更について知らされていませんでした。", answer: "nor", choices: ["nor", "or", "and", "but", "either"], expl: "neitherと対になる接続詞はnor。「neither A nor B」で「AもBも～ない」を表す。orとは組み合わせない。", rule: "Neither...Nor (Correlative Conjunctions)", kp: ["neither...nor がペア", "動詞はBの名詞（norの後）に一致させる"] },
  { id: "g062", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "Her cooking is ___ than mine.", ja: "彼女の料理は私のよりも上手です。", answer: "better", choices: ["better", "more good", "gooder", "best", "well"], expl: "goodの比較級はbetter（不規則変化）。「more good」や「gooder」という形は存在しない。", rule: "Irregular Comparatives", kp: ["good → better → best（不規則変化）", "more goodやgooder は誤り"] },
  { id: "g063", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "His condition after the accident was ___ than expected.", ja: "事故後の彼の状態は、予想よりも悪かった。", answer: "worse", choices: ["worse", "more bad", "badder", "worst", "badly"], expl: "badの比較級はworse（不規則変化）。「more bad」や「badder」という形は存在しない。", rule: "Irregular Comparatives", kp: ["bad → worse → worst（不規則変化）", "more badやbadder は誤り"] },
  { id: "g064", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "The letter ___ written by a famous author two centuries ago.", ja: "その手紙は2世紀前に有名な作家によって書かれました。", answer: "was", choices: ["was", "is", "had", "were", "be"], expl: "受動態はbe動詞 + 過去分詞の構造。「two centuries ago」が過去を示すのでwas + writtenが正解。", rule: "Passive Voice", kp: ["受動態 = be動詞 + 過去分詞", "ago が付けば過去時制のbe動詞を使う"] },
  { id: "g065", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "The suspects ___ questioned by the police for several hours.", ja: "容疑者たちは数時間にわたって警察に尋問されました。", answer: "were", choices: ["were", "was", "are", "be", "been"], expl: "受動態でThe suspects（複数主語）なのでwere + 過去分詞。単数のwasは主語と一致しない。", rule: "Passive Voice", kp: ["複数主語の受動態 → were + 過去分詞", "be動詞は主語の数に一致させる"] },
  { id: "g066", diff: "lv3", axis: "form", tags: ["eikenpre2", "toeic", "juken"], stem: "The ___ of a new bridge over the river will take two years.", ja: "川に新しい橋を建設するには2年かかる予定です。", answer: "construction", choices: ["construction", "construct", "constructing", "constructed", "constructive"], expl: "冠詞Theの直後には名詞が必要。constructは動詞なのでここには置けない。派生名詞のconstructionが正解。", rule: "Word Formation: Verb to Noun", kp: ["冠詞(The/A) + ___ + of → 名詞形が必要", "construct → construction（派生名詞）"] },
  { id: "g067", diff: "lv3", axis: "form", tags: ["eikenpre2", "toeic", "juken"], stem: "The ___ of new safety guidelines was welcomed by all employees.", ja: "新しい安全ガイドラインの導入は、全従業員に歓迎されました。", answer: "introduction", choices: ["introduction", "introduce", "introducing", "introduced", "introductory"], expl: "冠詞Theの後に名詞が必要。introduceは動詞形なので不可。正しい派生名詞はintroduction。", rule: "Word Formation: Verb to Noun", kp: ["冠詞の後は名詞形", "introduce → introduction（派生名詞）"] },
  { id: "g068", diff: "lv3", axis: "tense", tags: ["eikenpre2", "toeic"], stem: "By the time the ambulance arrived, he ___ for over an hour.", ja: "救急車が到着した時には、彼は1時間以上待ち続けていました。", answer: "had been waiting", choices: ["had been waiting", "has been waiting", "was waiting", "had waited", "were waiting"], expl: "「過去の時点（arrived）までずっと継続していた動作」はhad been + -ing（過去完了進行形）で表す。", rule: "Past Perfect Continuous", kp: ["過去の時点まで継続 → had been + -ing", "for + 期間 + when/by the time → 過去完了進行形"] },
  { id: "g069", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "After years of practice, she finally succeeded ___ mastering the violin.", ja: "何年もの練習の末、彼女はついにバイオリンをマスターすることに成功しました。", answer: "in", choices: ["in", "to", "at", "on", "with"], expl: "「succeed in -ing」で「～することに成功する」という意味。toは使わない固定表現。", rule: "Succeed In + Gerund", kp: ["succeed in + -ing（toは不可）", "in以外の前置詞も誤り"] },
  { id: "g070", diff: "lv3", axis: "form", tags: ["eikenpre2", "toeic"], stem: "The documentary was ___, so I fell asleep halfway through.", ja: "そのドキュメンタリーは退屈だったので、途中で眠ってしまいました。", answer: "boring", choices: ["boring", "bored", "bore", "bores", "been boring"], expl: "主語がThe documentary（物・事）なので、感情を引き起こす側を表す-ing形（boring）を使う。bored は人の感情を表す。", rule: "Participle Adjectives: -ing vs -ed", kp: ["物・事が主語 → -ing形（boring, exciting）", "人が感じる側 → -ed形（bored, excited）"] },
  { id: "g071", diff: "lv4", axis: "form", tags: ["eiken2", "toeic", "juken"], stem: "___ by a professional chef, the dish tasted far better than we expected.", ja: "プロのシェフによって作られたので、その料理は私たちの期待よりもずっと美味しかった。", answer: "Prepared", choices: ["Prepared", "Preparing", "Prepare", "Having prepared", "To prepare"], expl: "主語（the dish）は「作られる側」なので、受動の分詞構文として過去分詞Preparedで文を始める。", rule: "Participial Phrase (Passive)", kp: ["主語が動作を受ける側 → 過去分詞で分詞構文を開始", "Preparingでは能動の意味になり誤り"] },
  { id: "g072", diff: "lv4", axis: "logic", tags: ["eiken2", "toeic"], stem: "Not only ___ the project on time, but she also exceeded all quality standards.", ja: "彼女はプロジェクトを期日通りに完成させただけでなく、すべての品質基準も超えました。", answer: "did she complete", choices: ["did she complete", "she completed", "she did complete", "does she complete", "had she completed"], expl: "否定語句「Not only」が文頭に来た場合、主節は倒置（助動詞 + S + 原形動詞）が必要。過去の文脈なのでdid she completeが正解。", rule: "Inversion after Not Only", kp: ["Not onlyが文頭 → 倒置（助動詞 + S + 動詞の原形）が必要", "倒置なしの語順は誤り"] },
  { id: "g073", diff: "lv4", axis: "form", tags: ["eiken2", "toeic", "juken"], stem: "___ in warm water, the fabric became soft and smooth.", ja: "温水に浸されたので、その布地は柔らかくなめらかになりました。", answer: "Soaked", choices: ["Soaked", "Soaking", "Soak", "Having soaked", "To soak"], expl: "主語the fabricは「浸される側」なので受動の分詞構文として過去分詞Soakedで始める。Soakingでは能動の意味になり不適切。", rule: "Participial Phrase (Passive)", kp: ["受動の分詞構文 → 過去分詞で開始", "主語が動作を受ける側かどうかを確認する"] },
  { id: "g074", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic", "juken"], stem: "It is high time the company ___ its outdated policies.", ja: "会社はそろそろ時代遅れの方針を見直すべき時です。", answer: "revised", choices: ["revised", "revise", "will revise", "has revised", "is revising"], expl: "「It is high time + S + 過去形」（仮定法的用法）で「そろそろ～すべき時だ」を表す。原形やwillは使わない。", rule: "It Is Time + Past Tense (Subjunctive)", kp: ["It is high time + S + 過去形（仮定法）", "原形やwillは使わない"] },
  { id: "g075", diff: "lv5", axis: "vocab", tags: ["eikenpre1", "toeic"], stem: "The revised labor law will come ___ force at the beginning of next year.", ja: "改正された労働法は来年の初めに施行されます。", answer: "into", choices: ["into", "in", "to", "under", "with"], expl: "「come into force」で「施行される、発効する」という意味の固定表現。inやtoでは成立しない。", rule: "Come Into Effect (Fixed Expression)", kp: ["come into force/effect = 施行される・発効する", "into が必須（in や to は不可）"] },
  { id: "g076", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "My sister ___ a doctor at the city hospital.", ja: "私の姉は市立病院の医師です。", answer: "is", choices: ["is", "are", "am", "be", "was"], expl: "主語 My sister は三人称単数なので、be動詞は is を使います。", rule: "be動詞の人称一致", kp: ["He/She/It → is", "主語の人称・数でbe動詞を決める"] },
  { id: "g077", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "Tom and Ken ___ best friends.", ja: "トムとケンは親友同士です。", answer: "are", choices: ["are", "is", "am", "be", "were"], expl: "Tom and Ken は複数主語なので be動詞は are を使います。am は I にのみ使えます。", rule: "be動詞の人称一致", kp: ["複数主語 → are", "and で結ばれた主語は複数扱い"] },
  { id: "g078", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "Our English teacher ___ a lot of jokes in class.", ja: "私たちの英語の先生は授業中によくジョークを言います。", answer: "tells", choices: ["tells", "tell", "told", "telling", "is tell"], expl: "主語 Our English teacher は三人称単数なので、一般動詞に -s を付けて tells とします。", rule: "一般動詞の三単現", kp: ["三人称単数現在 → 動詞に -s", "主語がhe/she/it相当かどうか確認する"] },
  { id: "g079", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "All the students ___ English after school on Fridays.", ja: "すべての生徒は毎週金曜日の放課後に英語を勉強します。", answer: "study", choices: ["study", "studies", "studied", "studying", "to study"], expl: "主語 All the students は複数なので動詞に -s は付けず、原形 study を使います。", rule: "一般動詞の三単現", kp: ["複数主語 → 動詞は原形のまま", "三単現の -s は三人称単数のみ"] },
  { id: "g080", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "Listen! Someone ___ the guitar in the next room right now.", ja: "聞いて！今、隣の部屋で誰かがギターを弾いています。", answer: "is playing", choices: ["is playing", "plays", "play", "played", "will play"], expl: "right now という語が現在進行中の動作を示しているため、現在進行形 is playing を使います。", rule: "現在進行形", kp: ["right now → 現在進行形 (am/is/are + V-ing)", "be動詞を忘れずに使う"] },
  { id: "g081", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "I ___ you a call as soon as I get home tomorrow.", ja: "明日、家に着いたらすぐに電話します。", answer: "will give", choices: ["will give", "will gives", "will to give", "give", "gave"], expl: "tomorrow があり未来の意志を表すため will を使います。will の後は必ず動詞の原形が続きます。", rule: "未来形 will", kp: ["tomorrow → will + 動詞原形", "will の後に -s や to は付けない"] },
  { id: "g082", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "My younger brother is not very good ___ swimming.", ja: "私の弟は水泳があまり得意ではありません。", answer: "at", choices: ["at", "in", "for", "on", "with"], expl: "「～が得意・不得意」は be good/bad at で表します。in や for は不可です。", rule: "be good at", kp: ["be good at + 名詞/-ing = ～が得意", "good at は前置詞 at とセット"] },
  { id: "g083", diff: "lv2", axis: "logic", tags: ["eiken3"], stem: "Could you give me something ___ eat? I'm starving.", ja: "何か食べるものをもらえますか？お腹がペコペコです。", answer: "to", choices: ["to", "for", "of", "with", "and"], expl: "something の後に動詞で修飾するときは something to + 動詞原形 の形を使います。for は不可です。", rule: "不定詞の形容詞的用法", kp: ["something to + 動詞原形 = ～するための何か", "-thing / -one / -where の後は to + 原形"] },
  { id: "g084", diff: "lv2", axis: "logic", tags: ["eiken3"], stem: "I'm not sure ___ the train will arrive on time or not.", ja: "電車が時間通りに着くかどうか分かりません。", answer: "whether", choices: ["whether", "what", "that", "if not", "which"], expl: "「～かどうか」は whether を使い、or not と組み合わせます。that や what は or not と共には使えません。", rule: "whether ... or not", kp: ["whether ... or not = ～かどうか", "or not と一緒に使えるのは whether のみ"] },
  { id: "g085", diff: "lv2", axis: "trap", tags: ["eiken3", "toeic"], stem: "We are all looking forward ___ working with the new team members.", ja: "私たちは皆、新しいチームメンバーと一緒に働くことを楽しみにしています。", answer: "to", choices: ["to", "for", "at", "of", "toward"], expl: "look forward to の to は前置詞なので、後ろには動名詞（-ing形）が続きます。", rule: "look forward to + -ing", kp: ["look forward to + -ing（to は前置詞）", "to の後に動詞の原形を置かないよう注意"] },
  { id: "g086", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "This year's harvest was much ___ than last year's due to the drought.", ja: "干ばつのせいで、今年の収穫量は昨年よりずっと悪かった。", answer: "worse", choices: ["worse", "more bad", "badder", "worst", "more worse"], expl: "bad の比較級は不規則変化で worse になります。more bad や badder は誤りです。", rule: "不規則比較級", kp: ["bad → worse → worst（不規則変化）", "more bad / badder は誤り"] },
  { id: "g087", diff: "lv2", axis: "tense", tags: ["eiken3", "juken", "toeic"], stem: "Before you ___ the building, please show your ID at the reception desk.", ja: "建物に入る前に、受付でIDを提示してください。", answer: "enter", choices: ["enter", "will enter", "entered", "are entering", "would enter"], expl: "Before が導く時の副詞節の中では、未来の内容でも現在形を使います。will enter は誤りです。", rule: "時・条件の副詞節では現在形", kp: ["before/when/if 節の中は現在形（未来でも）", "副詞節の中では will を使わない"] },
  { id: "g088", diff: "lv2", axis: "trap", tags: ["eiken3", "toeic", "juken"], stem: "The strict teacher made all the students ___ their essays three times.", ja: "その厳しい先生は生徒全員に作文を3回書き直させました。", answer: "rewrite", choices: ["rewrite", "to rewrite", "rewriting", "rewrote", "rewritten"], expl: "使役動詞 make は make + O + 動詞原形 の形を取ります。to や -ing は不要です。", rule: "使役動詞 make + O + 原形", kp: ["make + O + 動詞原形（to なし）", "make/let/have の後の目的語には原形不定詞"] },
  { id: "g089", diff: "lv2", axis: "logic", tags: ["eiken3", "juken"], stem: "Neither the president ___ the vice president was available for the interview.", ja: "社長も副社長も、そのインタビューには対応できませんでした。", answer: "nor", choices: ["nor", "or", "and", "but", "not"], expl: "neither と対をなすのは nor です。neither A nor B で「AもBも～ない」を表します。", rule: "neither A nor B", kp: ["neither ... nor = AもBも～ない", "neither の相関語は nor（or ではない）"] },
  { id: "g090", diff: "lv2", axis: "trap", tags: ["eiken3", "toeic"], stem: "I am really looking forward to ___ my old friends at the reunion next week.", ja: "来週の同窓会で旧友たちに会うのをとても楽しみにしています。", answer: "meeting", choices: ["meeting", "meet", "met", "be meeting", "have met"], expl: "look forward to の to は前置詞なので、後ろには動名詞 -ing 形が必要です。原形の meet は誤りです。", rule: "look forward to + -ing", kp: ["look forward to + V-ing（to は前置詞）", "to の直後に動詞原形を置くと誤り"] },
  { id: "g091", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "My performance in the competition was ___ than I had expected.", ja: "大会での私のパフォーマンスは、思っていたよりも良かった。", answer: "better", choices: ["better", "more good", "gooder", "more better", "best"], expl: "good の比較級は不規則変化で better になります。more good や gooder は誤りです。", rule: "不規則比較級", kp: ["good → better → best（不規則変化）", "more good は誤り"] },
  { id: "g092", diff: "lv3", axis: "form", tags: ["eikenpre2", "toeic"], stem: "These old files need to be ___ before the end of the fiscal year.", ja: "これらの古いファイルは、会計年度末までに整理される必要があります。", answer: "organized", choices: ["organized", "organize", "organizing", "be organized", "have organized"], expl: "主語 These old files は動作を受ける側なので、need to be + 過去分詞 の受動態不定詞を使います。", rule: "受動態の不定詞", kp: ["need to be + pp = ～される必要がある", "主語が動作を受ける側 → to be + 過去分詞"] },
  { id: "g093", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "Visitors are requested to refrain ___ taking photographs inside the museum.", ja: "来館者は博物館内での写真撮影を控えるよう求められています。", answer: "from", choices: ["from", "to", "of", "in", "about"], expl: "refrain from + -ing で「～を控える」を表します。to は使えません。", rule: "refrain from -ing", kp: ["refrain from + V-ing = ～を控える", "from を忘れずに入れる"] },
  { id: "g094", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic", "juken"], stem: "A number of volunteers ___ gathered to help clean up the park.", ja: "多くのボランティアが公園の清掃を手伝うために集まりました。", answer: "have", choices: ["have", "has", "is", "was", "having"], expl: "A number of は「多くの」という意味で複数扱いのため、動詞は複数形 have を使います。The number of なら単数扱いです。", rule: "The number of（単数）vs A number of（複数）", kp: ["A number of + 複数名詞 → 複数動詞", "The number of + 複数名詞 → 単数動詞"] },
  { id: "g095", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "After months of hard work, the team finally succeeded ___ developing the new software.", ja: "数ヶ月の努力の末、チームはついに新しいソフトウェアの開発に成功しました。", answer: "in", choices: ["in", "to", "at", "on", "for"], expl: "succeed in + -ing で「～に成功する」を表します。to は使えません。", rule: "succeed in -ing", kp: ["succeed in + V-ing = ～に成功する", "succeed to は「～を継ぐ」という別の意味"] },
  { id: "g096", diff: "lv3", axis: "form", tags: ["eikenpre2", "toeic", "juken"], stem: "The ___ of the new airport is expected to boost the regional economy.", ja: "新空港の建設は地域経済を活性化させることが期待されています。", answer: "construction", choices: ["construction", "construct", "constructing", "constructed", "constructive"], expl: "冠詞 The の直後には名詞が必要です。construct（動詞）ではなく派生名詞 construction が正解です。", rule: "品詞変換（動詞→名詞）", kp: ["冠詞(The/A) + ___ + of → 名詞形が必要", "construct → construction（派生名詞）"] },
  { id: "g097", diff: "lv3", axis: "tense", tags: ["eikenpre2", "toeic"], stem: "The engineers ___ on the problem for two days when the solution was finally found.", ja: "解決策がついに見つかったとき、技術者たちはその問題に2日間取り組み続けていた。", answer: "had been working", choices: ["had been working", "have been working", "were working", "worked", "had worked"], expl: "過去のある時点（解決策が見つかった時）まで継続していた動作を表すため、過去完了進行形 had been + -ing を使います。", rule: "過去完了進行形", kp: ["過去の時点まで継続 → had been + V-ing", "for + 期間が続く場合は完了進行形が自然"] },
  { id: "g098", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "Passengers are kindly asked to refrain ___ eating or drinking in the priority seats.", ja: "乗客の皆様には、優先席での飲食をお控えいただくようお願い申し上げます。", answer: "from", choices: ["from", "to", "in", "of", "against"], expl: "refrain from + -ing で「～を控える」を表します。from が必ず必要です。", rule: "refrain from -ing", kp: ["refrain from + V-ing（from は省略不可）", "prevent / prohibit も同じく from + -ing"] },
  { id: "g099", diff: "lv3", axis: "logic", tags: ["eikenpre2", "juken"], stem: "___ tired she felt, she never gave up on her dream.", ja: "どんなに疲れを感じていても、彼女は夢を諦めることはなかった。", answer: "However", choices: ["However", "Whatever", "Whenever", "Wherever", "Whoever"], expl: "「どんなに～しても」と形容詞 tired を修飾するには however を使います。whatever は名詞を修飾します。", rule: "複合関係副詞 however", kp: ["however + 形容詞/副詞 = どんなに～でも", "whatever は名詞を修飾するので形容詞単独には使えない"] },
  { id: "g100", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic"], stem: "If she ___ the instructions more carefully, she wouldn't have made so many mistakes.", ja: "もし彼女がもっと注意深く説明書を読んでいたら、あれほど多くのミスをしなかっただろう。", answer: "had read", choices: ["had read", "read", "has read", "would have read", "would read"], expl: "過去の事実に反する仮定を表す仮定法過去完了では、if節に had + 過去分詞を使います。", rule: "仮定法過去完了", kp: ["If + had + pp, would have + pp（仮定法過去完了）", "過去の事実と異なる仮定には had + pp"] },
  { id: "g101", diff: "lv4", axis: "vocab", tags: ["eiken2", "toeic"], stem: "The union representative insisted ___ reviewing the contract before signing it.", ja: "組合代表は署名する前に契約書を見直すことを主張しました。", answer: "on", choices: ["on", "to", "in", "for", "about"], expl: "insist on + -ing で「～することを主張する」を表します。insist to は誤りです。", rule: "insist on -ing", kp: ["insist on + V-ing = ～することを主張する", "on の後は動詞原形ではなく -ing 形"] },
  { id: "g102", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic"], stem: "If the management ___ the warning signs earlier, the financial crisis could have been avoided.", ja: "もし経営陣がもっと早く警告のサインに気づいていたら、財政危機は避けられていただろう。", answer: "had noticed", choices: ["had noticed", "noticed", "would notice", "have noticed", "would have noticed"], expl: "過去の事実に反する仮定法過去完了では if 節に had + 過去分詞を用います。", rule: "仮定法過去完了", kp: ["If + had + pp = 過去の事実に反する仮定", "帰結節は could/would have + pp"] },
  { id: "g103", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic"], stem: "If only we ___ a backup copy of the data, we wouldn't be in this situation now.", ja: "もしデータのバックアップコピーを作成していたなら、今こんな状況にはなっていないのに。", answer: "had made", choices: ["had made", "made", "have made", "would make", "would have made"], expl: "過去の事実に反する後悔・願望を表す If only の構文でも、仮定法過去完了を使って had + 過去分詞とします。", rule: "仮定法過去完了", kp: ["If only + had + pp = ～していたなら（後悔・願望）", "主節の would have + pp と対応させる"] },
  { id: "g104", diff: "lv5", axis: "vocab", tags: ["eikenpre1", "toeic"], stem: "The amended tax code will come ___ effect from the first day of next quarter.", ja: "改正された税法は、来四半期の初日から施行されます。", answer: "into", choices: ["into", "in", "to", "under", "on"], expl: "「施行される・発効する」は come into effect という固定表現です。in や to は使えません。", rule: "come into effect", kp: ["come into effect/force = 施行される・発効する", "into を in や to と混同しない"] },
  { id: "g105", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "My cat ___ on the sofa every afternoon.", ja: "私の猫は毎日午後ソファの上で寝ます。", answer: "sleeps", choices: ["sleeps", "sleep", "slept", "sleeping", "is sleep"], expl: "主語 My cat は三人称単数なので、一般動詞に -s を付けて sleeps とする。", rule: "一般動詞の三単現", kp: ["He/She/It + 動詞-s", "三人称単数主語には必ず-sを付ける"] },
  { id: "g106", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "My parents ___ very proud of me.", ja: "私の両親は私をとても誇りに思っています。", answer: "are", choices: ["are", "is", "am", "be", "were"], expl: "主語 My parents は複数なので、be動詞は are を使う。is は三人称単数用、am は I 専用。", rule: "be動詞の人称一致", kp: ["複数主語 → are", "I → am / He/She/It → is"] },
  { id: "g107", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "She ___ to the library last Saturday.", ja: "彼女は先週の土曜日に図書館へ行きました。", answer: "went", choices: ["went", "goes", "go", "going", "has gone"], expl: "last Saturday という過去の時間表現があるので、go の不規則過去形 went を使う。", rule: "過去形（規則・不規則）", kp: ["last ~ → 過去形", "go の過去形は went（不規則変化）"] },
  { id: "g108", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "Dad ___ a nap on the couch right now.", ja: "お父さんは今まさにソファで昼寝をしています。", answer: "is taking", choices: ["is taking", "takes", "take", "was taking", "has taken"], expl: "right now は現在進行中の動作を示すシグナルなので、am/is/are + V-ing の形を使う。", rule: "現在進行形", kp: ["right now → 現在進行形", "S + is/are + V-ing"] },
  { id: "g109", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "There ___ a beautiful park near our school.", ja: "私たちの学校の近くに美しい公園があります。", answer: "is", choices: ["is", "are", "have", "has", "be"], expl: "後続する名詞 a beautiful park は単数なので、There is を使う。There have / There has は存在表現として不可。", rule: "There is / There are", kp: ["There is + 単数名詞", "後ろの名詞の数でis/areを決める"] },
  { id: "g110", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "I ___ you tomorrow morning without fail.", ja: "明日の朝、必ずあなたに電話します。", answer: "will call", choices: ["will call", "will calls", "called", "am calling", "call"], expl: "tomorrow という未来の時間表現があるので S + will + 動詞原形 を使う。will の後は必ず原形。", rule: "未来形 will", kp: ["tomorrow → will + 動詞原形", "will の後は必ず原形（-s / -ed 不可）"] },
  { id: "g111", diff: "lv1", axis: "logic", tags: ["eiken4"], stem: "I'm hungry. Is there anything ___ eat in the fridge?", ja: "お腹が空いています。冷蔵庫に何か食べるものはありますか？", answer: "to", choices: ["to", "for", "of", "with", "about"], expl: "anything のような -thing + to + 動詞原形 の形（不定詞の形容詞的用法）が正しい。for + -ing や of + -ing は不可。", rule: "不定詞の形容詞的用法", kp: ["-thing / -one / -where + to + 動詞原形", "forやofではなくtoを使う"] },
  { id: "g112", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "I can't find my keys. I've been ___ for them everywhere.", ja: "鍵が見つかりません。どこでも探し続けています。", answer: "looking", choices: ["looking", "watching", "seeing", "finding", "searching"], expl: "look for は「探す」という意味の句動詞。この文では look for them（鍵を探す）が適切。", rule: "句動詞 look up / look for / look at", kp: ["look for = 探す", "look up = 調べる / look at = 見る"] },
  { id: "g113", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "She ___ in this city for ten years.", ja: "彼女はこの街に10年間住んでいます。", answer: "has lived", choices: ["has lived", "lived", "is living", "had lived", "was living"], expl: "for + 期間（ten years）は現在完了（継続）のシグナル。has lived が正解。単純過去の lived は for との組み合わせで継続を表せない。", rule: "現在完了（継続）", kp: ["for + 期間 → 現在完了 have/has + pp", "sinceは時点、forは期間"] },
  { id: "g114", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "When the train arrived, the passengers ___ already ___ for thirty minutes.", ja: "電車が到着したとき、乗客たちはすでに30分間待っていた。", answer: "had been waiting", choices: ["had been waiting", "have been waiting", "were waiting", "had waited", "waited"], expl: "過去のある時点（電車到着）より前から継続していた動作を表すので、過去完了進行形 had been + V-ing を使う。", rule: "過去完了進行形", kp: ["過去の時点まで動作が継続 → had been + -ing", "for / since + 過去完了進行形の組み合わせ"] },
  { id: "g115", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "After he ___ his homework, he can watch TV.", ja: "宿題が終わったら、テレビを見てもいいですよ。", answer: "finishes", choices: ["finishes", "will finish", "finished", "has finished", "finish"], expl: "After に導かれる時の副詞節では、未来のことでも現在形を使う。will finish は不可。", rule: "時・条件の副詞節では現在形", kp: ["after / when / before / until 節の中は現在形（未来でも）", "will は時・条件節に使えない"] },
  { id: "g116", diff: "lv2", axis: "form", tags: ["eiken3", "toeic"], stem: "The ___ you got from the doctor is very helpful.", ja: "医者からもらったアドバイスはとても役に立ちます。", answer: "advice", choices: ["advice", "advices", "advise", "informations", "datas"], expl: "advice は不可算名詞なので複数形 advices は存在しない。動詞 advise と混同しないよう注意。", rule: "不可算名詞は単数扱い", kp: ["advice / information / news → 不可算名詞（複数形なし）", "不可算名詞には a / -s を付けない"] },
  { id: "g117", diff: "lv2", axis: "trap", tags: ["eiken3", "toeic"], stem: "I'm really looking forward ___ visiting the new art museum next weekend.", ja: "来週末、新しい美術館を訪れることをとても楽しみにしています。", answer: "to", choices: ["to", "for", "of", "about", "at"], expl: "look forward to の to は前置詞なので、後ろには動名詞（-ing）が続く。to visit のように原形を続けるのは誤り。", rule: "look forward to + -ing", kp: ["look forward to + V-ing（to は前置詞）", "to の後は動名詞（原形ではない）"] },
  { id: "g118", diff: "lv2", axis: "logic", tags: ["eiken3", "juken"], stem: "She told me ___ the party would start at seven or not.", ja: "彼女はパーティーが7時に始まるかどうか教えてくれました。", answer: "whether", choices: ["whether", "what", "that", "which", "if"], expl: "or not と一緒に使えるのは whether のみ。that や what は or not と組み合わせられない。if は単独で使えるが or not を直後に置く場合は whether が自然。", rule: "whether ... or not", kp: ["whether + S + V + or not = ～かどうか", "or notと共に使うのはwhether"] },
  { id: "g119", diff: "lv2", axis: "logic", tags: ["eiken3", "juken"], stem: "Neither my brother ___ my sister likes spicy food.", ja: "私の兄も妹も辛い食べ物が好きではありません。", answer: "nor", choices: ["nor", "or", "and", "but", "not"], expl: "neither とペアになる接続詞は nor。or は either とペアで使う。動詞は B（my sister）に一致して likes（単数）となる。", rule: "neither A nor B", kp: ["neither A nor B（neitherのペアはnor）", "動詞はBに一致させる"] },
  { id: "g120", diff: "lv2", axis: "vocab", tags: ["eiken3", "toeic"], stem: "Would you ___ me a favor and pass me that file?", ja: "そのファイルを取っていただけませんか？", answer: "do", choices: ["do", "make", "give", "take", "get"], expl: "「頼みを聞く」は do + 人 + a favor という定型表現。make a favor / give a favor は誤り。", rule: "do someone a favor", kp: ["do a favor（doが正しい動詞）", "make a decision / take a break などと動詞を混同しない"] },
  { id: "g121", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "He ___ already ___ the lab before I got there.", ja: "私が着く前に、彼はすでに実験室を出ていた。", answer: "had left", choices: ["had left", "has left", "left", "was leaving", "leaves"], expl: "「私が着く（過去）」より前の出来事を表すので過去完了 had + pp を使う。現在完了 has left は過去の文脈では不可。", rule: "過去完了", kp: ["過去の文中でさらに前の出来事 → had + pp", "already / by the time などが過去完了のヒント"] },
  { id: "g122", diff: "lv3", axis: "tense", tags: ["eikenpre2", "toeic"], stem: "By the time the concert begins, we ___ for over an hour.", ja: "コンサートが始まるころには、私たちは1時間以上待っていることになります。", answer: "will have been waiting", choices: ["will have been waiting", "will wait", "will have waited", "have been waiting", "are waiting"], expl: "by the time + 現在形（未来の時点）という文脈で、それまで動作が継続していることを示すので未来完了進行形 will have been + V-ing が正解。", rule: "未来完了", kp: ["by the time + 現在形 → 未来完了系（will have pp）", "継続を強調するなら will have been + V-ing"] },
  { id: "g123", diff: "lv3", axis: "form", tags: ["eikenpre2", "toeic"], stem: "All the windows in this building need ___ before winter comes.", ja: "この建物のすべての窓は冬が来る前に修理される必要があります。", answer: "to be repaired", choices: ["to be repaired", "to repair", "repairing", "repaired", "being repaired"], expl: "主語 windows は修理される側なので、受動態の不定詞 to be + pp を使う。to repair では「窓が修理する」という意味になり誤り。", rule: "受動態の不定詞", kp: ["主語が動作を受ける側 → need to be + pp", "to repair（能動）と to be repaired（受動）を区別する"] },
  { id: "g124", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "The flight was canceled ___ the thick fog at the airport.", ja: "濃霧のためにフライトがキャンセルされました。", answer: "due to", choices: ["due to", "because", "since", "although", "despite"], expl: "due to の後には名詞句（the thick fog）が続く。because の後は S + V の節が必要なので the thick fog のみでは使えない。", rule: "due to + 名詞", kp: ["due to + 名詞句", "because + S + V（節）"] },
  { id: "g125", diff: "lv3", axis: "tense", tags: ["eikenpre2", "toeic"], stem: "The researchers ___ the data for six hours when the computer suddenly crashed.", ja: "コンピューターが突然クラッシュしたとき、研究者たちは6時間データを分析し続けていた。", answer: "had been analyzing", choices: ["had been analyzing", "have been analyzing", "were analyzing", "analyzed", "had analyzed"], expl: "過去のある時点（コンピュータがクラッシュした時）まで動作が継続していたことを表すので、過去完了進行形 had been + V-ing を使う。", rule: "過去完了進行形", kp: ["過去の時点まで動作継続 → had been + V-ing", "for / since と組み合わせて継続期間を示す"] },
  { id: "g126", diff: "lv3", axis: "tense", tags: ["eikenpre2", "toeic"], stem: "By the time she retires next year, she ___ for this company for thirty years.", ja: "来年退職するころには、彼女はこの会社で30年間働いていることになります。", answer: "will have worked", choices: ["will have worked", "will work", "has worked", "would have worked", "is working"], expl: "by the time + 現在形（未来の文脈）で、その時点までに完了している事柄を表すので未来完了 will have + pp を使う。", rule: "未来完了", kp: ["by + 未来の時点 → will have + pp", "by the time 節の中は現在形（will は不可）"] },
  { id: "g127", diff: "lv3", axis: "form", tags: ["eikenpre2", "toeic"], stem: "___ from outside, the old castle appeared completely deserted.", ja: "外から見ると、その古い城は完全に廃墟のように見えた。", answer: "Seen", choices: ["Seen", "Seeing", "See", "To see", "Having seen"], expl: "主語 the old castle は「見られる」側なので、受動の分詞構文 Seen（過去分詞）で始める。Seeing は能動の分詞構文で誤り。", rule: "分詞構文（受動）", kp: ["主語が受動 → 過去分詞で分詞構文を開始", "Seeing（能動）と Seen（受動）を区別する"] },
  { id: "g128", diff: "lv3", axis: "tense", tags: ["eikenpre2", "toeic"], stem: "He ___ on the project for two weeks when the client suddenly changed all the requirements.", ja: "クライアントが突然すべての要件を変更したとき、彼はそのプロジェクトに2週間取り組み続けていた。", answer: "had been working", choices: ["had been working", "has been working", "was working", "worked", "had worked"], expl: "過去の出来事（クライアントが要件を変更した）より前からその時点まで継続していた動作なので、過去完了進行形 had been + V-ing を使う。", rule: "過去完了進行形", kp: ["過去の時点まで継続 → had been + V-ing", "has been は現在完了進行形（過去の文脈には不可）"] },
  { id: "g129", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic"], stem: "If she ___ the email, she would have replied immediately.", ja: "もし彼女がそのメールを見ていたなら、すぐに返信していたでしょう。", answer: "had seen", choices: ["had seen", "saw", "has seen", "would have seen", "was seeing"], expl: "過去の事実に反する仮定（仮定法過去完了）では If + S + had + pp を使う。saw（仮定法過去）は現在・未来の非現実を表す。", rule: "仮定法過去完了", kp: ["過去の事実に反する仮定 → If + had + pp, would have + pp", "sawは仮定法過去（現在・未来の非現実）"] },
  { id: "g130", diff: "lv4", axis: "form", tags: ["eiken2", "toeic", "juken"], stem: "___ from space, the Earth looks like a beautiful blue marble.", ja: "宇宙から見ると、地球は美しい青いビー玉のように見えます。", answer: "Seen", choices: ["Seen", "Seeing", "To see", "See", "Having seen"], expl: "主語 the Earth は「見られる」側なので、受動の分詞構文として過去分詞 Seen で始める。Seeing（能動）では「地球が見ている」という誤った意味になる。", rule: "分詞構文（受動）", kp: ["主語が受動の関係 → 過去分詞で分詞構文を開始", "分詞構文の主語と分詞の関係（能動/受動）を確認する"] },
  { id: "g131", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic", "juken"], stem: "It is high time the children ___ to bed. It's past midnight.", ja: "もう真夜中を過ぎています。子どもたちはもうとっくに寝る時間です。", answer: "went", choices: ["went", "go", "will go", "have gone", "are going"], expl: "It is high time + S + 過去形 という仮定法的表現。現在形の go や will go は使えない。", rule: "It is (high) time + S + 過去形", kp: ["It is high time + S + 過去形（仮定法的用法）", "high timeの後はwillや現在形ではなく過去形"] },
  { id: "g132", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic"], stem: "If the engineer ___ the safety manual more carefully, the accident could have been avoided.", ja: "もしそのエンジニアが安全マニュアルをもっと注意深く読んでいたなら、その事故は防げたでしょう。", answer: "had read", choices: ["had read", "read", "would have read", "has read", "was reading"], expl: "過去の事実に反する仮定（仮定法過去完了）なので If 節は had + pp の形を使う。過去形 read では仮定法過去（現在の非現実）になる。", rule: "仮定法過去完了", kp: ["過去の非現実 → If + had + pp, could/would have + pp", "If 節と帰結節の時制を対応させる"] },
  { id: "g133", diff: "lv5", axis: "trap", tags: ["eikenpre1", "toeic"], stem: "Hardly ___ her speech when the audience burst into applause.", ja: "彼女がスピーチを終えるやいなや、聴衆は拍手喝采した。", answer: "had she finished", choices: ["had she finished", "she had finished", "did she finish", "had finished she", "was she finishing"], expl: "Hardly が文頭に来ると倒置が起き、had + S + pp の語順になる。Hardly の後に通常語順 she had は不可。また hardly とペアになるのは when（than ではない）。", rule: "Hardly had S pp when ...", kp: ["Hardly + had + S + pp + when（倒置が必要）", "hardlyのペアはwhen（thanはno sooner...thanと使う）"] },
  { id: "g134", diff: "lv5", axis: "logic", tags: ["eikenpre1", "toeic"], stem: "No sooner ___ the door than the lights went out.", ja: "ドアを閉めるやいなや、電気が消えた。", answer: "had he closed", choices: ["had he closed", "he had closed", "did he close", "he closed", "has he closed"], expl: "No sooner が文頭に来ると倒置が起き、had + S + pp の語順になる。No sooner ... than は「～するやいなや」という意味で Hardly ... when と同じ構造を持つ。", rule: "Hardly had S pp when ...", kp: ["No sooner + had + S + pp + than（倒置）", "No sooner...than / Hardly...when のペアを覚える"] },
  { id: "g135", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "My uncle ___ a police officer in this city.", ja: "私のおじはこの街の警察官です。", answer: "is", choices: ["is", "are", "am", "be", "was"], expl: "主語 'My uncle' は三人称単数なので、be動詞は 'is' を使います。'are' は You/We/They に使い、'am' は I のみです。", rule: "be動詞の人称一致 (Subject-Verb Agreement with Be)", kp: ["三人称単数 → is", "am は I のみ、are は You/We/They"] },
  { id: "g136", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "The students in this class ___ very hardworking.", ja: "このクラスの生徒たちはとても勤勉です。", answer: "are", choices: ["are", "is", "am", "be", "was"], expl: "主語 'The students' は複数名詞なので、be動詞は 'are' を使います。", rule: "be動詞の人称一致 (Subject-Verb Agreement with Be)", kp: ["複数主語 → are", "単数主語 → is"] },
  { id: "g137", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "My grandfather ___ the newspaper every morning without fail.", ja: "私の祖父は毎朝欠かさず新聞を読みます。", answer: "reads", choices: ["reads", "read", "is reading", "to read", "readed"], expl: "主語 'My grandfather' は三人称単数で、習慣を表す現在形なので動詞に -s を付けた 'reads' が正解です。", rule: "一般動詞の三単現 (Third Person Singular -s)", kp: ["三人称単数 + 習慣・事実 → 動詞に -s", "複数主語や I/You では原形"] },
  { id: "g138", diff: "lv1", axis: "logic", tags: ["eiken4"], stem: "___ your brother walk to school every day?", ja: "あなたのお兄さんは毎日歩いて学校に行きますか？", answer: "Does", choices: ["Does", "Do", "Is", "Are", "Did"], expl: "'your brother' は三人称単数の一般動詞の疑問文なので 'Does' を使い、動詞は原形 'walk' のままにします。", rule: "一般動詞の疑問文 (Yes/No Questions with Do/Does)", kp: ["三人称単数の疑問文 → Does + 原形", "be動詞の疑問文と混同しない"] },
  { id: "g139", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "We ___ a long walk in the forest last Sunday.", ja: "私たちは先週の日曜日に森の中を長い間散歩しました。", answer: "took", choices: ["took", "take", "takes", "have taken", "taking"], expl: "'last Sunday' は過去を示す表現なので過去形が必要です。'take' の過去形は不規則変化で 'took' です。", rule: "過去形（規則・不規則） (Simple Past Tense)", kp: ["last ~ / yesterday / ago → 過去形", "take の過去形は took（不規則）"] },
  { id: "g140", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "I ___ finish all this work by tonight.", ja: "私は今夜までにこの仕事を全部終わらせるつもりです。", answer: "will", choices: ["will", "am", "was", "would", "shall to"], expl: "未来の意志や予定を表す場合は 'will + 動詞原形' を使います。'will' の後の動詞は原形 'finish' のままです。", rule: "未来形 will (Future with Will)", kp: ["未来 → will + 動詞原形", "will の後に to は不要"] },
  { id: "g141", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "Please be quiet. My little sister ___ sleeping right now.", ja: "静かにしてください。妹が今ちょうど眠っています。", answer: "is", choices: ["is", "are", "was", "be", "does"], expl: "'right now' は現在進行形のシグナルです。主語 'My little sister' は三人称単数なので 'is sleeping' が正しい形です。", rule: "現在進行形 (Present Continuous)", kp: ["now / right now → be + V-ing（進行形）", "三人称単数 → is + V-ing"] },
  { id: "g142", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "There ___ a large swimming pool behind the school.", ja: "学校の裏に大きなプールが一つあります。", answer: "is", choices: ["is", "are", "have", "has", "be"], expl: "後続の名詞 'a large swimming pool' は単数なので 'There is' を使います。複数名詞には 'There are' が必要です。", rule: "There is / There are (There is/are (Existential))", kp: ["There is + 単数名詞", "There are + 複数名詞"] },
  { id: "g143", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "Before she ___ to bed, she always brushes her teeth.", ja: "彼女は寝る前に必ず歯を磨きます。", answer: "goes", choices: ["goes", "will go", "went", "would go", "is going"], expl: "before が導く副詞節の中では、未来のことでも現在形を使います。'Before she goes' が正しい形です。", rule: "時・条件の副詞節では現在形 (Present Tense in Time/Condition Clauses)", kp: ["before/after/when/until 節の中は現在形（未来でも）", "if/before 節の中に will は使わない"] },
  { id: "g144", diff: "lv2", axis: "form", tags: ["eiken3", "toeic"], stem: "All the luggage ___ checked before the passengers boarded the plane.", ja: "乗客が搭乗する前に、すべての荷物が検査されました。", answer: "was", choices: ["was", "were", "is", "have been", "being"], expl: "'luggage' は不可算名詞なので単数扱いとなり、受動態の be動詞は 'was' が正しいです。", rule: "不可算名詞は単数扱い (Uncountable Nouns: Singular Agreement)", kp: ["luggage / baggage は不可算名詞 → 単数扱い", "不可算名詞 + is/was（複数形・were は不可）"] },
  { id: "g145", diff: "lv2", axis: "trap", tags: ["eiken3", "toeic", "juken"], stem: "The new law will ___ citizens report crimes more easily.", ja: "その新しい法律は市民が犯罪をより簡単に報告できるようにするでしょう。", answer: "make", choices: ["make", "makes", "let to", "allow", "have to"], expl: "使役動詞 'make' は 'make + O + 動詞原形' の形を取ります。'make citizens report' が正しい形です。", rule: "使役動詞 make + O + 原形 (Causative: Make + Object + Base Form)", kp: ["make + O + 動詞原形（to なし）", "make/let/have + O + 原形"] },
  { id: "g146", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "The ancient temple ___ built more than five hundred years ago.", ja: "その古い寺は500年以上前に建てられました。", answer: "was", choices: ["was", "is", "were", "has been", "been"], expl: "受動態は 'be動詞 + 過去分詞' の形で、過去の文脈なので 'was built' が正しいです。", rule: "受動態 (Passive Voice)", kp: ["受動態 → be + 過去分詞", "過去の受動態 → was/were + pp"] },
  { id: "g147", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "She realized that she ___ her wallet at home when she got to the store.", ja: "彼女は店に着いたとき、財布を家に置いてきたことに気づきました。", answer: "had left", choices: ["had left", "left", "has left", "was leaving", "leaves"], expl: "「店に着いた」より前に「財布を置いてきた」という出来事があったため、過去完了 'had left' を使います。", rule: "過去完了 (Past Perfect)", kp: ["過去の文脈でさらに前の出来事 → had + pp（過去完了）", "過去完了は二つの過去の出来事の前後関係を示す"] },
  { id: "g148", diff: "lv2", axis: "logic", tags: ["eiken3", "juken"], stem: "Neither the captain ___ the crew members had any idea about the bad weather approaching.", ja: "船長も乗組員も、近づいている悪天候についてまったく知りませんでした。", answer: "nor", choices: ["nor", "or", "and", "but", "either"], expl: "'neither' と対になる接続詞は 'nor' です。'neither A nor B' で「AもBも〜ない」という意味になります。", rule: "neither A nor B (Neither...Nor (Correlative Conjunctions))", kp: ["neither と対になるのは nor", "neither A nor B + 動詞（B に一致）"] },
  { id: "g149", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "If you ___ the application form today, your request will be processed faster.", ja: "もし今日申請書を提出すれば、あなたのリクエストはより早く処理されるでしょう。", answer: "submit", choices: ["submit", "will submit", "submitted", "submitting", "have submitted"], expl: "if が導く条件節の中では、未来のことでも現在形を使います。主語は二人称なので 'submit'（原形）が正しいです。", rule: "時・条件の副詞節では現在形 (Present Tense in Time/Condition Clauses)", kp: ["if 節の中は will を使わず現在形", "条件節 → 現在形、主節 → will + 原形"] },
  { id: "g150", diff: "lv2", axis: "form", tags: ["eiken3", "toeic"], stem: "The advice he gave me ___ really helpful in solving the problem.", ja: "彼が私にくれたアドバイスは、その問題を解決するのに本当に役立ちました。", answer: "was", choices: ["was", "were", "have been", "are", "being"], expl: "'advice' は不可算名詞で単数扱いなので、be動詞は 'was' が正しいです。複数形や 'were' は使えません。", rule: "不可算名詞は単数扱い (Uncountable Nouns: Singular Agreement)", kp: ["advice / information / news → 不可算名詞（単数扱い）", "不可算名詞には複数形の -s を付けない"] },
  { id: "g151", diff: "lv3", axis: "tense", tags: ["eikenpre2", "toeic"], stem: "By the time the rescue team reaches the village, the flood ___ most of the crops.", ja: "救助隊が村に到着するころには、洪水が農作物のほとんどを駄目にしてしまっているでしょう。", answer: "will have destroyed", choices: ["will have destroyed", "will destroy", "has destroyed", "had destroyed", "would destroy"], expl: "'By the time ~' と未来の時点が示されているので、その時点までに完了している動作を表す未来完了 'will have destroyed' を使います。", rule: "未来完了 (Future Perfect)", kp: ["by + 未来の時点 → will have + pp（未来完了）", "by the time 節の中は現在形"] },
  { id: "g152", diff: "lv3", axis: "logic", tags: ["eikenpre2", "juken"], stem: "The small village ___ I spent my childhood has changed a lot over the years.", ja: "私が子ども時代を過ごした小さな村は、長年でずいぶん変わりました。", answer: "where", choices: ["where", "which", "what", "that", "when"], expl: "先行詞 'village' が場所を表すため、関係副詞 'where' を使います。'which' を使う場合は 'in which' が必要です。", rule: "関係副詞 where (Relative Adverb: Where)", kp: ["場所の先行詞 → 関係副詞 where", "which の場合は in/at which が必要"] },
  { id: "g153", diff: "lv3", axis: "tense", tags: ["eikenpre2", "toeic"], stem: "He ___ in the rain for over an hour when a taxi finally stopped for him.", ja: "タクシーがやっと止まってくれたとき、彼は1時間以上雨の中を歩き続けていました。", answer: "had been walking", choices: ["had been walking", "has been walking", "was walking", "walked", "had walked"], expl: "過去のある時点（タクシーが止まった時）まで動作が継続していたことを表すため、過去完了進行形 'had been walking' を使います。", rule: "過去完了進行形 (Past Perfect Continuous)", kp: ["過去の時点まで継続 → had been + V-ing", "for + 期間 が継続を示すシグナル"] },
  { id: "g154", diff: "lv3", axis: "logic", tags: ["eikenpre2", "juken"], stem: "___ long the journey is, we must reach our destination before dark.", ja: "旅がどれほど長くても、暗くなる前に目的地に着かなければなりません。", answer: "However", choices: ["However", "Whatever", "Whenever", "Wherever", "Whichever"], expl: "'long' は形容詞で、「どんなに長くても」という意味を表すには 'However + 形容詞 + S + V' の形を使います。", rule: "複合関係副詞 however (However + Adj/Adv (Concessive))", kp: ["however + 形容詞/副詞 = どんなに〜でも", "whatever は名詞を、however は形容詞・副詞を修飾"] },
  { id: "g155", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic", "juken"], stem: "A number of employees ___ working overtime to meet the project deadline.", ja: "多くの従業員がプロジェクトの期限に間に合わせるために残業しています。", answer: "are", choices: ["are", "is", "was", "has been", "have"], expl: "'A number of' は「多くの」という意味で複数扱いです。'The number of'（〜の数）と混同しないように注意が必要です。", rule: "The number of（単数）vs A number of（複数） (The Number Of vs A Number Of)", kp: ["A number of + 複数名詞 → 複数動詞（are）", "The number of + 複数名詞 → 単数動詞（is）"] },
  { id: "g156", diff: "lv3", axis: "logic", tags: ["eikenpre2", "juken"], stem: "___ tired you feel after work, try to do some light exercise before bed.", ja: "仕事の後どんなに疲れていても、寝る前に軽い運動をするようにしてください。", answer: "However", choices: ["However", "Whatever", "Whenever", "No matter what", "Whichever"], expl: "'tired' は形容詞なので、「どんなに疲れていても」を表すには 'However + 形容詞 + S + V' を使います。", rule: "複合関係副詞 however (However + Adj/Adv (Concessive))", kp: ["however + 形容詞/副詞 + S + V の語順を守る", "直後に形容詞・副詞が来るのが however"] },
  { id: "g157", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic"], stem: "If the researchers ___ the data more carefully, they would not have drawn the wrong conclusion.", ja: "もし研究者たちがデータをより慎重に分析していたなら、誤った結論を導き出さなかったでしょう。", answer: "had analyzed", choices: ["had analyzed", "analyzed", "would have analyzed", "have analyzed", "were analyzing"], expl: "過去の事実に反する仮定を表す仮定法過去完了の形は 'If + S + had + pp' です。帰結節は 'would have + pp' となります。", rule: "仮定法過去完了 (Third Conditional (Past Unreal))", kp: ["仮定法過去完了：If + had pp, S + would have pp", "過去の事実に反する仮定 → had + pp"] },
  { id: "g158", diff: "lv4", axis: "form", tags: ["eiken2", "toeic", "juken"], stem: "___ from a bird's-eye view, the winding river looked like a silver ribbon across the landscape.", ja: "鳥瞰的に見ると、その蛇行する川は風景を横切る銀色のリボンのように見えました。", answer: "Seen", choices: ["Seen", "Seeing", "To see", "Having seen", "Being seen"], expl: "主語 'the winding river' は「見られる」側なので、受動の分詞構文 'Seen'（過去分詞）で始めます。", rule: "分詞構文（受動） (Participial Phrase (Passive))", kp: ["主語が動作を受ける側 → 過去分詞で分詞構文を開始", "能動の分詞構文 → -ing / 受動の分詞構文 → pp"] },
  { id: "g159", diff: "lv4", axis: "logic", tags: ["eiken2", "toeic"], stem: "Not only ___ the new policy unpopular, but it also caused significant financial losses.", ja: "その新しい方針は不評だっただけでなく、大きな財政的損失も引き起こしました。", answer: "was", choices: ["was", "is", "did", "the policy was", "it was"], expl: "否定語 'Not only' が文頭に来ると倒置が起き、'Not only + 助動詞/be動詞 + S' の語順になります。", rule: "Not only の倒置 (Inversion after Not Only)", kp: ["Not only が文頭 → 倒置（助動詞/be動詞 + 主語）", "Not only was S + pp / Not only does S + V"] },
  { id: "g160", diff: "lv4", axis: "vocab", tags: ["eiken2", "toeic"], stem: "The director insisted ___ presenting the results in person at the board meeting.", ja: "その取締役は、取締役会で自ら直接結果を発表することを主張しました。", answer: "on", choices: ["on", "to", "in", "for", "of"], expl: "'insist on + V-ing' で「〜することを主張する」という意味になります。'insist to' や 'insist for' は誤りです。", rule: "insist on -ing (Insist On + Gerund)", kp: ["insist on + V-ing（on が必要）", "insist to V は不可"] },
  { id: "g161", diff: "lv5", axis: "vocab", tags: ["eikenpre1", "toeic"], stem: "The new environmental regulations are expected to come ___ force by the end of this fiscal year.", ja: "新しい環境規制は今会計年度末までに施行される見込みです。", answer: "into", choices: ["into", "in", "to", "under", "onto"], expl: "「施行される・発効する」は 'come into force' または 'come into effect' という固定表現です。'in' や 'to' は不正解です。", rule: "come into effect (Come Into Effect (Fixed Expression))", kp: ["come into force/effect = 施行される・発効する", "into であり in や to ではない"] },
  { id: "g162", diff: "lv5", axis: "vocab", tags: ["eikenpre1", "toeic"], stem: "The revised data protection act will come ___ effect on the first day of April.", ja: "改正されたデータ保護法は4月1日に施行されます。", answer: "into", choices: ["into", "in", "to", "about", "upon"], expl: "「〜が施行される」は 'come into effect' という固定表現で、前置詞は必ず 'into' を使います。'in' や 'to' などは誤りです。", rule: "come into effect (Come Into Effect (Fixed Expression))", kp: ["come into effect の into は固定", "come into: effect / force / being / existence"] },
  { id: "g163", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "My dog ___ a lot every night.", ja: "私の犬は毎晩たくさん吠えます。", answer: "barks", choices: ["barks", "bark", "barking", "is bark", "to bark"], expl: "主語 My dog は三人称単数なので、一般動詞に -s を付けて barks とします。", rule: "一般動詞の三単現 (Third Person Singular -s)", kp: ["三人称単数の主語には動詞に -s を付ける", "He/She/It/固有名詞の単数 → V-s"] },
  { id: "g164", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "My friends ___ video games after school every day.", ja: "私の友達は毎日放課後にテレビゲームをします。", answer: "play", choices: ["play", "plays", "playing", "to play", "is playing"], expl: "主語 My friends は複数なので、動詞に -s は付けず原形 play を使います。", rule: "一般動詞の三単現 (Third Person Singular -s)", kp: ["複数主語には動詞の原形を使う", "They/We/You/I → V（原形）"] },
  { id: "g165", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "My grandmother ___ very kind and always smiles at everyone.", ja: "私の祖母はとても優しくて、いつも全員に微笑みかけます。", answer: "is", choices: ["is", "are", "am", "be", "were"], expl: "主語 My grandmother は三人称単数なので、be動詞は is を使います。", rule: "be動詞の人称一致 (Subject-Verb Agreement with Be)", kp: ["He/She/It/単数名詞 → is", "be動詞は主語の人称と数に合わせる"] },
  { id: "g166", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "My older sister is very good ___ drawing pictures.", ja: "私の姉は絵を描くのがとても得意です。", answer: "at", choices: ["at", "in", "for", "on", "with"], expl: "「～が得意」は be good at で表します。good の後は at を使うのが決まりです。", rule: "be good at (Be Good At + Noun/Gerund)", kp: ["be good at + 名詞/-ing = ～が得意", "good at（得意）/ good for（～に良い）を区別する"] },
  { id: "g167", diff: "lv1", axis: "logic", tags: ["eiken4"], stem: "I'm thirsty. Do you have anything ___ drink?", ja: "のどが渇いています。何か飲み物はありますか？", answer: "to", choices: ["to", "for", "of", "-ing", "with"], expl: "anything のような -thing の後は「to + 動詞原形」で「～するための」という意味を作ります。", rule: "不定詞の形容詞的用法 (Infinitive as Adjective)", kp: ["-thing/-one/-where + to + 動詞原形", "forや-ingではなくtoを使う"] },
  { id: "g168", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "I can't find my umbrella. I've been ___ for it since this morning.", ja: "傘が見つかりません。今朝からずっと探しています。", answer: "looking", choices: ["looking", "watching", "seeing", "finding", "searching"], expl: "「探す」は look for で表します。look at（見る）や look up（調べる）と混同しないようにしましょう。", rule: "句動詞 look up / look for / look at (Phrasal Verbs with Look)", kp: ["look for = 探す", "look up = 調べる / look at = 見る"] },
  { id: "g169", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "If you don't know the meaning of this word, please ___ it up in your dictionary.", ja: "この単語の意味がわからない場合は、辞書で調べてください。", answer: "look", choices: ["look", "find", "search", "check", "see"], expl: "「辞書で調べる」は look up（＋目的語＋in the dictionary）で表します。find や search では句動詞として成立しません。", rule: "句動詞 look up / look for / look at (Phrasal Verbs with Look)", kp: ["look up = 調べる（辞書などで）", "句動詞は動詞と前置詞/副詞のセットで意味が決まる"] },
  { id: "g170", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "Her piano performance was ___ than anyone else in the concert.", ja: "彼女のピアノ演奏はコンサートの中で誰よりも上手でした。", answer: "better", choices: ["better", "more good", "gooder", "best", "well"], expl: "good の比較級は不規則変化で better です。more good や gooder は誤りです。", rule: "不規則比較級 (Irregular Comparatives)", kp: ["good → better → best（不規則変化）", "more good / gooder は誤り"] },
  { id: "g171", diff: "lv2", axis: "trap", tags: ["eiken3", "toeic", "juken"], stem: "The coach made all the players ___ the drill ten times without stopping.", ja: "コーチは全選手に、止まらずにそのドリルを10回やらせました。", answer: "repeat", choices: ["repeat", "to repeat", "repeating", "repeated", "repeats"], expl: "使役動詞 make は「make + 目的語 + 動詞の原形」の形をとります。to は不要です。", rule: "使役動詞 make + O + 原形 (Causative: Make + Object + Base Form)", kp: ["make + O + 動詞原形（toは付けない）", "make/let/have + O + 原形"] },
  { id: "g172", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "My grandfather ___ in this small town for over forty years.", ja: "私の祖父は40年以上この小さな町に住んでいます。", answer: "has lived", choices: ["has lived", "lived", "is living", "lives", "had lived"], expl: "「for + 期間」は現在完了（継続）のシグナルです。has lived が正しい形です。", rule: "現在完了（継続） (Present Perfect (Duration))", kp: ["for + 期間 / since + 時点 → have/has + 過去分詞", "過去形や現在進行形は for（継続）と組み合わせられない"] },
  { id: "g173", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "When we reached the theater, the play ___ already ___.", ja: "私たちが劇場に着いたとき、劇はすでに始まっていました。", answer: "had already begun", choices: ["had already begun", "already began", "has already begun", "was already begun", "already begins"], expl: "reached（過去）よりも前の出来事を表すには過去完了 had + 過去分詞を使います。", rule: "過去完了 (Past Perfect)", kp: ["過去の文中でさらに前の出来事 → had + 過去分詞", "has（現在完了）は過去の文脈には使えない"] },
  { id: "g174", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "The weather today is ___ than it was yesterday.", ja: "今日の天気は昨日より悪いです。", answer: "worse", choices: ["worse", "more bad", "badder", "worst", "badly"], expl: "bad の比較級は不規則変化で worse です。more bad や badder は誤りです。", rule: "不規則比較級 (Irregular Comparatives)", kp: ["bad → worse → worst（不規則変化）", "more bad / badder は誤り"] },
  { id: "g175", diff: "lv2", axis: "logic", tags: ["eiken3", "juken"], stem: "Please tell me ___ this restaurant is open on Sundays or not.", ja: "このレストランが日曜日に開いているかどうか教えてください。", answer: "whether", choices: ["whether", "what", "that", "which", "how"], expl: "「～かどうか」は whether ... or not で表します。or not と共に使えるのは whether だけで、that や what は不可です。", rule: "whether ... or not (Whether...Or Not)", kp: ["「～かどうか」→ whether ... or not", "or not と組み合わせられるのは whether のみ"] },
  { id: "g176", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "My score on the math test was much ___ than last time.", ja: "数学のテストの点数は前回よりずっと良かったです。", answer: "better", choices: ["better", "more good", "gooder", "well", "good"], expl: "good の比較級は不規則変化の better です。much は比較級を強調する副詞です。", rule: "不規則比較級 (Irregular Comparatives)", kp: ["good → better（不規則変化）", "much / far / a lot は比較級を強調できる"] },
  { id: "g177", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "Guests are kindly asked to refrain ___ making loud noises after 10 p.m.", ja: "宿泊客の皆様は午後10時以降、大きな音を立てることをお控えください。", answer: "from", choices: ["from", "to", "of", "in", "against"], expl: "「～を控える」は refrain from + 動名詞で表します。refrain to は誤りです。", rule: "refrain from -ing (Refrain From + Gerund)", kp: ["refrain from + -ing = ～を控える", "toではなくfromを使う"] },
  { id: "g178", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic", "juken"], stem: "The committee recommended that every member ___ the final report by Friday.", ja: "委員会は全メンバーが金曜日までに最終報告書を提出するよう勧告しました。", answer: "submit", choices: ["submit", "submits", "submitted", "should submits", "to submit"], expl: "recommend that ... の後は仮定法現在で動詞の原形を使います。三人称単数でも -s は付けません。", rule: "仮定法現在 suggest/recommend + 原形 (Subjunctive after Suggest/Recommend)", kp: ["recommend/suggest/insist/demand + that S + 動詞原形", "仮定法現在では三単現の -s を付けない"] },
  { id: "g179", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic", "juken"], stem: "___ of applicants for this position has increased significantly this year.", ja: "今年はこのポジションへの応募者数が大幅に増加しました。", answer: "The number", choices: ["The number", "A number", "Numbers", "The amount", "Some number"], expl: "「応募者の数」は The number of + 複数名詞で、動詞は単数扱い（has increased）です。", rule: "The number of（単数）vs A number of（複数） (The Number Of vs A Number Of)", kp: ["The number of + 複数名詞 → 単数動詞（is/has）", "A number of + 複数名詞 → 複数動詞（are/have）"] },
  { id: "g180", diff: "lv3", axis: "tense", tags: ["eikenpre2", "toeic"], stem: "By the time the guests arrive, we ___ all the preparations.", ja: "ゲストが到着するころには、私たちは全ての準備を終えているでしょう。", answer: "will have completed", choices: ["will have completed", "will complete", "have completed", "had completed", "complete"], expl: "「by the time + 現在形」の文で、未来のある時点までに完了していることを表すには will have + 過去分詞（未来完了）を使います。", rule: "未来完了 (Future Perfect)", kp: ["by the time + 現在形 → 帰結節は will have + 過去分詞", "by + 未来の時点 → 未来完了"] },
  { id: "g181", diff: "lv3", axis: "form", tags: ["eikenpre2", "toeic"], stem: "All the equipment in the laboratory needs ___ regularly to ensure safety.", ja: "安全確保のため、実験室のすべての機器は定期的に点検される必要があります。", answer: "to be inspected", choices: ["to be inspected", "to inspect", "inspecting", "being inspected", "inspect"], expl: "主語 equipment は「点検される側」なので、受動態の不定詞 to be + 過去分詞の形を使います。", rule: "受動態の不定詞 (Passive Infinitive: to be + pp)", kp: ["主語が動作を受ける側 → need to be + 過去分詞", "to inspect（能動）と to be inspected（受動）を区別する"] },
  { id: "g182", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "The ceremony was canceled ___ unexpected circumstances.", ja: "式典は予期せぬ事情により中止になりました。", answer: "due to", choices: ["due to", "because", "because of to", "since", "for"], expl: "due to の後は名詞句（unexpected circumstances）が続きます。because の後は S + V の節が必要です。", rule: "due to + 名詞 (Due To vs Because)", kp: ["due to / owing to + 名詞句", "because + S + V（節）"] },
  { id: "g183", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "Employees are strongly advised to refrain ___ discussing confidential information in public places.", ja: "従業員は公共の場で機密情報を話し合うことを強く控えるよう求められています。", answer: "from", choices: ["from", "to", "of", "against", "for"], expl: "refrain from + 動名詞で「～を控える」という意味になります。from は必須で省略できません。", rule: "refrain from -ing (Refrain From + Gerund)", kp: ["refrain from + -ing（fromは省略不可）", "prevent/prohibit も同様に from + -ing"] },
  { id: "g184", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic", "juken"], stem: "A number of scientists ___ working on solutions to reduce plastic waste in the ocean.", ja: "多くの科学者が海洋プラスチックごみを減らす解決策に取り組んでいます。", answer: "are", choices: ["are", "is", "was", "has been", "have"], expl: "A number of は「多くの」という意味で複数扱いになるので、動詞は are を使います。", rule: "The number of（単数）vs A number of（複数） (The Number Of vs A Number Of)", kp: ["A number of = 多くの → 複数動詞（are）", "The number of = ～の数 → 単数動詞（is）"] },
  { id: "g185", diff: "lv4", axis: "logic", tags: ["eiken2", "toeic"], stem: "Not only ___ a gold medal at the Olympics, but she also broke the world record.", ja: "彼女はオリンピックで金メダルを獲得しただけでなく、世界記録も破りました。", answer: "did she win", choices: ["did she win", "she won", "she did win", "won she", "does she win"], expl: "Not only が文頭に来ると倒置が必要です。過去の文なので did を主語の前に置いて did she win とします。", rule: "Not only の倒置 (Inversion after Not Only)", kp: ["Not only が文頭 → 助動詞+主語の倒置", "倒置後の動詞は原形（did she win）"] },
  { id: "g186", diff: "lv4", axis: "logic", tags: ["eiken2", "juken"], stem: "___ I taken more time to review my answers, I would have passed the exam.", ja: "もっと時間をかけて解答を見直していたら、試験に合格していたでしょうに。", answer: "Had", choices: ["Had", "If had", "Have", "Was", "Did"], expl: "If I had taken ... の If を省略した倒置構文です。文頭に Had を置いて Had I taken の形にします。", rule: "仮定法過去完了の倒置 (Inversion in Third Conditional (Had + S + pp))", kp: ["If I had pp → Had I pp（Ifを省略した倒置）", "Were / Had / Should で if を省略した倒置が作れる"] },
  { id: "g187", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic", "juken"], stem: "It is high time the government ___ stricter measures to protect the environment.", ja: "政府がより厳しい環境保護策を取る時がとっくに来ています。", answer: "took", choices: ["took", "takes", "will take", "has taken", "take"], expl: "It is high time + 節の構文では、仮定法的に動詞を過去形にします。took が正解で、takes や will take は誤りです。", rule: "It is (high) time + S + 過去形 (It Is Time + Past Tense (Subjunctive))", kp: ["It is high time + S + 過去形（仮定法）", "willや原形は使わない"] },
  { id: "g188", diff: "lv4", axis: "form", tags: ["eiken2", "toeic", "juken"], stem: "___ from the air, the ancient ruins formed a perfect circle.", ja: "空から見ると、その古代遺跡は完全な円を形成していました。", answer: "Seen", choices: ["Seen", "Seeing", "See", "To see", "Having seen"], expl: "主語 the ancient ruins は「見られる側」なので、受動の分詞構文として Seen（過去分詞）で始めます。", rule: "分詞構文（受動） (Participial Phrase (Passive))", kp: ["主語が動作を受ける側 → 過去分詞で分詞構文を開始", "Seeing（能動）とSeen（受動）を区別する"] },
  { id: "g189", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic"], stem: "I would rather you ___ your personal calls during working hours.", ja: "あなたに勤務時間中に個人的な電話をかけないでいてほしいのですが。", answer: "didn't make", choices: ["didn't make", "don't make", "not make", "won't make", "hadn't made"], expl: "would rather + 主語 + 動詞の構文では仮定法的に動詞を過去形にします。didn't make が正解です。", rule: "would rather + S + 過去形 (Would Rather + Subject + Past Tense)", kp: ["would rather + S + 過去形（仮定法）", "don't や not makeは誤り"] },
  { id: "g190", diff: "lv5", axis: "logic", tags: ["eikenpre1", "toeic"], stem: "___ not for the generous funding from the sponsors, this research project would have been impossible.", ja: "スポンサーからの惜しみない資金援助がなければ、この研究プロジェクトは不可能だったでしょう。", answer: "Were it", choices: ["Were it", "Was it", "If it were", "Had it been", "Would it be"], expl: "「もし～がなければ」を倒置で表す Were it not for + 名詞の構文です。仮定法では were を使い was は不可、for も必須です。", rule: "Were it not for（仮定法倒置） (Were It Not For (Inverted Conditional))", kp: ["Were it not for + 名詞 = If it were not for + 名詞", "仮定法倒置では were を使う（was は不可）"] },
  { id: "g191", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "My little brother ___ soccer practice every Tuesday and Thursday.", ja: "私の弟は毎週火曜日と木曜日にサッカーの練習をします。", answer: "has", choices: ["has", "have", "is having", "had", "haves"], expl: "主語 My little brother は三人称単数なので、一般動詞 have には三単現の -s が必要です。have の三単現は has になります。", rule: "一般動詞の三単現", kp: ["三人称単数の主語には動詞に -s/-es を付ける", "have → has（不規則変化）"] },
  { id: "g192", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "Your new classmates ___ very friendly and kind.", ja: "あなたの新しいクラスメートたちはとても気さくで親切です。", answer: "are", choices: ["are", "is", "am", "be", "was"], expl: "主語 Your new classmates は複数なので、be動詞は are を使います。is は三人称単数、am は I にのみ使います。", rule: "be動詞の人称一致", kp: ["複数主語には are を使う", "be動詞は主語の人称・数に合わせる"] },
  { id: "g193", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "There ___ a big supermarket near my house.", ja: "私の家の近くに大きなスーパーマーケットがあります。", answer: "is", choices: ["is", "are", "have", "be", "has"], expl: "There is/are 構文では後続の名詞が単数なら is を使います。a big supermarket は単数名詞なので There is が正解です。", rule: "There is / There are", kp: ["There is + 単数名詞 / There are + 複数名詞", "存在を表すには There is/are を使う"] },
  { id: "g194", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "There ___ five birds sitting on the fence outside my window.", ja: "私の窓の外のフェンスに5羽の鳥が止まっています。", answer: "are", choices: ["are", "is", "have", "has", "be"], expl: "後続の名詞 five birds は複数なので、There are を使います。There is は単数名詞のときに使います。", rule: "There is / There are", kp: ["後続名詞が複数なら There are", "数字が付く名詞は複数扱い"] },
  { id: "g195", diff: "lv1", axis: "logic", tags: ["eiken4"], stem: "___ your father work on weekends?", ja: "あなたのお父さんは週末に働きますか？", answer: "Does", choices: ["Does", "Do", "Is", "Has", "Did"], expl: "主語 your father は三人称単数なので、一般動詞の疑問文には Does を使います。Does の後の動詞は原形になります。", rule: "一般動詞の疑問文", kp: ["三人称単数の疑問文は Does + S + V(原形)", "be動詞と一般動詞の疑問文を混同しない"] },
  { id: "g196", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "My older brother is very good ___ playing the guitar.", ja: "私の兄はギターを弾くのがとても得意です。", answer: "at", choices: ["at", "in", "for", "on", "with"], expl: "be good at は「～が得意である」という意味の固定表現です。in や for ではなく at を使います。", rule: "be good at", kp: ["be good at + 名詞/-ing = ～が得意", "形容詞と前置詞の組み合わせは固定"] },
  { id: "g197", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "I can't remember the name of this flower. Let me ___ it up on the internet.", ja: "この花の名前が思い出せません。インターネットで調べてみます。", answer: "look", choices: ["look", "search", "find", "check", "see"], expl: "look up は「（情報を）調べる」という意味の句動詞です。look for は「探す」、look at は「見る」と区別しましょう。", rule: "句動詞 look up / look for / look at", kp: ["look up = 調べる", "look for = 探す、look at = 見る と区別する"] },
  { id: "g198", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "The situation today is ___ than it was last week.", ja: "今日の状況は先週よりも悪いです。", answer: "worse", choices: ["worse", "more bad", "badder", "worst", "more badly"], expl: "bad の比較級は不規則変化で worse です。more bad や badder という形は存在しません。", rule: "不規則比較級", kp: ["bad → worse → worst（不規則変化）", "more bad や badder は誤り"] },
  { id: "g199", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "Before she ___ home tonight, she needs to finish the report.", ja: "今夜帰宅する前に、彼女はレポートを仕上げる必要があります。", answer: "gets", choices: ["gets", "will get", "would get", "got", "is getting"], expl: "before が導く時の副詞節では、未来の出来事でも動詞は現在形を使います。will get は誤りです。", rule: "時・条件の副詞節では現在形", kp: ["before/after/when/until 節の中は現在形（未来でも）", "主節に will があっても従属節は現在形"] },
  { id: "g200", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "I ___ ever visited a foreign country before this trip.", ja: "この旅行の前に、私は外国を訪れたことが一度もありませんでした。", answer: "had never", choices: ["had never", "have never", "never", "never had", "was never"], expl: "「この旅行の前に」という過去の基準点よりもさらに前の経験を表すため、過去完了 had never + 過去分詞を使います。", rule: "過去完了", kp: ["過去の基準点より前の出来事は had + 過去分詞", "have never は現在完了なので過去の文脈では使えない"] },
  { id: "g201", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "She ___ twice to the Eiffel Tower.", ja: "彼女はエッフェル塔を2回訪れたことがあります。", answer: "has been", choices: ["has been", "went", "has gone", "had been", "was"], expl: "twice（2回）は経験を表すキーワードなので現在完了を使います。has been to = ～に行ったことがある（経験）です。", rule: "現在完了（経験）", kp: ["twice/once/before/ever/never → 現在完了（経験）", "has been to = ～へ行ったことがある"] },
  { id: "g202", diff: "lv2", axis: "trap", tags: ["eiken3", "toeic", "juken"], stem: "The loud noise outside made the baby ___ in the middle of the night.", ja: "外の大きな音が夜中に赤ちゃんを泣かせました。", answer: "cry", choices: ["cry", "to cry", "crying", "cried", "cries"], expl: "使役動詞 make の後は〈O + 動詞の原形〉の形を取ります。to cry や crying は誤りです。", rule: "使役動詞 make + O + 原形", kp: ["make + O + 動詞の原形（to は不要）", "let/have も同じく原形不定詞を取る"] },
  { id: "g203", diff: "lv2", axis: "logic", tags: ["eiken3", "juken"], stem: "The woman ___ is talking to the principal is my homeroom teacher.", ja: "校長先生と話している女性は私の担任の先生です。", answer: "who", choices: ["who", "which", "what", "whose", "whom"], expl: "先行詞 The woman は人なので、関係代名詞には who を使います。which は物、what は先行詞を取れません。", rule: "関係代名詞 who（主格）", kp: ["人を先行詞とする主格の関係代名詞は who", "which は物、who は人"] },
  { id: "g204", diff: "lv2", axis: "logic", tags: ["eiken3", "juken"], stem: "I'm not sure ___ the store will be open on the holiday or not.", ja: "その店が祝日に開いているかどうかわかりません。", answer: "whether", choices: ["whether", "what", "that", "if", "which"], expl: "or not とともに使って「～かどうか」を表すのは whether です。that は or not と組み合わせられず、what は意味が異なります。", rule: "whether ... or not", kp: ["whether ... or not = ～かどうか", "or not を伴う場合は whether を使う（if は不可）"] },
  { id: "g205", diff: "lv2", axis: "vocab", tags: ["eiken3", "toeic"], stem: "Would you ___ me a favor and watch my bag for a moment?", ja: "お願いがあるのですが、少しの間私のバッグを見ていてもらえますか？", answer: "do", choices: ["do", "make", "give", "take", "get"], expl: "「頼みを聞く」という意味の固定表現は do a favor です。make a favor や give a favor は誤りです。", rule: "do someone a favor", kp: ["do a favor = 頼みを聞く（make や give は不可）", "定型表現: do a favor / make a decision / take a break"] },
  { id: "g206", diff: "lv2", axis: "logic", tags: ["eiken3", "juken"], stem: "Neither the host ___ the guests knew about the surprise.", ja: "ホストも客も誰もそのサプライズについて知りませんでした。", answer: "nor", choices: ["nor", "or", "and", "but", "yet"], expl: "neither と対になる接続詞は nor です。neither ... or という形は誤りで、neither ... nor が正しい組み合わせです。", rule: "neither A nor B", kp: ["neither ... nor = AもBも～ない", "either ... or / neither ... nor がペア"] },
  { id: "g207", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "The outdoor event was canceled ___ the sudden heavy snowfall.", ja: "突然の大雪のため、野外イベントは中止になりました。", answer: "due to", choices: ["due to", "because", "due that", "because of to", "since"], expl: "due to の後には名詞句が続きます。the sudden heavy snowfall は名詞句なので due to が正解です。because の後には節（S＋V）が必要です。", rule: "due to + 名詞", kp: ["due to + 名詞句 / because + S + V（節）", "owing to も同様に名詞句を取る"] },
  { id: "g208", diff: "lv3", axis: "logic", tags: ["eikenpre2", "juken"], stem: "The restaurant ___ we had our first date has unfortunately closed down.", ja: "私たちが初めてデートをしたレストランは残念ながら閉店してしまいました。", answer: "where", choices: ["where", "which", "that", "what", "when"], expl: "先行詞 The restaurant は場所を表すので、関係副詞 where を使います。which を使うなら at which とする必要があります。", rule: "関係副詞 where", kp: ["場所を表す先行詞には関係副詞 where を使う", "where = at/in which と置き換えられる"] },
  { id: "g209", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic", "juken"], stem: "The number of complaints about the new product ___ surprisingly low.", ja: "新製品についての苦情の数は驚くほど少なかった。", answer: "was", choices: ["was", "were", "have been", "are", "is being"], expl: "The number of + 複数名詞は「～の数」という意味で単数扱いです。過去の文脈なので was が正解です。", rule: "The number of（単数）vs A number of（複数）", kp: ["The number of + 複数名詞 → 単数動詞（is/was）", "A number of + 複数名詞 → 複数動詞（are/were）"] },
  { id: "g210", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "All passengers are kindly requested to refrain ___ eating in the priority seating area.", ja: "優先座席エリアでの飲食はご遠慮くださいますようお願い申し上げます。", answer: "from", choices: ["from", "to", "of", "about", "for"], expl: "refrain from + 動名詞（-ing）で「～を控える」という意味になります。refrain to や refrain of は誤りです。", rule: "refrain from -ing", kp: ["refrain from + -ing = ～を控える", "prevent from / prohibit from も同じパターン"] },
  { id: "g211", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "After years of dedicated practice, she finally succeeded ___ becoming a professional dancer.", ja: "長年の献身的な練習の末、彼女はついてプロのダンサーになることに成功しました。", answer: "in", choices: ["in", "to", "at", "on", "with"], expl: "succeed in + 動名詞（-ing）で「～に成功する」という意味になります。succeed to は「～を継ぐ」という別の意味になります。", rule: "succeed in -ing", kp: ["succeed in + -ing = ～に成功する（to は不可）", "consist of / insist on / depend on も同パターン"] },
  { id: "g212", diff: "lv3", axis: "logic", tags: ["eikenpre2", "juken"], stem: "The school ___ I studied for six years is located in the north part of the city.", ja: "私が6年間通った学校は市の北部にあります。", answer: "where", choices: ["where", "which", "what", "who", "that"], expl: "先行詞 The school は場所を表すため、関係副詞 where を使います。which を使うなら at which または in which とする必要があります。", rule: "関係副詞 where", kp: ["場所の先行詞には where（関係副詞）", "which を使う場合は前置詞（at/in）が必要"] },
  { id: "g213", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic", "juken"], stem: "A number of new employees ___ hired at the company this spring.", ja: "今春、その会社には多くの新入社員が採用されました。", answer: "were", choices: ["were", "was", "is", "has been", "have"], expl: "A number of は「多くの」という意味で複数扱いです。受動態の過去形は were + pp になります。", rule: "The number of（単数）vs A number of（複数）", kp: ["A number of + 複数名詞 → 複数動詞（are/were）", "The number of は単数扱いと区別する"] },
  { id: "g214", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic"], stem: "I would rather you ___ the documents without my permission.", ja: "私の許可なしにその書類を共有してほしくありません。", answer: "didn't share", choices: ["didn't share", "don't share", "not share", "hadn't shared", "won't share"], expl: "would rather + S + 過去形は仮定法的表現で、「Sに～してほしくない」という意味を表します。didn't share が正解です。", rule: "would rather + S + 過去形", kp: ["would rather + S + 過去形（仮定法的用法）", "現在形 don't や原形 not share は誤り"] },
  { id: "g215", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic", "juken"], stem: "It is high time the students ___ their study habits before the final exams.", ja: "期末試験の前に、学生たちはそろそろ学習習慣を改めるべきです。", answer: "changed", choices: ["changed", "change", "will change", "to change", "have changed"], expl: "It is high time + S + 過去形は仮定法的表現で「そろそろ～すべきだ」という意味です。現在形や will は使いません。", rule: "It is (high) time + S + 過去形", kp: ["It is high time + S + 過去形 = そろそろ～すべき", "現在形・will は不可。仮定法的に過去形を使う"] },
  { id: "g216", diff: "lv4", axis: "logic", tags: ["eiken2", "juken"], stem: "___ the manager consulted the legal team earlier, this costly dispute could have been avoided.", ja: "部長がもっと早く法務チームに相談していれば、この高くついた争いは避けられたでしょう。", answer: "Had", choices: ["Had", "If", "Should", "Were", "Have"], expl: "If を省略して仮定法過去完了の倒置を作る場合、Had + S + 過去分詞の語順になります。", rule: "仮定法過去完了の倒置", kp: ["If S had pp → Had S pp（Ifを省略した倒置）", "帰結節は would have + pp になる"] },
  { id: "g217", diff: "lv4", axis: "logic", tags: ["eiken2", "toeic"], stem: "Not only ___ the new software save time, but it also significantly reduces costs.", ja: "その新しいソフトウェアは時間を節約するだけでなく、コストも大幅に削減します。", answer: "does", choices: ["does", "do", "is", "has", "will"], expl: "否定語句 Not only が文頭に来ると主語と助動詞が倒置します。主語 the new software は三人称単数・現在形なので does が正解です。", rule: "Not only の倒置", kp: ["Not only が文頭 → 助動詞 + S の倒置", "三人称単数・現在形なので does を使う"] },
  { id: "g218", diff: "lv5", axis: "vocab", tags: ["eikenpre1", "toeic"], stem: "The updated privacy policy will come ___ effect on the first of next month.", ja: "改訂されたプライバシーポリシーは来月1日に施行されます。", answer: "into", choices: ["into", "in", "to", "under", "on"], expl: "「施行される・発効する」という意味の固定表現は come into effect です。in や to では意味をなしません。", rule: "come into effect", kp: ["come into effect/force = 施行される、発効する", "into が正しい前置詞（in や to は誤り）"] },
  { id: "g219", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "My little sister ___ her homework two hours ago.", ja: "私の妹は2時間前に宿題をした。", answer: "finished", choices: ["finished", "finishes", "has finished", "finish", "is finishing"], expl: "「two hours ago（2時間前）」は過去を示すキーシグナルなので、過去形 finished を使います。現在完了（has finished）は ago とは使えません。", rule: "過去形（規則・不規則）", kp: ["ago / yesterday / last ~ → 過去形", "現在完了と ago は共存不可"] },
  { id: "g220", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "We ___ a great time at the festival last weekend.", ja: "私たちは先週末、フェスティバルでとても楽しい時間を過ごした。", answer: "had", choices: ["had", "have", "haved", "have had", "were having"], expl: "「last weekend（先週末）」が過去のシグナルです。have の過去形は不規則変化で had になります。haved という形は存在しません。", rule: "過去形（規則・不規則）", kp: ["have の過去形は had（不規則変化）", "last ~ → 過去形"] },
  { id: "g221", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "There ___ a big dog in front of the gate.", ja: "門の前に大きな犬が1匹いる。", answer: "is", choices: ["is", "are", "have", "has", "be"], expl: "「a big dog」は単数名詞なので、There is を使います。複数なら There are、存在を表すのに have/has は使いません。", rule: "There is / There are", kp: ["There is + 単数名詞", "存在を表す構文は There is/are（have は不可）"] },
  { id: "g222", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "There ___ three apples on the kitchen table.", ja: "キッチンのテーブルの上にリンゴが3個ある。", answer: "are", choices: ["are", "is", "have", "be", "were"], expl: "「three apples」は複数名詞なので There are を使います。単数なら There is ですが、ここでは3個（複数）なので are が正解です。", rule: "There is / There are", kp: ["There are + 複数名詞", "後続の名詞が単数か複数かで is/are を使い分ける"] },
  { id: "g223", diff: "lv1", axis: "logic", tags: ["eiken4"], stem: "___ your mother cook dinner every evening?", ja: "あなたのお母さんは毎晩夕食を作りますか？", answer: "Does", choices: ["Does", "Do", "Is", "Has", "Did"], expl: "主語が三人称単数（your mother）の一般動詞の疑問文には Does を使い、動詞は原形にします。Is は be 動詞の疑問文に使うもので誤りです。", rule: "一般動詞の疑問文", kp: ["三人称単数 + 一般動詞 → Does + 原形", "be動詞の疑問文と混同しない"] },
  { id: "g224", diff: "lv1", axis: "logic", tags: ["eiken4"], stem: "___ your classmates walk to school every day?", ja: "あなたのクラスメートたちは毎日歩いて学校に来ますか？", answer: "Do", choices: ["Do", "Does", "Are", "Is", "Have"], expl: "主語が複数（your classmates）の一般動詞の疑問文には Do を使います。三人称単数なら Does ですが、ここでは複数なので Do が正解です。", rule: "一般動詞の疑問文", kp: ["複数主語 + 一般動詞 → Do + 原形", "Are は be動詞の疑問文に使う"] },
  { id: "g225", diff: "lv1", axis: "logic", tags: ["eiken4"], stem: "Could you give me something ___ write with? I lost my pen.", ja: "何か書くものをもらえますか？ペンをなくしてしまいました。", answer: "to", choices: ["to", "for", "of", "with", "and"], expl: "「something + to + 動詞原形」の形で「～するための何か」を表します。for や -ing ではなく、to + 原形（不定詞の形容詞的用法）が正しい形です。", rule: "不定詞の形容詞的用法", kp: ["-thing/-one/-where + to + 動詞原形", "forではなくtoを使う"] },
  { id: "g226", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "I can't find my glasses. Could you help me ___ for them?", ja: "メガネが見つかりません。探すのを手伝ってもらえますか？", answer: "look", choices: ["look", "see", "watch", "find", "search"], expl: "「look for ～」で「～を探す」という意味の句動詞です。see や watch は「見る」、find は「見つける」なので文意に合いません。", rule: "句動詞 look up / look for / look at", kp: ["look for = 探す", "look up = 調べる、look at = 見る と区別する"] },
  { id: "g227", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "My uncle ___ in this neighborhood for over twenty years.", ja: "私の叔父はこの近所に20年以上住んでいる。", answer: "has lived", choices: ["has lived", "lived", "is living", "lives", "had lived"], expl: "「for over twenty years（20年以上）」は期間を示す現在完了のシグナルです。過去形 lived では「今も続いている」ことが表せません。", rule: "現在完了（継続）", kp: ["for + 期間 → 現在完了（継続）", "sinceは時点、forは期間と組み合わせる"] },
  { id: "g228", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "She ___ this company since she graduated from university.", ja: "彼女は大学を卒業してからずっとこの会社で働いている。", answer: "has worked for", choices: ["has worked for", "worked for", "is working for", "works for", "had worked for"], expl: "「since she graduated（卒業してから）」は現在完了のシグナルです。since と進行形の組み合わせは不自然で、過去形も使えません。", rule: "現在完了（継続）", kp: ["since + 時点 → 現在完了（継続）", "sinceと過去形・進行形は不自然"] },
  { id: "g229", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "He speaks Japanese ___ than any other student in his class.", ja: "彼はクラスの他のどの生徒よりも上手に日本語を話す。", answer: "better", choices: ["better", "more good", "gooder", "more well", "best"], expl: "well の比較級は better です。「more good」「gooder」「more well」はすべて誤りで、不規則変化の比較級 better を使います。", rule: "不規則比較級", kp: ["good/well → better → best（不規則変化）", "more good / gooder は不可"] },
  { id: "g230", diff: "lv2", axis: "logic", tags: ["eiken3", "juken"], stem: "The girl ___ is wearing a red dress is my cousin.", ja: "赤いドレスを着ている女の子は私のいとこです。", answer: "who", choices: ["who", "which", "what", "whom", "whose"], expl: "先行詞が「人（the girl）」で、関係詞節の中で主語の役割を担うため、主格の関係代名詞 who を使います。which は物に使います。", rule: "関係代名詞 who（主格）", kp: ["先行詞が人・主格 → who", "物には which または that を使う"] },
  { id: "g231", diff: "lv2", axis: "tense", tags: ["eiken3", "juken", "toeic"], stem: "After she ___ the email, she will send it to her manager.", ja: "彼女はそのメールを書き終えたら、上司に送るつもりだ。", answer: "finishes", choices: ["finishes", "will finish", "finished", "is finishing", "has finishing"], expl: "After が導く時の副詞節では、未来のことでも現在形を使います。「will finish」は after 節内では使えません。", rule: "時・条件の副詞節では現在形", kp: ["after/when/before/until 節内は現在形（未来でも）", "if/when節内でwillは使わない"] },
  { id: "g232", diff: "lv2", axis: "tense", tags: ["eiken3", "juken", "toeic"], stem: "If you ___ hard enough, you will pass the entrance exam.", ja: "十分に一生懸命勉強すれば、入学試験に合格できるだろう。", answer: "study", choices: ["study", "will study", "studied", "are studying", "would study"], expl: "条件を表す if 節の中では、未来のことでも現在形を使います。「will study」は if 節内では使えません。", rule: "時・条件の副詞節では現在形", kp: ["if節内はwillを使わず現在形", "条件節と帰結節（will + 原形）の区別"] },
  { id: "g233", diff: "lv2", axis: "trap", tags: ["eiken3", "toeic"], stem: "My colleagues and I are really looking forward ___ starting the new project next month.", ja: "同僚たちと私は来月新しいプロジェクトを始めることをとても楽しみにしている。", answer: "to", choices: ["to", "for", "of", "about", "at"], expl: "「look forward to + -ing」の形で「～を楽しみにする」という意味です。ここの to は前置詞なので後ろには動名詞（-ing）が続きます。", rule: "look forward to + -ing", kp: ["look forward to の to は前置詞 → 後ろは -ing", "to + 原形（不定詞）と混同しない"] },
  { id: "g234", diff: "lv2", axis: "logic", tags: ["eiken3", "juken"], stem: "Neither the coach ___ the players was happy with the final score.", ja: "コーチも選手たちも最終スコアに満足していなかった。", answer: "nor", choices: ["nor", "or", "and", "but", "either"], expl: "neither と対になる接続詞は nor です。「neither A or B」は誤りで、正しくは「neither A nor B」の形を使います。", rule: "neither A nor B", kp: ["neither とペアになるのは nor（or ではない）", "neither A nor B + 動詞はBに一致"] },
  { id: "g235", diff: "lv2", axis: "vocab", tags: ["eiken3", "toeic"], stem: "We are all looking forward ___ hearing the results of the competition.", ja: "私たちは全員、コンクールの結果を聞くことをとても楽しみにしている。", answer: "to", choices: ["to", "for", "at", "of", "on"], expl: "「look forward to + -ing」の構文で、to は前置詞です。for や at などではなく、必ず to を使います。", rule: "look forward to + -ing", kp: ["look forward to + 動名詞(-ing)", "be used to / object to も同じ「to + -ing」のパターン"] },
  { id: "g236", diff: "lv3", axis: "form", tags: ["eikenpre2", "toeic"], stem: "This old bridge needs ___ before the rainy season begins.", ja: "この古い橋は雨季が始まる前に修理される必要がある。", answer: "to be repaired", choices: ["to be repaired", "to repair", "repairing", "repaired", "being repaired"], expl: "「bridge（橋）」は修理される側（受動）なので、「need + to be + 過去分詞」の形を使います。「to repair」では橋が自ら修理することになり意味が変わります。", rule: "受動態の不定詞", kp: ["主語が動作を受ける側 → need to be + pp", "to repair（能動）と to be repaired（受動）の区別"] },
  { id: "g237", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic", "juken"], stem: "The number of tourists visiting this island ___ doubled over the past decade.", ja: "この島を訪れる観光客の数は過去10年間で2倍になった。", answer: "has", choices: ["has", "have", "are", "were", "had"], expl: "「The number of ～」は「～の数」という意味で単数扱いなので、動詞は has（三人称単数）を使います。「A number of ～（多くの～）」なら複数扱いです。", rule: "The number of（単数）vs A number of（複数）", kp: ["The number of + 複数名詞 → 単数動詞(is/has)", "A number of + 複数名詞 → 複数動詞(are/have)"] },
  { id: "g238", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic", "juken"], stem: "A number of residents ___ signed the petition against the new construction plan.", ja: "多くの住民が新しい建設計画に反対する請願書に署名した。", answer: "have", choices: ["have", "has", "is", "was", "having"], expl: "「A number of ～」は「多くの～」という意味で複数扱いなので、動詞は have（複数形）を使います。The number of なら単数扱いで has になります。", rule: "The number of（単数）vs A number of（複数）", kp: ["A number of = 多くの → 複数動詞", "The number of = ～の数 → 単数動詞"] },
  { id: "g239", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic"], stem: "The doctor recommended that the patient ___ plenty of rest for at least a week.", ja: "医師は患者が少なくとも1週間は十分な休息を取るよう勧めた。", answer: "take", choices: ["take", "takes", "should takes", "took", "to take"], expl: "recommend that ～ の後の that 節では仮定法現在を使い、主語が三人称単数でも動詞は原形（take）になります。takes のように三単現の s を付けるのは誤りです。", rule: "仮定法現在 suggest/recommend + 原形", kp: ["recommend/suggest/insist/demand that + S + 動詞原形", "仮定法現在では三単現のsは付けない"] },
  { id: "g240", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic"], stem: "The supervisor insisted that all employees ___ the updated safety manual before returning to work.", ja: "上司は全従業員が職場復帰前に改訂された安全マニュアルを読むよう主張した。", answer: "read", choices: ["read", "reads", "should reads", "to read", "reading"], expl: "insist that ～ の後は仮定法現在を使い、動詞は原形（read）になります。三人称複数であっても reads のような語尾変化は不要です。", rule: "仮定法現在 suggest/recommend + 原形", kp: ["insist that + S + 動詞原形（原形のreadは過去形と同形）", "should の後も原形"] },
  { id: "g241", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "After ten years of hard training, she finally succeeded ___ winning the championship.", ja: "10年間の厳しいトレーニングの末、彼女はついに優勝することに成功した。", answer: "in", choices: ["in", "to", "on", "at", "for"], expl: "「succeed in + -ing」で「～することに成功する」を表します。「succeeded to win」のように to + 原形（不定詞）を使う形は英語では誤りです。", rule: "succeed in -ing", kp: ["succeed in + -ing（toは不可）", "consist of / insist on / depend on も「前置詞 + -ing」のパターン"] },
  { id: "g242", diff: "lv4", axis: "form", tags: ["eiken2", "toeic", "juken"], stem: "___ from above, the ancient maze was perfectly symmetrical.", ja: "上から見ると、その古代の迷路は完全に左右対称だった。", answer: "Seen", choices: ["Seen", "Seeing", "See", "Having seen", "To see"], expl: "「maze（迷路）」は「上から見られる」側なので、受動の分詞構文として過去分詞 Seen で始めます。Seeing では迷路が自ら「見ている」という意味になり不自然です。", rule: "分詞構文（受動）", kp: ["主語が受動の立場 → 過去分詞で分詞構文を始める", "Seen from ～ = ～から見ると"] },
  { id: "g243", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic"], stem: "I would rather you ___ the confidential data without authorization.", ja: "あなたには無許可で機密データにアクセスしてほしくない。", answer: "didn't access", choices: ["didn't access", "don't access", "not access", "wouldn't access", "haven't accessed"], expl: "「would rather + 主語 + 動詞の過去形」の形で「（主語に）～してほしい/ほしくない」を表します。仮定法的表現なので、否定は didn't + 原形になります。", rule: "would rather + S + 過去形", kp: ["would rather + S + 過去形（仮定法）", "否定は didn't + 原形（don't ではない）"] },
  { id: "g244", diff: "lv4", axis: "logic", tags: ["eiken2", "toeic"], stem: "Not only ___ the competition, but she also set a new world record.", ja: "彼女はその競技で優勝しただけでなく、新しい世界記録も打ち立てた。", answer: "did she win", choices: ["did she win", "she won", "she did win", "has she won", "she has won"], expl: "「Not only」が文頭に来ると倒置が必要です。過去の文なので「did + 主語 + 動詞の原形」という語順になります。", rule: "Not only の倒置", kp: ["Not only が文頭 → 助動詞+S+原形の倒置", "did の後は動詞の原形（wins ではなく win）"] },
  { id: "g245", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic", "juken"], stem: "It is high time the management ___ the working conditions for all employees.", ja: "経営陣はそろそろ全従業員の労働条件を改善すべき時だ。", answer: "improved", choices: ["improved", "improve", "will improve", "has improved", "would improve"], expl: "「It is high time + 主語 + 過去形」の仮定法的表現で「そろそろ～すべき時だ」を表します。原形や will を使うのは誤りです。", rule: "It is (high) time + S + 過去形", kp: ["It is high time + S + 過去形（仮定法）", "原形・willは不可"] },
  { id: "g246", diff: "lv5", axis: "trap", tags: ["eikenpre1", "toeic"], stem: "Hardly ___ her seat when the announcement about the delay was made.", ja: "彼女が席に着くやいなや、遅延に関するアナウンスがあった。", answer: "had she taken", choices: ["had she taken", "she had taken", "did she take", "had she been taking", "she took"], expl: "「Hardly」が文頭に来ると倒置が必要で、「Hardly + had + S + 過去分詞 + when ～」の形になります。「she had taken」のように倒置なしにするのは誤りです。", rule: "Hardly had S pp when ...", kp: ["Hardly が文頭 → had + S + pp（倒置）", "Hardly...when（～するやいなや）。thanではなくwhen"] },
  { id: "g247", diff: "lv5", axis: "logic", tags: ["eikenpre1", "toeic"], stem: "___ not for the strict safety regulations, far more industrial accidents would occur every year.", ja: "厳しい安全規制がなければ、毎年はるかに多くの産業事故が起きるだろう。", answer: "Were it", choices: ["Were it", "Was it", "If it were", "Would it be", "Is it"], expl: "「Were it not for ～」は「If it were not for ～（もし～がなければ）」の倒置形です。仮定法では was ではなく were を使います。", rule: "Were it not for（仮定法倒置）", kp: ["Were it not for = If it were not for（仮定法倒置）", "仮定法ではwasではなくwereを使う"] },
  { id: "g248", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "My younger brother is terrible ___ singing, but he loves it anyway.", ja: "私の弟は歌が苦手だが、それでも大好きだ。", answer: "at", choices: ["at", "in", "for", "on", "of"], expl: "「be good/bad at ～」で「～が得意/苦手だ」を表します。「good/bad + in」や「good/bad + for」は誤りで、前置詞は必ず at です。", rule: "be good at", kp: ["be bad at = ～が苦手（good at と同じ前置詞 at）", "good for = ～に良い とは区別する"] },
  { id: "g249", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "My cat ___ very lazy and sleeps all day long.", ja: "私の猫はとても怠け者で、一日中寝てばかりいます。", answer: "is", choices: ["is", "are", "am", "be", "were"], expl: "主語 My cat は三人称単数なので、be動詞は is を使います。are は You/We/They に、am は I にのみ使います。", rule: "be動詞の人称一致 (Subject-Verb Agreement with Be)", kp: ["三人称単数 → is", "am は I のみ、are は You/We/They"] },
  { id: "g250", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "My best friend and I ___ in the same class at school.", ja: "親友と私は学校で同じクラスにいます。", answer: "are", choices: ["are", "is", "am", "be", "was"], expl: "主語が「My best friend and I」で複数なので、be動詞は are を使います。and でつないだ複数主語は are が正解です。", rule: "be動詞の人称一致 (Subject-Verb Agreement with Be)", kp: ["A and B → are（複数扱い）", "主語の数でbe動詞を選ぶ"] },
  { id: "g251", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "There ___ a big tree in front of our house.", ja: "私たちの家の前に大きな木が1本あります。", answer: "is", choices: ["is", "are", "have", "has", "be"], expl: "There is/are 構文では後続の名詞が単数（a big tree）なので is を使います。There have は存在を表す表現として不適切です。", rule: "There is / There are (There is/are (Existential))", kp: ["There is + 単数名詞", "There have は存在の表現に使えない"] },
  { id: "g252", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "There ___ twelve students in our English class.", ja: "私たちの英語の授業には12人の生徒がいます。", answer: "are", choices: ["are", "is", "have", "has", "be"], expl: "後続の名詞 twelve students は複数なので There are を使います。複数名詞には is ではなく are が必要です。", rule: "There is / There are (There is/are (Existential))", kp: ["There are + 複数名詞", "後続名詞の数でis/areを決める"] },
  { id: "g253", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "I can't find my wallet. I've been ___ for it all morning.", ja: "財布が見つかりません。今朝からずっと探しています。", answer: "looking", choices: ["looking", "watching", "seeing", "finding", "checking"], expl: "「探す」は look for で表します。watch / see / find はこの文脈では「探す」の意味になりません。look for の進行形 looking が正解です。", rule: "句動詞 look up / look for / look at (Phrasal Verbs with Look)", kp: ["look for = 探す", "look up = 調べる、look at = 見る"] },
  { id: "g254", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "My younger sister is very good ___ playing the piano.", ja: "私の妹はピアノを弾くのがとても得意です。", answer: "at", choices: ["at", "in", "for", "on", "with"], expl: "「～が得意」は be good at で表します。in や for は good との組み合わせでこの意味を作ることができません。", rule: "be good at (Be Good At + Noun/Gerund)", kp: ["be good at + 名詞/-ing = ～が得意", "in / for / on は不可"] },
  { id: "g255", diff: "lv1", axis: "tense", tags: ["eiken4"], stem: "We ___ a wonderful time at the beach last summer.", ja: "去年の夏、私たちは海辺でとても楽しい時間を過ごしました。", answer: "had", choices: ["had", "have", "have had", "haved", "were having"], expl: "last summer という過去の時間表現があるので過去形が必要です。have の過去形は had（不規則変化）で、haved という形は存在しません。", rule: "過去形（規則・不規則） (Simple Past Tense)", kp: ["last ~ / yesterday / ago → 過去形", "have の過去形は had（不規則）"] },
  { id: "g256", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "This famous painting ___ created by a young Spanish artist in the 19th century.", ja: "この有名な絵画は19世紀のスペインの若い芸術家によって描かれました。", answer: "was", choices: ["was", "is", "were", "be", "created"], expl: "「～された」という受動態は be動詞 + 過去分詞で表します。過去の出来事なので was created が正解です。be動詞なしでは受動態になりません。", rule: "受動態 (Passive Voice)", kp: ["受動態 = be動詞 + 過去分詞", "過去の受動態 → was/were + pp"] },
  { id: "g257", diff: "lv2", axis: "form", tags: ["eiken3", "toeic"], stem: "The advice she gave me ___ extremely useful for my project.", ja: "彼女がくれたアドバイスは、私のプロジェクトに非常に役立ちました。", answer: "was", choices: ["was", "were", "have been", "are", "is being"], expl: "advice は不可算名詞で単数扱いです。よって be動詞は was（過去）が正解で、were は不可算名詞には使えません。", rule: "不可算名詞は単数扱い (Uncountable Nouns: Singular Agreement)", kp: ["advice は不可算名詞 → 単数扱い", "news / information / furniture も同様"] },
  { id: "g258", diff: "lv2", axis: "form", tags: ["eiken3", "toeic"], stem: "The furniture in their new apartment ___ chosen by an interior designer.", ja: "彼らの新しいアパートの家具はインテリアデザイナーによって選ばれました。", answer: "was", choices: ["was", "were", "are", "have been", "is being"], expl: "furniture は不可算名詞で常に単数扱いです。複数形もなく、were ではなく was が正解です。", rule: "不可算名詞は単数扱い (Uncountable Nouns: Singular Agreement)", kp: ["furniture は不可算名詞 → was", "複数形 furnitures は存在しない"] },
  { id: "g259", diff: "lv2", axis: "trap", tags: ["eiken3", "toeic", "juken"], stem: "The strict coach made all the athletes ___ the entire route twice.", ja: "厳しいコーチは全選手にコース全体を2回走らせました。", answer: "run", choices: ["run", "to run", "running", "ran", "runs"], expl: "使役動詞 make の後は「目的語 + 動詞の原形」の形をとります。to run や running は不可で、原形の run が正解です。", rule: "使役動詞 make + O + 原形 (Causative: Make + Object + Base Form)", kp: ["make + O + 動詞の原形（to なし）", "let / have も同様に原形をとる"] },
  { id: "g260", diff: "lv2", axis: "vocab", tags: ["eiken3", "toeic"], stem: "Could you ___ me a favor and print out this document for me?", ja: "お願いがあるのですが、この書類を印刷していただけますか？", answer: "do", choices: ["do", "make", "give", "take", "get"], expl: "「頼みを聞く」の定型表現は do someone a favor です。make a favor や give a favor は誤りで、do が唯一の正解です。", rule: "do someone a favor (Do Someone a Favor (Fixed Expression))", kp: ["do a favor（定型表現）", "make a decision / take a break なども定型"] },
  { id: "g261", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "This smartphone model is ___ than the previous one.", ja: "このスマートフォンのモデルは前のものより優れています。", answer: "better", choices: ["better", "more good", "gooder", "best", "more well"], expl: "good の比較級は不規則変化で better です。more good や gooder は誤りで、英語では認められません。", rule: "不規則比較級 (Irregular Comparatives)", kp: ["good → better → best（不規則変化）", "more good / gooder は不可"] },
  { id: "g262", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "My grandfather ___ in this same house for over fifty years.", ja: "私の祖父は50年以上この同じ家に住んでいます。", answer: "has lived", choices: ["has lived", "lived", "is living", "lives", "was living"], expl: "for + 期間（fifty years）は現在完了のシグナルです。過去形 lived では「今も継続中」のニュアンスが出せません。", rule: "現在完了（継続） (Present Perfect (Duration))", kp: ["for + 期間 → 現在完了（has/have + pp）", "since + 時点も同様"] },
  { id: "g263", diff: "lv2", axis: "logic", tags: ["eiken3", "juken"], stem: "Please let me know ___ the package has arrived or not.", ja: "荷物が届いたかどうか教えてください。", answer: "whether", choices: ["whether", "what", "that", "if not", "which"], expl: "「～かどうか」を表すのは whether です。or not と共に使う場合は whether が適切で、that や what は使えません。", rule: "whether ... or not (Whether...Or Not)", kp: ["whether ... or not = ～かどうか", "or not と共に使うのは whether"] },
  { id: "g264", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "After years of training, the young chef finally succeeded ___ opening his own restaurant.", ja: "何年もの修業の末、その若いシェフはついに自分のレストランを開くことに成功しました。", answer: "in", choices: ["in", "to", "at", "on", "with"], expl: "succeed の後は in + 動名詞（-ing）の形をとります。to 不定詞を続けることはできません。", rule: "succeed in -ing (Succeed In + Gerund)", kp: ["succeed in + -ing = ～に成功する", "succeed to は不可"] },
  { id: "g265", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "All visitors to the gallery are kindly asked to refrain ___ touching the artwork.", ja: "ギャラリーのすべての来場者は、作品に触れることを控えるようお願いします。", answer: "from", choices: ["from", "to", "of", "in", "against"], expl: "refrain の後は from + 動名詞（-ing）の形が必要です。refrain to は誤りで、from が唯一の正解です。", rule: "refrain from -ing (Refrain From + Gerund)", kp: ["refrain from + -ing = ～を控える", "to / of は refrain に続けられない"] },
  { id: "g266", diff: "lv3", axis: "form", tags: ["eikenpre2", "toeic", "juken"], stem: "The ___ of the old railway station into a modern art museum took three years.", ja: "その古い鉄道駅を現代美術館に転換する作業は3年かかりました。", answer: "conversion", choices: ["conversion", "convert", "converting", "converted", "converts"], expl: "冠詞 The の後には名詞が必要です。動詞 convert の派生名詞は conversion で、動詞形や動名詞よりも派生名詞が適切です。", rule: "品詞変換（動詞→名詞） (Word Formation: Verb to Noun)", kp: ["冠詞（The/A）の後 → 名詞形", "convert → conversion（派生名詞）"] },
  { id: "g267", diff: "lv3", axis: "tense", tags: ["eikenpre2", "toeic"], stem: "By the time he graduates next spring, he ___ this university for four years.", ja: "来年の春に卒業するころには、彼はこの大学に4年間在籍したことになります。", answer: "will have attended", choices: ["will have attended", "will attend", "has attended", "attends", "would attend"], expl: "by the time + 未来の節に対し、主節は未来完了（will have + pp）を使います。will attend では「完了・継続」のニュアンスが出ません。", rule: "未来完了 (Future Perfect)", kp: ["by + 未来の時点 → will have + pp", "by the time節は現在形"] },
  { id: "g268", diff: "lv3", axis: "tense", tags: ["eikenpre2", "toeic"], stem: "The engineers ___ on the broken pipeline for six hours when they finally located the leak.", ja: "エンジニアたちは、ついに漏れ箇所を発見したとき、壊れたパイプラインの修理を6時間続けていました。", answer: "had been working", choices: ["had been working", "have been working", "were working", "worked", "had worked"], expl: "過去のある時点（located the leak）まで継続していた動作は過去完了進行形（had been + -ing）で表します。for で期間を示していることもシグナルです。", rule: "過去完了進行形 (Past Perfect Continuous)", kp: ["過去の時点まで継続 → had been + -ing", "for + 期間がシグナル"] },
  { id: "g269", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic", "juken"], stem: "The number of international students at this university ___ risen sharply over the past decade.", ja: "この大学の留学生の数は過去10年間で急激に増加しました。", answer: "has", choices: ["has", "have", "are", "were", "had"], expl: "The number of は「～の数」という意味で単数扱いです。したがって動詞は has が正解で、have は不可です。", rule: "The number of（単数）vs A number of（複数） (The Number Of vs A Number Of)", kp: ["The number of → 単数（has/is）", "A number of → 複数（have/are）"] },
  { id: "g270", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "toeic"], stem: "The concert was postponed ___ the sudden illness of the lead singer.", ja: "コンサートはリードシンガーの突然の病気のために延期されました。", answer: "due to", choices: ["due to", "because", "since", "although", "despite"], expl: "due to の後には名詞句（the sudden illness）が来ます。because の後は節（S+V）が必要なので、名詞句のみの場合は due to が正解です。", rule: "due to + 名詞 (Due To vs Because)", kp: ["due to + 名詞句", "because + 節（S+V）"] },
  { id: "g271", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic"], stem: "A number of delegates ___ attending the international summit next week.", ja: "多くの代表者が来週の国際サミットに出席します。", answer: "are", choices: ["are", "is", "was", "has", "have"], expl: "A number of は「多くの」という意味で複数扱いです。したがって動詞は are が正解で、is は不可です。", rule: "The number of（単数）vs A number of（複数） (The Number Of vs A Number Of)", kp: ["A number of → 複数（are/have）", "The number of → 単数（is/has）"] },
  { id: "g272", diff: "lv4", axis: "form", tags: ["eiken2", "toeic", "juken"], stem: "___ from the hilltop at sunset, the vast ocean looked like a painting.", ja: "夕暮れ時に丘の上から見ると、広大な海は絵画のように見えました。", answer: "Seen", choices: ["Seen", "Seeing", "See", "Having seen", "To see"], expl: "主語 the vast ocean は「見られる」側なので、受動の分詞構文となり過去分詞 Seen で始めます。Seeing（能動）では意味が逆になります。", rule: "分詞構文（受動） (Participial Phrase (Passive))", kp: ["主語が受動 → 過去分詞で開始", "能動なら現在分詞（-ing）"] },
  { id: "g273", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic"], stem: "I would rather you ___ the meeting without letting me know in advance.", ja: "事前に知らせずに会議をキャンセルしてほしくありません。", answer: "didn't cancel", choices: ["didn't cancel", "don't cancel", "won't cancel", "not cancel", "hadn't canceled"], expl: "would rather + S + 動詞の過去形 という仮定法的表現を使います。don't や won't など現在・未来形は不可で、過去形 didn't cancel が正解です。", rule: "would rather + S + 過去形 (Would Rather + Subject + Past Tense)", kp: ["would rather + S + 過去形（仮定法）", "don't / won't は不可"] },
  { id: "g274", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic", "juken"], stem: "It is high time the hospital ___ its outdated medical equipment.", ja: "その病院はもう時代遅れの医療機器を更新すべきです。", answer: "replaced", choices: ["replaced", "replace", "will replace", "has replaced", "replaces"], expl: "It is high time + S + 動詞の過去形 という仮定法的表現です。replace や will replace など現在・未来形は使えません。", rule: "It is (high) time + S + 過去形 (It Is Time + Past Tense (Subjunctive))", kp: ["It's (high) time + 過去形 = そろそろ～すべき", "will / 現在形は不可"] },
  { id: "g275", diff: "lv4", axis: "logic", tags: ["eiken2", "toeic"], stem: "Not only ___ the budget cut, but the project timeline was also shortened significantly.", ja: "予算が削減されただけでなく、プロジェクトのスケジュールも大幅に短縮されました。", answer: "was the budget cut", choices: ["was the budget cut", "the budget was cut", "the budget cut was", "did the budget cut", "has the budget cut"], expl: "Not only が文頭に来ると倒置が必要です。過去の受動態なので was + 主語の語順になり、was the budget cut が正解です。", rule: "Not only の倒置 (Inversion after Not Only)", kp: ["Not only が文頭 → 倒置（助動詞/be動詞 + 主語）", "Never / Hardly / Seldom も同様"] },
  { id: "g276", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic"], stem: "If the pilot ___ the weather report before departure, the flight would not have been delayed.", ja: "もし出発前にパイロットが気象情報を確認していたら、フライトは遅延しなかったでしょう。", answer: "had checked", choices: ["had checked", "checked", "would have checked", "has checked", "would check"], expl: "過去の事実に反する仮定は仮定法過去完了を使います。If節は had + 過去分詞、主節は would have + 過去分詞の形です。", rule: "仮定法過去完了 (Third Conditional (Past Unreal))", kp: ["If + had pp, would have pp（仮定法過去完了）", "would have checked は条件節に使えない"] },
  { id: "g277", diff: "lv5", axis: "logic", tags: ["eikenpre1", "toeic"], stem: "___ it not for the team's perseverance, the groundbreaking discovery would never have been made.", ja: "チームの粘り強さがなければ、その画期的な発見は決してなされなかったでしょう。", answer: "Were", choices: ["Were", "Was", "Had", "If", "Should"], expl: "Were it not for は「もし～がなければ」という意味の仮定法倒置表現です。仮定法では was ではなく were を使い、if は不要です。", rule: "Were it not for（仮定法倒置） (Were It Not For (Inverted Conditional))", kp: ["Were it not for + 名詞 = If it were not for + 名詞", "仮定法では Was ではなく Were"] },
  { id: "g278", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "My dog ___ very energetic and loves to run in the park.", ja: "私の犬はとても活発で、公園を走るのが大好きです。", answer: "is", choices: ["is", "are", "am", "be", "were"], expl: "主語 My dog は三人称単数なので、be動詞は is を使います。are は You/We/They、am は I にのみ使います。", rule: "Subject-Verb Agreement with Be", kp: ["He/She/It → is", "主語の人称と数でbe動詞を決める"] },
  { id: "g279", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "My older brother ___ to school by bicycle every morning.", ja: "私の兄は毎朝自転車で学校へ通っています。", answer: "rides", choices: ["rides", "ride", "riding", "rided", "is ride"], expl: "主語 My older brother は三人称単数なので、一般動詞には -s を付けて rides とします。", rule: "Third Person Singular -s", kp: ["三人称単数現在形は動詞に -s/-es を付ける", "He/She/It + V-s"] },
  { id: "g280", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "There ___ two cats sleeping on the sofa.", ja: "ソファの上で2匹の猫が眠っています。", answer: "are", choices: ["are", "is", "have", "has", "were"], expl: "後続の名詞 two cats が複数形なので、There are を使います。There is は単数名詞に使います。", rule: "There is/are (Existential)", kp: ["There are + 複数名詞", "後続の名詞が複数かどうかを確認する"] },
  { id: "g281", diff: "lv1", axis: "vocab", tags: ["eiken4"], stem: "I can't remember what this word means. Let me ___ it up online.", ja: "この単語の意味が思い出せません。ネットで調べてみます。", answer: "look", choices: ["look", "search", "find", "see", "check"], expl: "「調べる」は look up を使います。look for は「探す」、look at は「見る」なので文脈に合いません。", rule: "Phrasal Verbs with Look", kp: ["look up = 調べる", "look for = 探す、look at = 見る と区別する"] },
  { id: "g282", diff: "lv1", axis: "form", tags: ["eiken4"], stem: "There ___ a big library next to the post office in our town.", ja: "私たちの町では、郵便局の隣に大きな図書館があります。", answer: "is", choices: ["is", "are", "have", "be", "has"], expl: "後続の名詞 a big library が単数形なので、There is を使います。複数名詞には There are を使います。", rule: "There is/are (Existential)", kp: ["There is + 単数名詞", "名詞が単数か複数かで is/are を使い分ける"] },
  { id: "g283", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "He ___ in this small town since he was born.", ja: "彼は生まれてからずっとこの小さな町に住んでいます。", answer: "has lived", choices: ["has lived", "lived", "is living", "was living", "had lived"], expl: "since he was born という「時点」を示す語句があるため、現在完了（継続）has lived を使います。過去形 lived や進行形 is living は since と組み合わせると不自然です。", rule: "Present Perfect (Duration)", kp: ["since + 時点 → have/has + pp", "過去形はsince と組み合わせて継続を表せない"] },
  { id: "g284", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "I ___ this author's novels before, so I'm excited to read her new one.", ja: "私は以前にもこの著者の小説を読んだことがあるので、新作を読むのが楽しみです。", answer: "have read", choices: ["have read", "read", "have readed", "had read", "was reading"], expl: "「以前に～したことがある」という経験を表すには現在完了（経験）have read を使います。have readed は誤りで、read の過去分詞は read です。", rule: "Present Perfect (Experience)", kp: ["経験は have/has + pp で表す", "read の過去分詞は read（不規則変化）"] },
  { id: "g285", diff: "lv2", axis: "form", tags: ["eiken3", "juken"], stem: "Her English pronunciation is ___ than it was a year ago.", ja: "彼女の英語の発音は1年前よりも良くなっています。", answer: "better", choices: ["better", "more good", "gooder", "best", "more better"], expl: "good の比較級は不規則変化で better です。more good や gooder は誤りで、比較級に more を付けることも -er を付けることもできません。", rule: "Irregular Comparatives", kp: ["good → better → best（不規則変化）", "more good / gooder は誤り"] },
  { id: "g286", diff: "lv2", axis: "trap", tags: ["eiken3", "toeic", "juken"], stem: "The loud thunder made the young children ___ and hide under the table.", ja: "大きな雷の音で幼い子どもたちは叫んで、テーブルの下に隠れました。", answer: "scream", choices: ["scream", "to scream", "screaming", "screamed", "to be screaming"], expl: "make + O + 動詞原形の形を取ります。to scream のように to をつけるのは誤りで、-ing 形も使いません。", rule: "Causative: Make + Object + Base Form", kp: ["make + O + 原形（to なし）", "let/have も同様に原形不定詞を取る"] },
  { id: "g287", diff: "lv2", axis: "tense", tags: ["eiken3", "juken"], stem: "My aunt ___ for this company for over fifteen years.", ja: "私の叔母は15年以上この会社に勤めています。", answer: "has worked", choices: ["has worked", "worked", "is working", "works", "had worked"], expl: "for + 期間（for over fifteen years）があるので、現在完了（継続）has worked を使います。過去形 worked では現在まで続いているニュアンスが出ません。", rule: "Present Perfect (Duration)", kp: ["for + 期間 → have/has + pp", "現在も続いている状態は現在完了で表す"] },
  { id: "g288", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic"], stem: "The doctor recommended that the patient ___ plenty of water every day.", ja: "医師は患者が毎日十分な水を飲むよう勧めました。", answer: "drink", choices: ["drink", "drinks", "should drinks", "drinking", "to drink"], expl: "recommend + that + S + 動詞原形（仮定法現在）の形を取ります。主語が三人称単数でも -s は付けず、原形 drink を使います。", rule: "Subjunctive after Suggest/Recommend", kp: ["recommend/suggest + that S + 原形（三単現の s なし）", "仮定法現在では主語の人称に関わらず原形"] },
  { id: "g289", diff: "lv3", axis: "logic", tags: ["eikenpre2", "juken"], stem: "The small town ___ my grandfather grew up has barely changed over the decades.", ja: "私の祖父が育った小さな町は、数十年経ってもほとんど変わっていません。", answer: "where", choices: ["where", "which", "what", "that", "in that"], expl: "先行詞 The small town が場所を示しているので、関係副詞 where を使います。which を使う場合は in which が必要です。", rule: "Relative Adverb: Where", kp: ["場所を表す先行詞 → 関係副詞 where", "which を使うなら in which とする"] },
  { id: "g290", diff: "lv3", axis: "tense", tags: ["eikenpre2", "toeic"], stem: "By the time the director arrives at the office tomorrow, the team ___ the presentation slides.", ja: "明日、部長が会社に到着するころには、チームはプレゼンのスライドを完成させているでしょう。", answer: "will have finished", choices: ["will have finished", "will finish", "have finished", "had finished", "finish"], expl: "by the time + 現在形（未来の時点）は未来完了のシグナルです。「到着するころには終わっているだろう」という未来の完了を表すには will have finished を使います。", rule: "Future Perfect", kp: ["by + 未来の時点 → will have + pp", "by the time 節の中は現在形（will は不要）"] },
  { id: "g291", diff: "lv3", axis: "trap", tags: ["eikenpre2", "toeic", "juken"], stem: "A number of delegates ___ already arrived at the conference venue.", ja: "多くの代表者がすでに会議会場に到着しています。", answer: "have", choices: ["have", "has", "is", "was", "having"], expl: "A number of は「多くの」という意味で複数扱いになるため、動詞は複数形の have を使います。The number of（～の数）であれば単数扱いで has になります。", rule: "The Number Of vs A Number Of", kp: ["A number of + 複数名詞 → 複数動詞（have/are）", "The number of + 複数名詞 → 単数動詞（has/is）"] },
  { id: "g292", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic", "juken"], stem: "It is high time the company ___ its approach to environmental sustainability.", ja: "その会社はそろそろ環境の持続可能性に対するアプローチを見直すべき時期です。", answer: "reconsidered", choices: ["reconsidered", "reconsider", "will reconsider", "has reconsidered", "should reconsider"], expl: "It is high time + S + 過去形 の構文では、仮定法的に動詞を過去形にします。reconsider（原形）や will reconsider（未来形）は誤りです。", rule: "It Is Time + Past Tense (Subjunctive)", kp: ["It is high time + S + 過去形（仮定法）", "原形や will は使わない"] },
  { id: "g293", diff: "lv4", axis: "logic", tags: ["eiken2", "juken"], stem: "___ the government acted sooner, thousands of jobs could have been saved.", ja: "政府がもっと早く行動していれば、何千もの雇用が守られたかもしれません。", answer: "Had", choices: ["Had", "If", "Were", "Should", "Has"], expl: "仮定法過去完了の倒置構文で、If the government had acted を Had the government acted と表します。帰結節が could have been saved となっていることも確認のポイントです。", rule: "Inversion in Third Conditional (Had + S + pp)", kp: ["Had + S + pp = If S had pp（仮定法過去完了の倒置）", "帰結節は would/could have + pp"] },
  { id: "g294", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic", "juken"], stem: "It is about time the students ___ their exam schedules and study plans seriously.", ja: "学生たちはそろそろ試験のスケジュールと学習計画を真剣に考えるべき時です。", answer: "reviewed", choices: ["reviewed", "review", "will review", "are reviewing", "have reviewed"], expl: "It is about time + S + 過去形（仮定法）の構文です。「そろそろ～すべき時」という意味で、動詞は過去形 reviewed を使います。原形や will は使いません。", rule: "It Is Time + Past Tense (Subjunctive)", kp: ["It is about time + S + 過去形", "It is time / It is high time も同じパターン"] },
  { id: "g295", diff: "lv5", axis: "logic", tags: ["eikenpre1", "toeic"], stem: "___ it not for the advanced early warning system, the coastal towns could not have been evacuated in time.", ja: "高度な早期警報システムがなければ、沿岸の町々を時間内に避難させることはできなかったでしょう。", answer: "Were", choices: ["Were", "Was", "Had", "If", "Should"], expl: "Were it not for + 名詞 は「もし～がなければ」という意味の仮定法倒置表現です。仮定法では Were を使い、Was は使いません。", rule: "Were It Not For (Inverted Conditional)", kp: ["Were it not for + N = If it were not for + N（仮定法倒置）", "仮定法では必ず were を使い was は不可"] },
  { id: "g296", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "The dog ran ___ across the field.", ja: "その犬は野原をすばやく走った。", answer: "quickly", choices: ["quickly", "quick", "quickness", "more quick", "quicken"], expl: "動詞 ran を修飾するには副詞が必要です。quick は形容詞なので動詞を修飾できません。副詞 quickly を使います。", rule: "R009", kp: ["動詞を修飾するのは副詞", "形容詞＋ly → 副詞"] },
  { id: "g297", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "She passed the test ___ because she studied every day.", ja: "毎日勉強していたので、彼女は簡単にテストに合格した。", answer: "easily", choices: ["easily", "easy", "easiness", "more easy", "easier"], expl: "動詞 passed を修飾するには副詞が必要です。easy は形容詞なので、副詞形の easily を使います。", rule: "R009", kp: ["動詞を修飾するのは副詞", "easy → easily（形容詞→副詞）"] },
  { id: "g298", diff: "lv1", axis: "trap", tags: ["eiken4", "eiken3", "juken"], stem: "My grandfather is ___ honest man who never tells a lie.", ja: "私の祖父は決して嘘をつかない正直な男性だ。", answer: "an", choices: ["an", "a", "the", "one", "any"], expl: "honest は頭の h が発音されず、母音の音（オ）で始まるため、不定冠詞は an を使います。", rule: "R015", kp: ["サイレントh の語の前は an", "綴りではなく発音で a/an を判断する"] },
  { id: "g299", diff: "lv1", axis: "trap", tags: ["eiken4", "eiken3", "juken"], stem: "She wants to become ___ engineer when she grows up.", ja: "彼女は大人になったらエンジニアになりたいと思っている。", answer: "an", choices: ["an", "a", "the", "one", "some"], expl: "engineer は母音の音（エ）で始まるため、不定冠詞は an を使います。", rule: "R015", kp: ["母音の音で始まる語の前は an", "綴りではなく発音で a/an を判断する"] },
  { id: "g300", diff: "lv1", axis: "trap", tags: ["eiken4", "eiken3", "juken"], stem: "He bought ___ uniform for the school festival.", ja: "彼は学校祭のためにユニフォームを買った。", answer: "a", choices: ["a", "an", "the", "one", "some"], expl: "uniform は綴りが u で始まりますが、発音は「ユ」（子音 y の音）で始まるため、不定冠詞は a を使います。", rule: "R015", kp: ["u が子音音（ユ）で始まる語の前は a", "綴りではなく発音で a/an を判断する"] },
  { id: "g301", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "He is ___ player on the team because he never gives up.", ja: "彼は決してあきらめないので、チームの中で優秀な選手だ。", answer: "a brilliant", choices: ["a brilliant", "a brilliantly", "an brilliantly", "brilliantly", "an brilliant"], expl: "名詞 player を修飾するのは形容詞 brilliant です。副詞 brilliantly は名詞を修飾できません。また brilliant は子音音（b）で始まるため a を使います。", rule: "R008", kp: ["名詞を修飾するのは形容詞", "形容詞は名詞の直前に置く"] },
  { id: "g302", diff: "lv1", axis: "tense", tags: ["grammar", "present progressive", "ing", "ongoing action"], stem: "Please be quiet! The baby ___ right now.", ja: "静かにしてください！赤ちゃんが今まさに眠っています。", answer: "is sleeping", choices: ["is sleeping", "sleeps", "slept", "has slept", "sleep"], expl: "right now は今まさに進行中の動作を示すシグナルです。現在進行形 is sleeping を使います。", rule: "R047", kp: ["right now → 現在進行形", "is/am/are + 動詞-ing"] },
  { id: "g303", diff: "lv1", axis: "form", tags: ["grammar", "verb", "contraction", "doesn't", "don't"], stem: "My sister ___ enjoy watching horror movies.", ja: "私の姉はホラー映画を見るのが好きではない。", answer: "doesn't", choices: ["doesn't", "don't", "isn't", "aren't", "wasn't"], expl: "主語が My sister（三人称単数）なので、否定の助動詞は doesn't を使います。don't は複数主語や I/you に使います。", rule: "R028", kp: ["三人称単数には doesn't", "I/you/複数には don't"] },
  { id: "g304", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "The flowers in the garden smell ___.", ja: "庭の花はとてもよい香りがする。", answer: "wonderful", choices: ["wonderful", "wonderfully", "wonder", "more wonderfully", "to be wonderful"], expl: "smell は感覚動詞なので、後ろに来て主語の状態を述べるのは形容詞 wonderful です。副詞 wonderfully を使うと「においをかぐのが上手」という意味になってしまいます。", rule: "R010", kp: ["感覚動詞（smell/look/feel 等）の後は形容詞", "副詞は感覚動詞の後に使えない"] },
  { id: "g305", diff: "lv2", axis: "form", tags: ["grammar", "noun", "count", "noncount", "plural"], stem: "We need to buy some new ___ for the office.", ja: "オフィス用に新しい家具をいくつか買う必要がある。", answer: "furniture", choices: ["furniture", "furnitures", "a furniture", "furnitures pieces", "piece of furnitures"], expl: "furniture は不可算名詞なので複数形にできません。furnitures という形は存在しません。", rule: "R040", kp: ["furniture は不可算名詞（複数形なし）", "不可算名詞には -s を付けない"] },
  { id: "g306", diff: "lv2", axis: "trap", tags: ["grammar", "much", "many", "quantifier", "count", "noncount"], stem: "There isn't ___ milk left in the fridge.", ja: "冷蔵庫にはミルクがほとんど残っていない。", answer: "much", choices: ["much", "many", "a lot of number of", "a great number of", "few"], expl: "milk は不可算名詞なので、many ではなく much を使います。few や a great number of は可算名詞に使います。", rule: "R041", kp: ["much + 不可算名詞", "many + 可算名詞"] },
  { id: "g307", diff: "lv2", axis: "trap", tags: ["grammar", "much", "many", "quantifier", "count", "noncount"], stem: "How ___ languages can you speak?", ja: "あなたはいくつの言語を話せますか？", answer: "many", choices: ["many", "much", "a great amount of", "a large quantity of", "a number amount of"], expl: "languages は可算名詞（複数形）なので、much ではなく many を使います。", rule: "R041", kp: ["many + 可算名詞", "much + 不可算名詞"] },
  { id: "g308", diff: "lv2", axis: "logic", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "The cat is hiding ___ the sofa and the bookshelf.", ja: "ネコはソファと本棚の間に隠れている。", answer: "between", choices: ["between", "among", "beside", "behind", "through"], expl: "2つのもの（ソファと本棚）の間を表すには between を使います。among は3つ以上の間に使います。", rule: "R023", kp: ["2者の間 → between", "3者以上の間 → among"] },
  { id: "g309", diff: "lv2", axis: "logic", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "Please put your signature ___ the dotted line.", ja: "点線の上にサインをしてください。", answer: "on", choices: ["on", "in", "at", "above", "into"], expl: "点線という表面（面）の上に書くことを表すには on を使います。in は内部、at は地点を表します。", rule: "R020", kp: ["on = 表面", "at = 点・地点、in = 内部"] },
  { id: "g310", diff: "lv2", axis: "form", tags: ["grammar", "modal", "auxiliary", "invariant form"], stem: "She ___ speak three languages fluently.", ja: "彼女は3つの言語を流暢に話すことができる。", answer: "can", choices: ["can", "cans", "is can", "be able", "canning"], expl: "助動詞 can は主語が何であっても形が変わりません。cans のように三人称単数で s を付けることはできません。", rule: "R049", kp: ["助動詞は主語によって形が変わらない", "She can（× She cans）"] },
  { id: "g311", diff: "lv2", axis: "tense", tags: ["grammar", "modal", "auxiliary", "invariant form"], stem: "Every student ___ submit the assignment by Friday.", ja: "すべての生徒は金曜日までに課題を提出しなければならない。", answer: "must", choices: ["must", "musts", "is must", "muster", "be must"], expl: "助動詞 must は主語が何であっても形が変わりません。musts のように三人称単数で s を付けることはできません。", rule: "R049", kp: ["助動詞は主語によって形が変わらない", "Every student must（× musts）"] },
  { id: "g312", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "The boys on the soccer team forgot to bring ___ water bottles.", ja: "サッカーチームの少年たちは水筒を持ってくるのを忘れた。", answer: "their", choices: ["their", "his", "her", "its", "our"], expl: "先行詞 The boys（複数）に合わせて、代名詞も複数形の their を使います。単数の his や her は不正解です。", rule: "R024", kp: ["代名詞は先行詞と数を一致させる", "複数の先行詞 → their"] },
  { id: "g313", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "eiken2", "toeic"], stem: "I have lived in this city ___ I was five years old.", ja: "私は5歳のときからこの街に住んでいる。", answer: "since", choices: ["since", "for", "during", "within", "by"], expl: "起点（5歳のとき）を示すには since を使います。for は「〜の間（期間の長さ）」、during は名詞期間に使います。", rule: "R021", kp: ["since + 起点（時点）", "for + 期間の長さ"] },
  { id: "g314", diff: "lv3", axis: "tense", tags: ["grammar", "past perfect", "had", "past participle"], stem: "By the time the ambulance arrived, the patient ___ already ___ consciousness.", ja: "救急車が到着したとき、患者はすでに意識を失っていた。", answer: "had lost", choices: ["had lost", "lost", "has lost", "was losing", "would lose"], expl: "救急車の到着（過去）よりも前に意識を失ったことを表すため、過去完了形 had lost を使います。", rule: "R046", kp: ["過去の出来事より前の出来事 → 過去完了形", "had + 過去分詞"] },
  { id: "g315", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "eiken2", "toeic"], stem: "The patient was still ___ after the long surgery.", ja: "長時間の手術の後も、患者はまだ意識があった。", answer: "conscious", choices: ["conscious", "conscience", "consciously", "conscientious", "consciousness"], expl: "「意識がある」という意味の形容詞は conscious です。conscience は「良心」という意味の名詞なので文法的に使えません。", rule: "R004", kp: ["conscious = 形容詞（意識がある）", "conscience = 名詞（良心）"] },
  { id: "g316", diff: "lv3", axis: "trap", tags: ["eikenpre2", "eiken2", "toeic"], stem: "He refused to lie because his ___ would not allow it.", ja: "彼は良心が許さないので嘘をつくことを拒否した。", answer: "conscience", choices: ["conscience", "conscious", "consciously", "conscientious", "consciousness"], expl: "「良心」という意味の名詞は conscience です。conscious は「意識がある」という意味の形容詞なので、名詞の位置には使えません。", rule: "R004", kp: ["conscience = 名詞（良心）", "conscious = 形容詞（意識がある）"] },
  { id: "g317", diff: "lv3", axis: "tense", tags: ["grammar", "tense", "consistency", "tense shift"], stem: "Every morning, she wakes up early and ___ a long walk in the park.", ja: "毎朝、彼女は早起きして公園を長い時間散歩する。", answer: "takes", choices: ["takes", "took", "was taking", "had taken", "is taking"], expl: "wakes up（現在形）と同じ時間軸の習慣的動作を表すため、動詞の時制を一致させて takes（現在形）を使います。", rule: "R051", kp: ["同一時間軸では時制を統一する", "習慣的動作 → 現在形"] },
  { id: "g318", diff: "lv3", axis: "logic", tags: ["grammar", "that", "which", "who", "writing style", "comma"], stem: "The professor ___ won the Nobel Prize is giving a lecture tomorrow.", ja: "ノーベル賞を受賞した教授が明日講義をする。", answer: "who", choices: ["who", "which", "that", "whom", "whose"], expl: "書き言葉では人を指す関係代名詞には who を優先して使います。that も文法的には可能ですが、形式的な書き言葉では who が適切です。", rule: "R039", kp: ["書き言葉で人を指す → who", "物を指す → which"] },
  { id: "g319", diff: "lv4", axis: "logic", tags: ["grammar", "which", "non-defining", "clause reference"], stem: "The flight was delayed by two hours, ___ made everyone very frustrated.", ja: "フライトが2時間遅延し、それが全員をとても苛立たせた。", answer: "which", choices: ["which", "that", "what", "this", "it"], expl: "前の節全体（フライトが2時間遅延したこと）を先行詞とする非制限用法の関係節には which を使います。that の前にはコンマを置けません。", rule: "R036", kp: ["前節全体を先行詞とする非制限用法 → which", "コンマ + that は不可"] },
  { id: "g320", diff: "lv4", axis: "logic", tags: ["grammar", "which", "non-defining", "clause reference"], stem: "She forgot to save her work before shutting down the computer, ___ meant she lost everything.", ja: "彼女はコンピューターをシャットダウンする前に保存するのを忘れ、そのためすべてのデータを失った。", answer: "which", choices: ["which", "that", "what", "it", "this"], expl: "「保存し忘れたこと」という前節全体を先行詞とする非制限用法には which を使います。コンマの後に that は使えません。", rule: "R036", kp: ["前節全体を先行詞とする非制限用法 → which", "コンマ + that は不可"] },
  { id: "g321", diff: "lv4", axis: "logic", tags: ["grammar", "of whom", "of which", "relative pronoun", "quantifier"], stem: "The team had ten members, ___ had worked together before.", ja: "そのチームには10人のメンバーがおり、そのうち何人かは以前一緒に働いたことがあった。", answer: "some of whom", choices: ["some of whom", "some of which", "some of who", "some of them", "which some"], expl: "先行詞が people（ten members）なので、of の後には whom を使います。of which は物・概念に使います。", rule: "R037", kp: ["人 → some of whom", "物 → some of which"] },
  { id: "g322", diff: "lv4", axis: "form", tags: ["toeic", "eiken2"], stem: "The survey showed that the company had two, five, and ___ employees in each department.", ja: "調査によると、その会社は各部門にそれぞれ2人、5人、そして8人の従業員がいた。", answer: "eight", choices: ["eight", "8", "the number 8", "eighth", "eighty"], expl: "同一文中でシリーズの数字を表記する際、two や five とスペルアウトしているので eight と統一します。", rule: "R007", kp: ["同一文中の数字表記は統一する", "スペルアウトか数字かを一貫させる"] },
  { id: "g323", diff: "lv5", axis: "logic", tags: ["eikenpre1", "toeic"], stem: "Not only ___ the deadline, but the team also delivered outstanding results.", ja: "チームは期限を守っただけでなく、素晴らしい成果も出した。", answer: "did they meet", choices: ["did they meet", "they met", "they did meet", "met they", "have they met"], expl: "Not only が文頭に来ると倒置が必要です。助動詞 did を主語の前に出して did they meet とします。", rule: "R057", kp: ["Not only が文頭 → 助動詞＋主語の倒置", "否定副詞句が文頭 → 倒置"] },
  { id: "g324", diff: "lv5", axis: "vocab", tags: ["eikenpre1", "toeic"], stem: "The new safety standards will come ___ effect at the start of next fiscal year.", ja: "新しい安全基準は来年度の開始時に施行される。", answer: "into", choices: ["into", "in", "to", "under", "with"], expl: "「施行される・発効する」という意味のコロケーションは come into effect です。in や to は使いません。", rule: "R061", kp: ["come into effect = 施行される", "into が正しい前置詞（in や to は不可）"] },
  { id: "g325", diff: "lv1", axis: "form", tags: ["grammar", "some", "any", "quantifier"], stem: "Is there ___ juice left in the bottle?", ja: "ボトルにジュースは残っていますか？", answer: "any", choices: ["any", "much", "many", "few", "little"], expl: "疑問文では可算・不可算名詞のどちらにも 'any' を使います。'much' は不可算名詞に使えますが、この文脈では 'any' が自然な選択です。", rule: "some/anyは可算名詞・不可算名詞の両方に使える", kp: ["疑問文・否定文では any を使う", "any は可算・不可算名詞どちらにも使える"] },
  { id: "g326", diff: "lv1", axis: "form", tags: ["grammar", "verb", "contraction", "doesn't", "don't"], stem: "My older sister ___ like doing homework.", ja: "私の姉は宿題をするのが好きではありません。", answer: "doesn't", choices: ["doesn't", "don't", "isn't", "aren't", "wasn't"], expl: "主語が三人称単数（my older sister）なので 'doesn't' を使います。'don't' は複数主語や I・you に使います。", rule: "doesn'tは単数主語、don'tは複数主語に使う（I・youはdon't）", kp: ["三人称単数には doesn't を使う", "I・you には don't を使う"] },
  { id: "g327", diff: "lv1", axis: "form", tags: ["grammar", "verb", "contraction", "doesn't", "don't"], stem: "Our neighbors ___ make any noise late at night.", ja: "私たちの隣人たちは夜遅くに騒音を立てません。", answer: "don't", choices: ["don't", "doesn't", "isn't", "aren't", "hasn't"], expl: "主語が複数（our neighbors）なので 'don't' を使います。'doesn't' は三人称単数にのみ使います。", rule: "doesn'tは単数主語、don'tは複数主語に使う（I・youはdon't）", kp: ["複数主語には don't を使う", "doesn't は三人称単数専用"] },
  { id: "g328", diff: "lv1", axis: "trap", tags: ["eiken4", "eiken3", "juken"], stem: "She wants to become ___ architect in the future.", ja: "彼女は将来建築家になりたいと思っています。", answer: "an", choices: ["an", "a", "the", "one", "any"], expl: "'architect' は母音の音 /æ/ で始まるため、不定冠詞は 'an' を使います。綴りではなく発音で判断します。", rule: "不定冠詞 a vs. an：音に基づく選択", kp: ["母音の音で始まる語には an", "綴りではなく発音で判断する"] },
  { id: "g329", diff: "lv1", axis: "trap", tags: ["eiken4", "eiken3", "juken"], stem: "He made ___ honest mistake during the presentation.", ja: "彼はプレゼン中に正直な（悪意のない）ミスをしました。", answer: "an", choices: ["an", "a", "the", "one", "some"], expl: "'honest' の語頭の 'h' は発音されないため、母音の音 /ɒ/ で始まります。よって 'an' が正しい選択です。", rule: "不定冠詞 a vs. an：音に基づく選択", kp: ["サイレントhの語には an を使う", "honest / hour / honor などに注意"] },
  { id: "g330", diff: "lv1", axis: "trap", tags: ["eiken4", "eiken3", "juken"], stem: "My cousin is studying to be ___ university professor.", ja: "私のいとこは大学教授になるために勉強しています。", answer: "a", choices: ["a", "an", "the", "one", "some"], expl: "'university' の語頭は綴りが 'u' でも、発音は子音の /j/ 音（ユニバーシティ）で始まるため 'a' が正しい。", rule: "不定冠詞 a vs. an：音に基づく選択", kp: ["university / union / unicorn などは子音音 /j/ で始まるので a を使う", "綴りのuが母音でも発音が/j/なら a"] },
  { id: "g331", diff: "lv2", axis: "form", tags: ["grammar", "little", "few", "quantifier", "count", "noncount"], stem: "There are very ___ seats left for the concert tonight.", ja: "今夜のコンサートには席がほとんど残っていません。", answer: "few", choices: ["few", "little", "much", "less", "small"], expl: "'seats' は可算名詞の複数形なので 'few' を使います。'little' は不可算名詞にのみ使えます。", rule: "littleは不可算名詞、fewは可算名詞を修飾する", kp: ["few + 可算名詞（複数形）", "little + 不可算名詞"] },
  { id: "g332", diff: "lv2", axis: "form", tags: ["grammar", "little", "few", "quantifier", "count", "noncount"], stem: "She had very ___ patience left after dealing with the complaints all day.", ja: "一日中クレームに対応した後、彼女にはほとんど忍耐が残っていませんでした。", answer: "little", choices: ["little", "few", "many", "several", "less"], expl: "'patience' は不可算名詞なので 'little' を使います。'few' は可算名詞の複数形にのみ使えます。", rule: "littleは不可算名詞、fewは可算名詞を修飾する", kp: ["little + 不可算名詞", "patience / time / water などは不可算名詞"] },
  { id: "g333", diff: "lv2", axis: "form", tags: ["grammar", "much", "many", "quantifier", "count", "noncount"], stem: "We don't have ___ chairs in the meeting room for all the guests.", ja: "会議室にはすべてのゲストのための椅子が十分にありません。", answer: "many", choices: ["many", "much", "little", "a little", "few"], expl: "'chairs' は可算名詞の複数形なので 'many' を使います。'much' は不可算名詞にのみ使えます。", rule: "muchは不可算名詞、manyは可算名詞を修飾する", kp: ["many + 可算名詞（複数形）", "much + 不可算名詞"] },
  { id: "g334", diff: "lv2", axis: "form", tags: ["grammar", "much", "many", "quantifier", "count", "noncount"], stem: "There isn't ___ information available about the new policy yet.", ja: "新しい方針についてはまだあまり情報がありません。", answer: "much", choices: ["much", "many", "few", "several", "a few"], expl: "'information' は不可算名詞なので 'much' を使います。'many' は可算名詞の複数形にのみ使えます。", rule: "muchは不可算名詞、manyは可算名詞を修飾する", kp: ["much + 不可算名詞", "information / advice / news などは不可算名詞"] },
  { id: "g335", diff: "lv2", axis: "form", tags: ["grammar", "verb", "subject", "and"], stem: "The director and her assistant ___ at the conference right now.", ja: "ディレクターとそのアシスタントは今会議に出席しています。", answer: "are", choices: ["are", "is", "was", "has been", "have"], expl: "'and' で結ばれた二つの主語（the director + her assistant）は複数扱いなので、動詞は複数形の 'are' を使います。", rule: "andで結ばれた複数の主語には複数形の動詞を使う", kp: ["A and B → 複数扱いで複数動詞", "is ではなく are を使う"] },
  { id: "g336", diff: "lv2", axis: "form", tags: ["grammar", "verb", "subject", "or", "nor"], stem: "Either the manager or the team leader ___ responsible for the final decision.", ja: "マネージャーかチームリーダーのどちらかが最終決定に責任があります。", answer: "is", choices: ["is", "are", "were", "have been", "be"], expl: "'or' で結ばれた二つの単数名詞には単数形の動詞を使います。どちらも単数なので 'is' が正しい。", rule: "orまたはnorで結ばれた複数の単数名詞・代名詞には単数形の動詞を使う", kp: ["単数 or 単数 → 単数動詞", "either A or B も同様"] },
  { id: "g337", diff: "lv2", axis: "tense", tags: ["grammar", "past progressive", "was", "were", "ing"], stem: "The students ___ their notes carefully when the fire alarm suddenly rang.", ja: "火災報知器が突然鳴ったとき、生徒たちはノートを注意深く取っていました。", answer: "were reviewing", choices: ["were reviewing", "reviewed", "had reviewed", "are reviewing", "review"], expl: "'when the fire alarm suddenly rang' は割り込んだ動作を示しており、その時点で進行中だった動作には過去進行形 'were reviewing' を使います。", rule: "過去進行形は過去のある時点で進行中だった動作、または別の動作に割り込まれた動作を表す", kp: ["when に続く割り込み動作には過去進行形", "was/were + verb-ing で過去の進行中動作を表す"] },
  { id: "g338", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic"], stem: "Could you give me some ___ on how to improve my writing skills?", ja: "ライティングスキルを上達させる方法についてアドバイスをいただけますか？", answer: "advice", choices: ["advice", "advise", "advices", "advising", "advised"], expl: "空欄には名詞が必要です。'advice'（名詞）が正しく、'advise' は動詞です。また 'advice' は不可算名詞なので複数形にはなりません。", rule: "advise と advice の区別", kp: ["advice = 名詞（-ice）", "advise = 動詞（-ise）"] },
  { id: "g339", diff: "lv2", axis: "form", tags: ["grammar", "irregular verb", "past tense", "past participle"], stem: "She ___ all the way to the office because she missed the bus.", ja: "バスに乗り遅れたので、彼女はオフィスまでずっと走りました。", answer: "ran", choices: ["ran", "runned", "run", "runed", "running"], expl: "'run' は不規則動詞で、過去形は 'ran' です。'runned' のような規則変化形は存在しません。", rule: "不規則動詞は過去形・過去分詞形が規則的な-ed形にならず、固有の変化をする", kp: ["run → ran → run（不規則変化）", "-ed を付けた runned は誤り"] },
  { id: "g340", diff: "lv2", axis: "form", tags: ["grammar", "irregular verb", "past tense", "past participle"], stem: "The children ___ all the cookies before their parents came home.", ja: "子供たちは両親が帰宅する前にクッキーをすべて食べてしまいました。", answer: "ate", choices: ["ate", "eated", "eaten", "aten", "eat"], expl: "'eat' は不規則動詞で、過去形は 'ate' です。'eated' のような規則変化形は誤りです。", rule: "不規則動詞は過去形・過去分詞形が規則的な-ed形にならず、固有の変化をする", kp: ["eat → ate → eaten（不規則変化）", "過去形は eated ではなく ate"] },
  { id: "g341", diff: "lv3", axis: "logic", tags: ["grammar", "verb", "subject", "intervening phrase"], stem: "The quality of the products ___ been improving over the past year.", ja: "製品の品質はここ一年で向上しています。", answer: "has", choices: ["has", "have", "had", "were", "are"], expl: "主語は 'the quality'（単数）であり、'of the products' は挿入句です。動詞は主語 'the quality' に一致させて 'has' を使います。", rule: "主語と動詞の間に挿入句があっても、動詞は主語に一致させる", kp: ["of + 複数名詞に惑わされず、主語を正しく特定する", "the quality of … → 動詞は単数形"] },
  { id: "g342", diff: "lv3", axis: "tense", tags: ["grammar", "tense", "consistency", "tense shift"], stem: "Every morning, he wakes up at six, eats a light breakfast, and ___ to work by bicycle.", ja: "毎朝、彼は6時に起き、軽い朝食を食べ、自転車で仕事に行きます。", answer: "rides", choices: ["rides", "rode", "was riding", "had ridden", "will ride"], expl: "同一時間軸（毎朝の習慣）の動作は同じ時制で統一します。'wakes' と 'eats' が現在形なので、'rides' も現在形にする必要があります。", rule: "動詞の時制を不必要に変えてはならない。同一時間軸の動作は同じ時制で統一する", kp: ["同一時間軸の動作は同じ時制を維持する", "習慣を表す文では現在形で統一"] },
  { id: "g343", diff: "lv3", axis: "form", tags: ["grammar", "verb", "subject", "or", "nor", "proximity"], stem: "Neither the technicians nor the supervisor ___ aware of the system failure.", ja: "技術者もスーパーバイザーもシステム障害に気づいていませんでした。", answer: "was", choices: ["was", "were", "is", "are", "have been"], expl: "'nor' で結ばれた主語では、動詞に近い方の主語（the supervisor＝単数）に動詞を一致させます。よって 'was' が正しい。", rule: "or/norで単数・複数の名詞が結ばれる場合、動詞は動詞に近い方の主語に一致させる", kp: ["neither A nor B → 動詞は B に一致", "B が単数なら単数動詞を使う"] },
  { id: "g344", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "eiken2", "toeic"], stem: "Regular exercise will positively ___ your physical and mental health.", ja: "定期的な運動はあなたの身体的・精神的健康にプラスの影響を与えます。", answer: "affect", choices: ["affect", "effect", "affection", "effective", "effecting"], expl: "空欄は動詞位置にあり「影響する」の意味が必要なので 'affect'（動詞）が正しい。'effect' は名詞（または「もたらす」の意味の動詞）です。", rule: "affect と effect の区別（RAVEN）", kp: ["affect = 動詞（影響する）", "RAVEN: Remember Affect is a Verb, Effect is a Noun"] },
  { id: "g345", diff: "lv3", axis: "logic", tags: ["grammar", "that", "which", "who", "writing style", "comma"], stem: "The committee reviewed the proposal, ___ had been submitted two weeks earlier.", ja: "委員会はその提案書を審査しました。それは2週間前に提出されていたものです。", answer: "which", choices: ["which", "that", "who", ", that", "what"], expl: "先行詞が物（the proposal）で、追加情報を加える非制限用法（コンマあり）なので 'which' が正しい。コンマの前に 'that' は使えません。", rule: "書き言葉では、人はwho、物はwhichを優先し、thatの前にコンマを置かない", kp: ["コンマ + 関係詞には which（物）または who（人）を使う", "コンマの前に that は置かない"] },
  { id: "g346", diff: "lv3", axis: "logic", tags: ["grammar", "that", "which", "who", "writing style", "comma"], stem: "The scientist ___ discovered this element was awarded the Nobel Prize.", ja: "この元素を発見した科学者はノーベル賞を受賞しました。", answer: "who", choices: ["who", "which", ", who", "what", "whose"], expl: "先行詞が人（the scientist）で、どの科学者かを限定する制限用法なので、書き言葉ではコンマなしの 'who' が正しい。", rule: "書き言葉では、人はwho、物はwhichを優先し、thatの前にコンマを置かない", kp: ["人には who（制限用法・コンマなし）", "書き言葉では that より who / which を優先"] },
  { id: "g347", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic"], stem: "If the team ___ the deadline, the client would have terminated the contract.", ja: "もしチームが締め切りを守れなかったら、クライアントは契約を終了していたでしょう。", answer: "had missed", choices: ["had missed", "missed", "would miss", "has missed", "were missing"], expl: "過去の事実に反する仮定（仮定法過去完了）では 'If + S + had + 過去分詞' の形を使います。", rule: "仮定法過去完了", kp: ["If + had + pp, would have + pp（仮定法過去完了）", "過去の事実に反する仮定にはこの形を使う"] },
  { id: "g348", diff: "lv4", axis: "logic", tags: ["grammar", "of whom", "of which", "relative pronoun", "quantifier"], stem: "The department hired ten new staff members, ___ had extensive international experience.", ja: "その部署は10名の新しいスタッフを採用しましたが、そのうち何人かは豊富な国際経験を持っていました。", answer: "some of whom", choices: ["some of whom", "some of which", "some of who", "some of them", "some who"], expl: "先行詞が人（ten new staff members）なので 'of whom' を使います。'of which' は物に使います。", rule: "most, many, some, both, noneなどの後で人にはof whom、物にはof whichを使う", kp: ["人 → some of whom", "物 → some of which"] },
  { id: "g349", diff: "lv4", axis: "logic", tags: ["grammar", "of whom", "of which", "relative pronoun", "quantifier"], stem: "She submitted five project proposals, ___ was eventually approved by the board.", ja: "彼女は5つのプロジェクト提案書を提出しましたが、そのうち1つが最終的に取締役会に承認されました。", answer: "one of which", choices: ["one of which", "one of whom", "one of that", "one of them", "one of those"], expl: "先行詞が物（five project proposals）なので 'of which' を使います。'of whom' は人に使います。", rule: "most, many, some, both, noneなどの後で人にはof whom、物にはof whichを使う", kp: ["物 → one of which", "人 → one of whom"] },
  { id: "g350", diff: "lv5", axis: "vocab", tags: ["eikenpre1", "toeic"], stem: "The revised safety protocols will come ___ effect at the beginning of next month.", ja: "改訂された安全手順は来月初めから施行されます。", answer: "into", choices: ["into", "in", "to", "under", "on"], expl: "「施行される・発効する」は 'come into effect' という固定表現です。'in' や 'to' ではなく 'into' を使います。", rule: "come into effect", kp: ["come into effect = 施行される・発効する", "into を使う（in / to は誤り）"] },
  { id: "g351", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "She wants to be ___ astronaut when she grows up.", ja: "彼女は大人になったら宇宙飛行士になりたいと思っています。", answer: "an", choices: ["an", "a", "the", "one", "some"], expl: "astronaut は母音 /æ/ の音で始まるため、不定冠詞は an を使います。", rule: "不定冠詞 a vs. an：音に基づく選択", kp: ["母音の音で始まる語の前は an", "綴りではなく発音で判断する"] },
  { id: "g352", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "My father is ___ honest man and always keeps his promises.", ja: "私の父は正直な人で、いつも約束を守ります。", answer: "an", choices: ["an", "a", "the", "one", "—"], expl: "honest の h は発音されないため、母音 /ɒ/ の音で始まります。したがって an が正しい形です。", rule: "不定冠詞 a vs. an：音に基づく選択", kp: ["サイレント h の語（honest, hour など）の前は an", "綴りのhに惑わされない"] },
  { id: "g353", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "He bought ___ uniform for his new job at the hotel.", ja: "彼はホテルの新しい仕事のためにユニフォームを買いました。", answer: "a", choices: ["a", "an", "the", "one", "some"], expl: "uniform は綴りが u で始まりますが、発音は /juː/ という子音 /j/ の音で始まるため、a が正しい形です。", rule: "不定冠詞 a vs. an：音に基づく選択", kp: ["u で始まっても /j/ の音なら a を使う", "uniform / university / unicorn は a + 名詞"] },
  { id: "g354", diff: "lv1", axis: "form", tags: ["grammar", "some", "any", "quantifier"], stem: "Is there ___ sugar in the kitchen? I need some for my coffee.", ja: "キッチンに砂糖はありますか？コーヒーに少し必要なのですが。", answer: "any", choices: ["any", "some", "much", "many", "a few"], expl: "疑問文では不可算名詞・可算名詞のどちらにも any を使います。sugar は不可算名詞です。", rule: "some/anyは可算名詞・不可算名詞の両方に使える", kp: ["疑問文・否定文では any を使う", "some / any は可算・不可算の両方に使える"] },
  { id: "g355", diff: "lv1", axis: "form", tags: ["grammar", "some", "any", "quantifier"], stem: "There are ___ new students in our class this semester.", ja: "今学期、私たちのクラスには何人かの新入生がいます。", answer: "some", choices: ["some", "any", "much", "a little", "a lot"], expl: "肯定文で可算名詞（students）の前には some を使います。", rule: "some/anyは可算名詞・不可算名詞の両方に使える", kp: ["肯定文では some を使う", "some は可算名詞にも不可算名詞にも使える"] },
  { id: "g356", diff: "lv1", axis: "form", tags: ["grammar", "present progressive", "ing", "ongoing action"], stem: "Please don't disturb him. He ___ an important report right now.", ja: "彼の邪魔をしないでください。彼は今、重要な報告書を書いています。", answer: "is writing", choices: ["is writing", "writes", "wrote", "has written", "will write"], expl: "right now という信号語があり、今まさに進行中の動作を表すため、現在進行形 is writing が正しい形です。", rule: "現在進行形は今進行中の動作または近い将来の予定を表す", kp: ["right now / at the moment → 現在進行形", "is/am/are + 動詞-ing"] },
  { id: "g357", diff: "lv1", axis: "form", tags: ["grammar", "verb", "contraction", "doesn't", "don't"], stem: "My best friend ___ like spicy food at all.", ja: "私の親友は辛い食べ物が全く好きではありません。", answer: "doesn't", choices: ["doesn't", "don't", "isn't", "aren't", "didn't"], expl: "主語が My best friend という三人称単数なので、否定の助動詞は doesn't を使います。", rule: "doesn'tは単数主語、don'tは複数主語に使う（I・youはdon't）", kp: ["三人称単数（he/she/it）には doesn't", "複数・I・you には don't"] },
  { id: "g358", diff: "lv1", axis: "form", tags: ["grammar", "verb", "contraction", "doesn't", "don't"], stem: "These machines ___ work properly when the temperature is too low.", ja: "これらの機械は温度が低すぎると正常に動作しません。", answer: "don't", choices: ["don't", "doesn't", "isn't", "aren't", "didn't"], expl: "主語が These machines という複数形なので、否定の助動詞は don't を使います。", rule: "doesn'tは単数主語、don'tは複数主語に使う（I・youはdon't）", kp: ["複数主語には don't", "単数主語（三人称）には doesn't"] },
  { id: "g359", diff: "lv2", axis: "tense", tags: ["grammar", "present perfect", "have", "has", "past participle"], stem: "He ___ this company for more than twenty years and still enjoys his work.", ja: "彼は20年以上この会社に勤めており、今でも仕事を楽しんでいます。", answer: "has worked for", choices: ["has worked for", "worked for", "is working for", "had worked for", "works for"], expl: "「今も続いている状態」を表すため、現在完了形 has worked for を使います。still enjoys という現在の継続を示す表現が根拠です。", rule: "現在完了形は過去に始まり現在まで続く動作・状態、または効果が今も残る完了した行為を表す", kp: ["for + 期間で現在まで継続 → has/have + 過去分詞", "現在完了は今も続いていることを含意する"] },
  { id: "g360", diff: "lv2", axis: "tense", tags: ["grammar", "modal", "auxiliary", "invariant form"], stem: "According to the schedule, every participant ___ bring their own laptop to the workshop.", ja: "スケジュールによると、すべての参加者はワークショップに自分のノートパソコンを持参しなければなりません。", answer: "must", choices: ["must", "musts", "is must", "has must", "must to"], expl: "助動詞 must は主語に関わらず形が変わりません。musts や must to などの形は誤りです。", rule: "助動詞（can, will, shall, may, could, would, should, might, must）は主語に関わらず形が変わらない", kp: ["助動詞は三人称単数でも -s を付けない", "助動詞の後は動詞の原形"] },
  { id: "g361", diff: "lv2", axis: "logic", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "I just finished reading ___ most fascinating book I have ever come across.", ja: "私はこれまでに出会った中で最も魅力的な本を読み終えたところです。", answer: "the", choices: ["the", "a", "an", "one", "—"], expl: "最上級（most fascinating）で特定された唯一のものを指すため、定冠詞 the が必要です。", rule: "定冠詞 the と不定冠詞 a/an の使い分け", kp: ["最上級の前は the", "特定・唯一のものには the を使う"] },
  { id: "g362", diff: "lv2", axis: "logic", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "Can you recommend ___ good restaurant near the station?", ja: "駅の近くに良いレストランを教えてもらえますか？", answer: "a", choices: ["a", "an", "the", "one", "some"], expl: "特定のレストランではなく、任意の「どれかの」良いレストランを指しているため、不定冠詞 a を使います。", rule: "定冠詞 the と不定冠詞 a/an の使い分け", kp: ["不特定・任意のものには a/an", "特定・既知のものには the"] },
  { id: "g363", diff: "lv2", axis: "form", tags: ["grammar", "irregular verb", "past tense", "past participle"], stem: "By the time the guests arrived, the chef had already ___ a delicious three-course meal.", ja: "ゲストが到着するまでに、シェフはすでに美味しい三品料理を作り終えていました。", answer: "made", choices: ["made", "maked", "make", "making", "been made"], expl: "make の過去分詞は made です。規則動詞のように maked とはなりません。", rule: "不規則動詞は過去形・過去分詞形が規則的な-ed形にならず、固有の変化をする", kp: ["make → made → made（不規則変化）", "had + 過去分詞 = 過去完了形"] },
  { id: "g364", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "She had ___ patience with the repeated complaints from the same customer.", ja: "彼女は同じ顧客からの繰り返しのクレームに対してあまり忍耐がありませんでした。", answer: "little", choices: ["little", "few", "many", "a lot of", "much"], expl: "patience は不可算名詞なので、「ほとんどない」を表すには little を使います。few は可算名詞に使います。", rule: "可算名詞と不可算名詞：much vs. many", kp: ["不可算名詞には little（ほぼない）/ much（多い）", "可算名詞には few / many"] },
  { id: "g365", diff: "lv2", axis: "vocab", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "The treasure was buried ___ an old oak tree and a large rock.", ja: "宝物は古いオーク の木と大きな岩の間に埋められていました。", answer: "between", choices: ["between", "among", "beside", "behind", "above"], expl: "2つのもの（an old oak tree と a large rock）の間を指しているため between を使います。", rule: "空間的前置詞の一覧（above/below/between等）", kp: ["2者の間 → between", "3者以上の間 → among"] },
  { id: "g366", diff: "lv3", axis: "form", tags: ["grammar", "verb", "indefinite pronoun", "singular"], stem: "___ of the applicants has submitted the required documents on time.", ja: "応募者全員が必要書類を期限内に提出しました。", answer: "Each", choices: ["Each", "All", "Both", "Many", "Several"], expl: "Each は不定代名詞で単数扱いのため、単数動詞 has が続いています。この文では Each が主語として適切です。", rule: "each, everyone, everybodyなどの不定代名詞は単数扱いで単数動詞を使う", kp: ["each は単数扱いで単数動詞", "each of + 複数名詞 + 単数動詞"] },
  { id: "g367", diff: "lv3", axis: "form", tags: ["grammar", "verb", "subject", "or", "nor", "proximity"], stem: "Either the CEO or the board members ___ responsible for announcing the policy change.", ja: "CEOか取締役会のメンバーのどちらかが、方針変更を発表する責任があります。", answer: "are", choices: ["are", "is", "was", "has been", "were"], expl: "or で結ばれた複合主語では、動詞に近い方の主語（board members：複数）に動詞を一致させるため are が正しい形です。", rule: "or/norで単数・複数の名詞が結ばれる場合、動詞は動詞に近い方の主語に一致させる", kp: ["or / nor の近接一致の原則", "動詞に近い主語が複数なら複数動詞"] },
  { id: "g368", diff: "lv3", axis: "form", tags: ["toeic", "eiken2"], stem: "___ percent of the surveyed employees expressed satisfaction with the new work schedule.", ja: "調査した従業員の67パーセントが、新しい勤務スケジュールへの満足を示しました。", answer: "Sixty-seven", choices: ["Sixty-seven", "67", "67%", "67 percent", "Sixtyseven"], expl: "文の先頭に数字を置く場合はアラビア数字や記号を使えず、必ずスペルアウトしなければなりません。", rule: "文頭の数字は必ずスペルアウト", kp: ["文頭の数字は英語で書き出す", "アラビア数字・%記号は文頭に使えない"] },
  { id: "g369", diff: "lv3", axis: "trap", tags: ["eikenpre2", "eiken2", "toeic"], stem: "The patient slowly regained ___ after the surgery and was able to speak.", ja: "患者は手術後にゆっくりと意識を取り戻し、話せるようになりました。", answer: "consciousness", choices: ["consciousness", "conscience", "conscious", "consciously", "conscientious"], expl: "「意識」を意味する名詞は consciousness です。conscience は「良心」を意味する名詞で意味が異なります。", rule: "conscious と conscience の区別", kp: ["consciousness（名詞）= 意識", "conscience（名詞）= 良心"] },
  { id: "g370", diff: "lv3", axis: "trap", tags: ["eikenpre2", "eiken2", "toeic"], stem: "Despite being nervous, she performed ___ at the final audition.", ja: "緊張していたにもかかわらず、彼女は最終オーディションでうまく演じました。", answer: "well", choices: ["well", "good", "nicely", "fine", "greatly"], expl: "動作動詞 perform を修飾するには副詞が必要です。well は副詞で「上手に」を意味します。good は形容詞なので動詞を修飾できません。", rule: "good と well の使い分け", kp: ["動作動詞の後は副詞 well", "good は形容詞なので動詞を修飾できない"] },
  { id: "g371", diff: "lv4", axis: "logic", tags: ["eiken2", "eikenpre1", "toeic"], stem: "My colleague Sarah, ___, was promoted to department head last month.", ja: "私の同僚のSarahは、優秀な販売記録を持つ人物で、先月部長に昇進しました。", answer: "an outstanding sales record holder", choices: ["an outstanding sales record holder", "the outstanding sales record holder", "outstanding sales record holder", "who outstanding sales record", "she has outstanding sales records"], expl: "Sarah という固有名詞で既に特定されているため、後続の同格語句はなくても意味が通ります。これは非制限的同格語であり、コンマで囲まれた名詞句が適切です。", rule: "同格語（アポジティブ）の基本", kp: ["固有名詞の後の同格語は非制限的 → コンマあり", "同格語は名詞または名詞句"] },
  { id: "g372", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic"], stem: "If the project manager ___ the risks earlier, the team would have avoided the costly delay.", ja: "もしプロジェクトマネージャーがもっと早くリスクを特定していたら、チームは高くつく遅延を避けられたでしょう。", answer: "had identified", choices: ["had identified", "identified", "would identify", "has identified", "would have identified"], expl: "過去の事実に反する仮定（仮定法過去完了）では、if 節に had + 過去分詞を使います。", rule: "仮定法過去完了", kp: ["If + had + pp → 過去の事実に反する仮定", "帰結節は would have + pp"] },
  { id: "g373", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic"], stem: "If the scientists ___ the formula correctly, the experiment would have been a great success.", ja: "もし科学者たちが式を正しく計算していたなら、その実験は大成功だったでしょう。", answer: "had calculated", choices: ["had calculated", "calculated", "would calculate", "have calculated", "were calculating"], expl: "仮定法過去完了では、if 節は had + 過去分詞、帰結節は would have + 過去分詞の形をとります。", rule: "仮定法過去完了", kp: ["仮定法過去完了：If + S + had pp, S + would have pp", "過去の非現実を表す"] },
  { id: "g374", diff: "lv5", axis: "vocab", tags: ["eikenpre1", "toeic"], stem: "The new immigration policy is scheduled to come ___ effect at the beginning of next April.", ja: "新しい移民政策は来年4月の初めに発効する予定です。", answer: "into", choices: ["into", "in", "to", "onto", "under"], expl: "「施行される・発効する」を意味するコロケーションは come into effect です。in や to では意味をなしません。", rule: "come into effect", kp: ["come into effect / force = 施行される・発効する", "into であり in / to ではない"] },
  { id: "g375", diff: "lv5", axis: "tense", tags: ["eikenpre1", "toeic"], stem: "___ it not for the advanced medical technology available today, many lives could not be saved.", ja: "今日利用可能な高度な医療技術がなければ、多くの命を救うことはできないでしょう。", answer: "Were", choices: ["Were", "Was", "If", "Had", "Would"], expl: "仮定法の倒置構文「Were it not for ～」は「If it were not for ～（～がなければ）」の意味です。仮定法では were を使い was は不可です。", rule: "Were it not for（仮定法倒置）", kp: ["Were it not for = If it were not for", "仮定法倒置では Was ではなく Were を使う"] },
  { id: "g376", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "My teacher gave us ___ interesting homework assignment about local history.", ja: "先生は地域の歴史についての面白い宿題を出しました。", answer: "an", choices: ["an", "a", "the", "one", "—"], expl: "interesting は母音 /ɪ/ の音で始まるため、不定冠詞は an を使います。", rule: "不定冠詞 a vs. an：音に基づく選択", kp: ["母音の音で始まる語の前は an", "interesting / important / intelligent → an"] },
  { id: "g377", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "She runs ___ every morning before school.", ja: "彼女は毎朝学校の前に速く走る。", answer: "fast", choices: ["fast", "fastly", "quick", "quicker", "more fast"], expl: "動詞 runs を修飾するには副詞が必要。fast は形容詞・副詞の両方に使えるが、fastly という語は存在しない。quick は形容詞なので動詞を修飾できない。", rule: "R009", kp: ["動詞を修飾するには副詞を使う", "fast は形容詞・副詞どちらにも使える"] },
  { id: "g378", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "He is ___ careful driver and never speeds.", ja: "彼はとても慎重なドライバーで、スピードを出すことは決してない。", answer: "a", choices: ["a", "an", "the", "some", "any"], expl: "careful は /k/ という子音の音で始まるので、不定冠詞は a を使う。an は母音の音で始まる語の前に置く。", rule: "R015", kp: ["aとanは綴りではなく発音で判断する", "子音の音で始まる語の前はa"] },
  { id: "g379", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "My teacher gave us ___ interesting homework assignment about local history.", ja: "先生は私たちに地元の歴史に関する興味深い宿題を出した。", answer: "an", choices: ["an", "a", "the", "some", "one"], expl: "interesting は /ɪ/ という母音の音で始まるため、不定冠詞は an を使う。", rule: "R015", kp: ["母音の音で始まる語の前はan", "発音で判断する"] },
  { id: "g380", diff: "lv1", axis: "form", tags: ["grammar", "verb", "contraction"], stem: "My older brother ___ enjoy cooking at all.", ja: "私の兄は料理をすることが全く好きではない。", answer: "doesn't", choices: ["doesn't", "don't", "isn't", "aren't", "wasn't"], expl: "主語が My older brother（三人称単数）なので、否定の助動詞は doesn't を使う。don't は複数主語や I・you に使う。", rule: "R028", kp: ["三人称単数主語にはdoesn't", "I・you・複数主語にはdon't"] },
  { id: "g381", diff: "lv1", axis: "tense", tags: ["grammar", "present progressive", "ing", "ongoing action"], stem: "Hurry up! The bus ___ right now.", ja: "急いで！バスが今まさに出発しようとしている。", answer: "is leaving", choices: ["is leaving", "leaves", "left", "will leave", "has left"], expl: "right now という語が今まさに進行中の動作を示しているため、現在進行形 is leaving を使う。", rule: "R047", kp: ["right nowはpresent progressiveのシグナル", "is/am/are + V-ing で進行中の動作を表す"] },
  { id: "g382", diff: "lv1", axis: "form", tags: ["grammar", "some", "any", "quantifier"], stem: "I'm sorry, but there isn't ___ bread left in the basket.", ja: "申し訳ありませんが、かごの中にパンは残っていません。", answer: "any", choices: ["any", "some", "much", "many", "few"], expl: "否定文では any を使って不可算名詞（bread）の有無を表す。some は肯定文で使うのが基本で、否定文には any が適切。", rule: "R043", kp: ["否定文・疑問文ではanyを使う", "some/anyは不可算名詞にも使える"] },
  { id: "g383", diff: "lv1", axis: "form", tags: ["grammar", "some", "any", "quantifier"], stem: "Would you like ___ more tea before you go?", ja: "帰る前にもう少しお茶はいかがですか？", answer: "some", choices: ["some", "any", "many", "much", "few"], expl: "提供・勧誘の疑問文では some を使うのが自然。any は否定文や一般的な疑問文に用いる。", rule: "R043", kp: ["勧誘・提供の疑問文ではsomeを使う", "some/anyは不可算名詞にも使える"] },
  { id: "g384", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "She was born ___ a cold December morning in the city.", ja: "彼女はその都市の寒い12月のある朝に生まれた。", answer: "on", choices: ["on", "in", "at", "during", "by"], expl: "a cold December morning のような特定の朝（日）を表すには on を使う。in は月・年・季節に、at は時刻・noon などに使う。", rule: "R019", kp: ["特定の日・曜日の前にはon", "朝・午後などの時間帯にはin（ただし特定の日の朝はon）"] },
  { id: "g385", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "The concert will begin ___ seven o'clock sharp.", ja: "コンサートはちょうど7時に始まる。", answer: "at", choices: ["at", "on", "in", "by", "for"], expl: "時刻を表すには前置詞 at を使う。on は曜日・特定の日、in は月・年・時間帯に用いる。", rule: "R019", kp: ["時刻の前にはat", "on=曜日・日、in=月・年・季節・時間帯"] },
  { id: "g386", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "The boys left ___ jackets on the bench after the game.", ja: "少年たちは試合後にベンチにジャケットを置いていった。", answer: "their", choices: ["their", "his", "her", "its", "our"], expl: "先行詞 The boys は複数形なので、代名詞も複数形の their を使う。his・her は単数の代名詞なので不一致。", rule: "R024", kp: ["複数の先行詞にはtheirを使う", "代名詞は先行詞と数を一致させる"] },
  { id: "g387", diff: "lv2", axis: "vocab", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "The trophy is displayed ___ the two championship banners on the wall.", ja: "トロフィーは壁の2枚の優勝旗の間に飾られている。", answer: "between", choices: ["between", "among", "beside", "behind", "above"], expl: "2つのもの（two championship banners）の間には between を使う。among は3つ以上のものの間に用いる。", rule: "R023", kp: ["2者の間はbetween", "3者以上の間はamong"] },
  { id: "g388", diff: "lv2", axis: "logic", tags: ["grammar", "verb", "subject", "or", "nor"], stem: "Either the manager or the assistant ___ in charge of locking the office.", ja: "マネージャーかアシスタントのどちらかが事務所の施錠を担当している。", answer: "is", choices: ["is", "are", "were", "have been", "be"], expl: "either A or B で結ばれた2つの単数名詞には単数動詞を使う。or/nor で結ばれた単数名詞には単数動詞が必要。", rule: "R026", kp: ["or/norで結ばれた単数名詞には単数動詞", "Either A or B + 単数動詞"] },
  { id: "g389", diff: "lv2", axis: "logic", tags: ["grammar", "relative pronoun", "relative clause", "antecedent"], stem: "The student ___ won the science competition will represent our school next month.", ja: "科学コンクールで優勝した生徒は来月、私たちの学校を代表する。", answer: "who", choices: ["who", "which", "whom", "whose", "where"], expl: "先行詞 The student は人なので、主格の関係代名詞 who を使う。which は物・概念に用いる。", rule: "R035", kp: ["人を指す関係代名詞はwho/whom", "物・概念にはwhichを使う"] },
  { id: "g390", diff: "lv2", axis: "tense", tags: ["grammar", "modal", "auxiliary", "invariant form"], stem: "She ___ speak four languages fluently after years of practice.", ja: "何年もの練習の末、彼女は4つの言語を流暢に話せる。", answer: "can", choices: ["can", "cans", "is able", "could to", "musts"], expl: "助動詞 can は主語に関わらず形が変わらない。三人称単数でも cans とはしない。", rule: "R049", kp: ["助動詞は主語にかかわらず形が変わらない", "cansやmustsは誤り"] },
  { id: "g391", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic"], stem: "My doctor always gives me useful ___ about staying healthy.", ja: "私の医師はいつも健康を維持することについて役立つアドバイスをくれる。", answer: "advice", choices: ["advice", "advise", "advices", "advisement", "advising"], expl: "動詞 gives の目的語になる名詞が必要。advice が「助言」という意味の名詞。advise は動詞なので名詞の位置には使えない。", rule: "R003", kp: ["adviceは名詞、adviseは動詞", "名詞の位置にはadviceを使う"] },
  { id: "g392", diff: "lv2", axis: "tense", tags: ["grammar", "tense", "auxiliary", "present", "past"], stem: "Every evening, she sits by the window and ___ in her diary.", ja: "毎晩、彼女は窓のそばに座って日記を書く。", answer: "writes", choices: ["writes", "is writing", "has written", "will write", "wrote"], expl: "Every evening という繰り返しの習慣を表す文脈では、動詞単独で表せる現在形を使う。sits と時制を一致させて writes とするのが正しい。", rule: "R044", kp: ["習慣・繰り返しの動作には単純現在形", "同一時間軸の動詞は時制を統一する"] },
  { id: "g393", diff: "lv2", axis: "logic", tags: ["grammar", "relative pronoun", "relative clause", "antecedent"], stem: "The bicycle ___ was stolen from the parking lot has been found by the police.", ja: "駐車場から盗まれた自転車が警察によって発見された。", answer: "that", choices: ["that", "who", "whom", "whose", "what"], expl: "先行詞 The bicycle は物なので関係代名詞 that（または which）を使う。who・whom は人を指す関係代名詞。", rule: "R035", kp: ["物・概念を指す制限用法の関係代名詞はthatまたはwhich", "whoは人に使う"] },
  { id: "g394", diff: "lv3", axis: "tense", tags: ["grammar", "tense", "consistency", "tense shift"], stem: "The journalist interviews the local residents and ___ detailed notes about their daily lives.", ja: "そのジャーナリストは地元住民にインタビューし、彼らの日常生活について詳細なメモをとる。", answer: "takes", choices: ["takes", "took", "has taken", "was taking", "had taken"], expl: "interviews と同じ時間軸（現在の習慣）なので、同じ現在形 takes で統一しなければならない。時制を不必要に変えてはいけない。", rule: "R051", kp: ["同一時間軸の動作は同じ時制で統一する", "不要な時制のシフトは避ける"] },
  { id: "g395", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "eiken2", "toeic"], stem: "She poured the orange juice ___ a tall glass and handed it to her guest.", ja: "彼女はオレンジジュースを背の高いグラスに注ぎ、ゲストに手渡した。", answer: "into", choices: ["into", "onto", "to", "in", "through"], expl: "グラスの内部への移動を表すため、into を使う。onto は表面への移動、to は目的地への方向を示す。", rule: "R022", kp: ["内部への移動にはinto", "表面への移動にはonto、目的地にはto"] },
  { id: "g396", diff: "lv3", axis: "trap", tags: ["eikenpre2", "eiken2", "toeic"], stem: "After the accident, the driver was still ___ and could answer the paramedics' questions.", ja: "事故の後も、ドライバーは意識があり、救急隊員の質問に答えることができた。", answer: "conscious", choices: ["conscious", "conscience", "consciously", "consciousness", "conscientious"], expl: "「意識がある」という意味の形容詞は conscious。conscience は「良心」という意味の名詞で文脈に合わない。", rule: "R004", kp: ["consciousは形容詞で「意識がある」", "conscienceは名詞で「良心」"] },
  { id: "g397", diff: "lv3", axis: "tense", tags: ["grammar", "modal perfect", "could have", "would have", "must have"], stem: "If he had left earlier, he ___ caught the last train.", ja: "もし彼がもっと早く出発していたら、最終電車に乗れていただろう。", answer: "could have", choices: ["could have", "could of", "could has", "could had", "could to have"], expl: "過去の仮定に対する帰結は could have + 過去分詞で表す。could of は spoken English の聞き間違いから来た誤った表記で文法的に誤り。", rule: "R050", kp: ["could have + 過去分詞が正しい形", "could ofは誤り"] },
  { id: "g398", diff: "lv3", axis: "trap", tags: ["eikenpre2", "eiken2", "toeic"], stem: "She performed ___ at the audition and was immediately offered the lead role.", ja: "彼女はオーディションで素晴らしく演じ、すぐに主役を提供された。", answer: "brilliantly", choices: ["brilliantly", "brilliant", "more brilliant", "good", "well-doing"], expl: "動詞 performed を修飾するには副詞が必要。brilliant は形容詞なので動詞を修飾できない。brilliantly（副詞）が正しい。", rule: "R009", kp: ["動詞を修飾するには副詞(-ly形)を使う", "形容詞は名詞を修飾する"] },
  { id: "g399", diff: "lv3", axis: "tense", tags: ["grammar", "past perfect", "had", "past participle"], stem: "By the time the firefighters arrived, the roof ___ completely.", ja: "消防士たちが到着したころには、屋根は完全に崩壊していた。", answer: "had collapsed", choices: ["had collapsed", "collapsed", "has collapsed", "was collapsing", "would collapse"], expl: "消防士が到着する（過去）よりも前に屋根が崩壊した（さらに過去）という時間的前後関係を表すため、過去完了 had collapsed を使う。", rule: "R046", kp: ["過去の別の出来事より前のことにはhad + 過去分詞", "by the timeは過去完了のシグナル"] },
  { id: "g400", diff: "lv3", axis: "logic", tags: ["grammar", "relative clause", "non-restrictive", "non-defining", "comma", "that"], stem: "My neighbor Mr. Tanaka, ___ has lived here for forty years, knows everyone on the street.", ja: "私の隣人の田中さんは、ここに40年間住んでいて、通りの皆を知っている。", answer: "who", choices: ["who", "that", "which", "whose", "whom"], expl: "コンマで区切られた非制限用法の関係節では that は使えない。人を指すので who が正しい。that は非制限用法には使えない。", rule: "R034", kp: ["非制限用法の関係節ではthatは使えない", "コンマ+人はwho、コンマ+物はwhich"] },
  { id: "g401", diff: "lv3", axis: "vocab", tags: ["grammar", "pronoun", "singular they", "gender-neutral"], stem: "Every employee should submit ___ timesheet by the end of Friday.", ja: "すべての従業員は金曜日の終わりまでに勤務表を提出しなければならない。", answer: "their", choices: ["their", "his", "her", "its", "our"], expl: "Every employee は性別が特定されていない個人を指す場合、性別中立の単数 they/their を使うのが現在の標準的な用法。", rule: "R031", kp: ["性別不明の個人にはsingular theyを使う", "hisをデフォルトとする用法は現代では避ける"] },
  { id: "g402", diff: "lv4", axis: "logic", tags: ["grammar", "relative pronoun", "relative clause", "antecedent"], stem: "The company hired twenty new engineers, most ___ had experience in AI development.", ja: "その会社は20人の新しいエンジニアを採用し、その大部分はAI開発の経験があった。", answer: "of whom", choices: ["of whom", "of which", "of that", "of who", "of those"], expl: "先行詞 twenty new engineers は人なので、most of whom を使う。of which は物・概念に使う。", rule: "R037", kp: ["人にはof whom、物にはof whichを使う", "most/some/none of whom/which"] },
  { id: "g403", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic"], stem: "The committee insisted that the chairperson ___ a full written report within two weeks.", ja: "委員会は議長が2週間以内に完全な書面による報告書を提出するよう強く求めた。", answer: "submit", choices: ["submit", "submits", "submitted", "to submit", "submitting"], expl: "insist that 節の中では仮定法現在（動詞の原形）を使う。三人称単数でも -s はつけない。", rule: "R060", kp: ["insist/suggest/recommend + that S + 動詞原形（仮定法現在）", "三人称単数でもsをつけない"] },
  { id: "g404", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic", "juken"], stem: "If I ___ you, I would think twice before making that decision.", ja: "もし私があなたなら、その決断をする前にもう一度よく考えるだろう。", answer: "were", choices: ["were", "was", "am", "have been", "would be"], expl: "現在の事実に反する仮定（仮定法過去）では、be 動詞は主語に関わらず were を使うのが格式的に正しい。", rule: "R055", kp: ["仮定法過去のbe動詞はwere（格式）", "If S were ..., S would V の構造"] },
  { id: "g405", diff: "lv5", axis: "tense", tags: ["eikenpre1", "toeic"], stem: "___ it not for modern medicine, millions of lives would be lost to preventable diseases every year.", ja: "現代医学がなければ、毎年何百万もの命が予防可能な病気で失われていただろう。", answer: "Were", choices: ["Were", "Was", "Had", "Should", "Would"], expl: "Were it not for は If it were not for の倒置形。仮定法では were を使い、was は不可。この構文では Were が文頭に来る。", rule: "R059", kp: ["Were it not for = If it were not forの倒置", "仮定法倒置ではWere（Wasは不可）"] },
  { id: "g406", diff: "lv1", axis: "tense", tags: ["grammar", "present progressive", "ing", "ongoing action"], stem: "Hurry up! The kettle ___ on the stove right now.", ja: "急いで！ケトルが今コンロで沸いているよ。", answer: "is boiling", choices: ["is boiling", "boils", "boiled", "has boiled", "will boil"], expl: "「right now（今まさに）」があるため、現在進行中の動作を表す現在進行形 is boiling が正解。", rule: "現在進行形", kp: ["right now → is/am/are + verb-ing", "現在進行形は今起きていることを表す"] },
  { id: "g407", diff: "lv1", axis: "tense", tags: ["grammar", "present progressive", "ing", "ongoing action"], stem: "Look at those clouds! It ___ heavily outside at the moment.", ja: "あの雲を見て！今外は激しく雨が降っている。", answer: "is raining", choices: ["is raining", "rains", "rained", "has rained", "will rain"], expl: "「at the moment（今この瞬間）」というシグナルから、現在進行中の動作を示す is raining が正解。", rule: "現在進行形", kp: ["at the moment → 現在進行形", "is/am/are + verb-ing で今起きていることを表す"] },
  { id: "g408", diff: "lv1", axis: "form", tags: ["grammar", "some", "any", "quantifier"], stem: "Is there ___ orange juice in the refrigerator?", ja: "冷蔵庫にオレンジジュースは少し残っていますか？", answer: "any", choices: ["any", "some", "much", "many", "a few"], expl: "疑問文では不可算名詞・可算名詞ともに any を使うのが基本。much も不可算名詞に使えるが、「is there much juice?」は不自然で、anyが正しい疑問文のパターン。", rule: "some/anyは可算名詞・不可算名詞の両方に使える", kp: ["疑問文・否定文 → any", "some/any は可算・不可算の両方に使える"] },
  { id: "g409", diff: "lv1", axis: "form", tags: ["grammar", "some", "any", "quantifier"], stem: "We need to buy ___ apples and ___ milk before the store closes.", ja: "店が閉まる前にリンゴと牛乳をいくらか買わなければならない。", answer: "some", choices: ["some", "any", "many", "much", "few"], expl: "肯定文では some を使い、可算名詞（apples）にも不可算名詞（milk）にも同様に使える。", rule: "some/anyは可算名詞・不可算名詞の両方に使える", kp: ["肯定文 → some", "some は可算・不可算名詞のどちらにも使える"] },
  { id: "g410", diff: "lv1", axis: "form", tags: ["grammar", "verb", "contraction", "doesn't", "don't"], stem: "My cat ___ like the new brand of cat food at all.", ja: "私の猫は新しいブランドのキャットフードが全く好きではない。", answer: "doesn't", choices: ["doesn't", "don't", "isn't", "aren't", "hasn't"], expl: "主語が My cat（三人称単数）なので、否定形は doesn't を使う。don't は複数や I・you に使う。", rule: "doesn'tは単数主語、don'tは複数主語に使う（I・youはdon't）", kp: ["He/She/It → doesn't", "三人称単数には doesn't"] },
  { id: "g411", diff: "lv1", axis: "form", tags: ["grammar", "verb", "contraction", "doesn't", "don't"], stem: "The new supermarket near our house ___ open on Sundays.", ja: "私たちの家の近くの新しいスーパーマーケットは日曜日に開いていない。", answer: "doesn't", choices: ["doesn't", "don't", "isn't", "aren't", "not"], expl: "主語 The new supermarket は三人称単数なので doesn't が正しい。don't は複数主語や I・you に用いる。", rule: "doesn'tは単数主語、don'tは複数主語に使う（I・youはdon't）", kp: ["単数主語 → doesn't", "複数主語・I・you → don't"] },
  { id: "g412", diff: "lv1", axis: "form", tags: ["grammar", "verb", "contraction", "doesn't", "don't"], stem: "My cousins ___ live in this country anymore; they moved abroad.", ja: "私のいとこたちはもうこの国には住んでいない。海外に引っ越した。", answer: "don't", choices: ["don't", "doesn't", "isn't", "aren't", "hasn't"], expl: "主語が My cousins（複数）なので don't を使う。doesn't は三人称単数にしか使えない。", rule: "doesn'tは単数主語、don'tは複数主語に使う（I・youはdon't）", kp: ["複数主語 → don't", "I・you → don't（単数でも）"] },
  { id: "g413", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "She is a very ___ singer and always wins the school competitions.", ja: "彼女はとても才能のある歌手で、学校のコンテストでいつも優勝する。", answer: "talented", choices: ["talented", "talently", "talent", "talentful", "talentedly"], expl: "名詞 singer を修飾するのは形容詞。副詞 talently や名詞 talent は名詞を修飾できない。talented（形容詞）が正解。", rule: "形容詞の基本：名詞を修飾する", kp: ["名詞を修飾するのは形容詞", "副詞・名詞は名詞の直前に置けない"] },
  { id: "g414", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "The boys brought ___ sports equipment to the gym by themselves.", ja: "少年たちは自分たちでジムにスポーツ用具を持ってきた。", answer: "their", choices: ["their", "his", "her", "its", "our"], expl: "先行詞が The boys（複数）なので、代名詞も複数形の their を使う。his や her は単数で性別が特定される場合に使う。", rule: "代名詞の数の一致", kp: ["先行詞が複数 → their/them", "代名詞は先行詞の数に一致させる"] },
  { id: "g415", diff: "lv2", axis: "form", tags: ["grammar", "verb", "subject", "or", "nor"], stem: "Either the principal or the vice principal ___ responsible for making the announcement.", ja: "校長か副校長のどちらかがアナウンスをする責任がある。", answer: "is", choices: ["is", "are", "were", "have been", "being"], expl: "either A or B の構造で A と B がともに単数名詞の場合、動詞は単数形 is を使う。", rule: "orまたはnorで結ばれた複数の単数名詞・代名詞には単数形の動詞を使う", kp: ["Either A or B + 単数動詞", "or/nor で結ばれた単数名詞 → 単数動詞"] },
  { id: "g416", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "After running the marathon, she felt completely ___.", ja: "マラソンを走り終えた後、彼女は完全に疲れ果てていた。", answer: "exhausted", choices: ["exhausted", "exhaustedly", "exhausting", "exhaustion", "exhaust"], expl: "feel の後は主語の状態を説明する形容詞が来る。副詞 exhaustedly や名詞 exhaustion は不適切。exhausted（形容詞）が正解。", rule: "be動詞・感覚動詞の後は形容詞", kp: ["feel/look/seem の後は形容詞", "副詞・名詞は感覚動詞の後に置けない"] },
  { id: "g417", diff: "lv2", axis: "tense", tags: ["grammar", "past progressive", "was", "were", "ing"], stem: "The students ___ their final exam when the fire drill suddenly started.", ja: "生徒たちが期末試験を受けているときに、突然避難訓練が始まった。", answer: "were taking", choices: ["were taking", "took", "had taken", "have taken", "take"], expl: "「when the fire drill suddenly started（別の動作に割り込まれた）」とあるため、そのとき進行中だった動作には過去進行形 were taking を使う。", rule: "過去進行形は過去のある時点で進行中だった動作、または別の動作に割り込まれた動作を表す", kp: ["when + 過去形 → 割り込まれた動作は過去進行形", "was/were + verb-ing"] },
  { id: "g418", diff: "lv2", axis: "vocab", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "The treasure chest was discovered ___ a heavy stone and an ancient wooden door.", ja: "宝箱は重い石と古い木の扉の間で発見された。", answer: "between", choices: ["between", "among", "beside", "through", "above"], expl: "2つのもの（a heavy stone と an ancient wooden door）の間には between を使う。among は3つ以上の間に用いる。", rule: "空間的前置詞の一覧（above/below/between等）", kp: ["2者の間 → between", "3者以上の間 → among"] },
  { id: "g419", diff: "lv2", axis: "tense", tags: ["grammar", "past progressive", "was", "were", "ing"], stem: "She ___ a phone call while her brother was washing the dishes.", ja: "兄が皿を洗っている間、彼女は電話をしていた。", answer: "was making", choices: ["was making", "made", "has made", "make", "had made"], expl: "while は同時進行を示すシグナルで、過去のある時点で進行中の動作には was making（過去進行形）を使う。", rule: "過去進行形は過去のある時点で進行中だった動作、または別の動作に割り込まれた動作を表す", kp: ["while + 同時進行 → 過去進行形", "was/were + verb-ing"] },
  { id: "g420", diff: "lv2", axis: "form", tags: ["grammar", "noun", "count", "noncount", "plural"], stem: "We need to buy new ___ for the break room because the old ones are broken.", ja: "古いものが壊れているので、休憩室に新しい家具を買う必要がある。", answer: "furniture", choices: ["furniture", "furnitures", "a furniture", "the furnitures", "some furnitures"], expl: "furniture は不可算名詞なので複数形にすることができない。furnitures は誤りで、furniture がそのまま正しい形。", rule: "可算名詞は複数形になれるが、不可算名詞は原則として複数形にならない", kp: ["furniture は不可算名詞 → 複数形にしない", "不可算名詞には -s をつけない"] },
  { id: "g421", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic"], stem: "She went to her teacher for ___ on how to improve her essay.", ja: "彼女はエッセイの改善方法についてアドバイスを求めに先生のところへ行った。", answer: "advice", choices: ["advice", "advise", "advices", "an advise", "advisement"], expl: "名詞が必要な位置であり、正しい名詞形は advice（不可算名詞）。advise は動詞であり、ここでは使えない。", rule: "advise と advice の区別", kp: ["名詞は advice（末尾 -ice）", "動詞は advise（末尾 -ise）"] },
  { id: "g422", diff: "lv2", axis: "form", tags: ["grammar", "irregular verb", "past tense", "past participle"], stem: "By the time the guests arrived, we had already ___ all the food.", ja: "客が到着する頃には、私たちはすでに食べ物を全部食べていた。", answer: "eaten", choices: ["eaten", "ate", "eated", "eat", "eating"], expl: "had + 過去分詞の形（過去完了）が必要。eat の過去分詞は eaten（不規則変化）。eated という形は存在しない。", rule: "不規則動詞は過去形・過去分詞形が規則的な-ed形にならず、固有の変化をする", kp: ["eat → ate → eaten（不規則変化）", "had + 過去分詞 → 過去完了"] },
  { id: "g423", diff: "lv3", axis: "trap", tags: ["eikenpre2", "eiken2", "toeic"], stem: "All the team members were present ___ the project leader, who was ill.", ja: "病気だったプロジェクトリーダーを除いて、チームメンバー全員が出席していた。", answer: "except", choices: ["except", "accept", "without", "beside", "unless"], expl: "「〜を除いて」という前置詞の意味が必要。except が正しい。accept は「受け取る・同意する」という動詞で前置詞として使えない。", rule: "accept と except の区別", kp: ["「〜を除いて」→ except（前置詞）", "accept は動詞、except は前置詞"] },
  { id: "g424", diff: "lv3", axis: "tense", tags: ["grammar", "modal perfect", "could have", "would have", "must have"], stem: "She looked so pale and tired. She ___ stayed up all night studying.", ja: "彼女はとても青白く疲れて見えた。一晩中勉強していたに違いない。", answer: "must have", choices: ["must have", "must of", "should of", "could of", "would of"], expl: "「〜に違いない」という過去への推量は must have + 過去分詞で表す。must of などは口語の誤用であり正式な英語では使えない。", rule: "could have / would have / must haveの後には過去分詞を置く（'of'は誤り）", kp: ["must have + 過去分詞 → 過去への確信的推量", "of ではなく have を使う"] },
  { id: "g425", diff: "lv3", axis: "form", tags: ["grammar", "pronoun", "singular they", "gender-neutral"], stem: "When a customer calls with a complaint, ___ should be connected to the support team immediately.", ja: "顧客が苦情の電話をかけてきたとき、その人はすぐにサポートチームにつないでもらうべきだ。", answer: "they", choices: ["they", "he", "she", "it", "one"], expl: "性別不明の個人を指す場合、単数の they が現代英語では公式に認められた表現。he を総称的に使うのは避けるべき。", rule: "単数のtheyは性別を特定しない個人または非二元的な性自認を持つ人を指す代名詞として使える", kp: ["性別不明の個人 → 単数 they", "he を総称的に使うことは現代では避けられる"] },
  { id: "g426", diff: "lv3", axis: "form", tags: ["grammar", "verb", "subject", "intervening phrase"], stem: "The manager, together with all the department heads, ___ planning to attend the conference.", ja: "マネージャーは全部長とともに、その会議に参加する予定だ。", answer: "is", choices: ["is", "are", "were", "have been", "being"], expl: "主語は The manager（単数）であり、together with 以下は挿入句。動詞は主語 The manager に一致させて is が正解。", rule: "主語と動詞の間に挿入句があっても、動詞は主語に一致させる", kp: ["together with / as well as は挿入句 → 主語の数で動詞を決める", "挿入句は動詞の数に影響しない"] },
  { id: "g427", diff: "lv3", axis: "tense", tags: ["grammar", "modal perfect", "could have", "would have", "must have"], stem: "If he had taken better care of himself, he ___ avoided getting sick.", ja: "もっと体に気をつけていれば、彼は病気を避けられたのに。", answer: "could have", choices: ["could have", "could of", "would of", "might of", "should of"], expl: "「〜できたのに」という過去の可能性は could have + 過去分詞で表す。could of は誤りで、have を使う必要がある。", rule: "could have / would have / must haveの後には過去分詞を置く（'of'は誤り）", kp: ["could have + 過去分詞 → 過去の可能性・後悔", "of ではなく have"] },
  { id: "g428", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic"], stem: "If the manager ___ the report in advance, the meeting would have gone more smoothly.", ja: "もしマネージャーが事前に報告書を読んでいれば、会議はもっとスムーズに進んだだろう。", answer: "had read", choices: ["had read", "read", "would have read", "has read", "was reading"], expl: "過去の事実に反する仮定（仮定法過去完了）の if 節は had + 過去分詞の形。read の過去分詞は read（同形）。", rule: "仮定法過去完了", kp: ["If + had + pp → 過去の事実に反する仮定", "帰結節は would have + pp"] },
  { id: "g429", diff: "lv4", axis: "logic", tags: ["grammar", "of whom", "of which", "relative pronoun", "quantifier"], stem: "The committee interviewed twelve candidates, three ___ had previously worked overseas.", ja: "委員会は12人の候補者を面接したが、そのうちの3人は以前海外で働いた経験があった。", answer: "of whom", choices: ["of whom", "of which", "of that", "of who", "of whose"], expl: "候補者（人）を先行詞とする量化表現には of whom を使う。of which は物・概念を指す場合に使う。", rule: "most, many, some, both, noneなどの後で人にはof whom、物にはof whichを使う", kp: ["人 → of whom", "物・概念 → of which"] },
  { id: "g430", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic"], stem: "If the engineers ___ the warning signals earlier, they would have prevented the system crash.", ja: "もしエンジニアたちがもっと早く警告信号に気づいていれば、システムのクラッシュを防げたのに。", answer: "had noticed", choices: ["had noticed", "noticed", "would have noticed", "have noticed", "were noticing"], expl: "過去の事実に反する仮定（仮定法過去完了）では if 節に had + 過去分詞を使う。noticed は単純過去で仮定法にならない。", rule: "仮定法過去完了", kp: ["If had + pp → 仮定法過去完了の if 節", "would have + pp が帰結節"] },
  { id: "g431", diff: "lv4", axis: "logic", tags: ["grammar", "which", "non-defining", "clause reference"], stem: "The board approved the new budget proposal, ___ came as a surprise to many employees.", ja: "取締役会が新しい予算案を承認したことは、多くの社員にとって驚きだった。", answer: "which", choices: ["which", "that", "what", "who", "it"], expl: "前の節全体（取締役会が予算案を承認したこと）を先行詞とする非制限用法の関係節には which を使う。that は非制限用法には使えない。", rule: "節全体を先行詞とする非制限用法の関係節にはwhichを使う", kp: ["節全体を先行詞にする非制限用法 → which", "that は非制限用法に使えない"] },
  { id: "g432", diff: "lv5", axis: "vocab", tags: ["eikenpre1", "toeic"], stem: "The stricter data privacy rules are scheduled to come ___ effect from the first of next month.", ja: "より厳しいデータプライバシー規則は来月1日から施行される予定だ。", answer: "into", choices: ["into", "in", "to", "onto", "under"], expl: "「施行される」は come into effect という固定表現。into が正しい前置詞で、in や to では意味をなさない。", rule: "come into effect", kp: ["come into effect = 施行される・発効する", "into を使う（in / to は誤り）"] },
  { id: "g433", diff: "lv5", axis: "logic", tags: ["eikenpre1", "toeic"], stem: "Hardly ___ her acceptance speech when the lights in the hall suddenly went out.", ja: "彼女が受諾スピーチを始めてほどなく、ホールの電気が突然消えた。", answer: "had she begun", choices: ["had she begun", "she had begun", "had she begin", "she began", "did she begin"], expl: "Hardly + had + S + 過去分詞 + when ... の倒置構文が必要。Hardly の後は助動詞 had を先に置く倒置形をとる。", rule: "Hardly had S pp when ...", kp: ["Hardly + had + S + pp + when → 倒置が必要", "hardly → when（no sooner → than）"] },
  { id: "g434", diff: "lv1", axis: "form", tags: ["grammar", "some", "any", "quantifier"], stem: "Is there ___ salt in the cupboard? We need some for the soup.", ja: "棚に塩はありますか？スープに必要なんです。", answer: "any", choices: ["any", "much", "many", "some", "few"], expl: "疑問文では不可算名詞・可算名詞を問わず any を使います。much は否定・疑問文で使えますが、ここでは any が最も自然です。", rule: "some/anyは可算名詞・不可算名詞の両方に使える", kp: ["疑問文・否定文では any", "any は可算・不可算両方に使える"] },
  { id: "g435", diff: "lv1", axis: "form", tags: ["grammar", "some", "any", "quantifier"], stem: "There are ___ interesting museums in this city. You should visit them.", ja: "この街には興味深い博物館がいくつかあります。ぜひ行ってみてください。", answer: "some", choices: ["some", "any", "much", "many a", "few"], expl: "肯定文で可算名詞の複数形に「いくつかの」を表す場合は some を使います。", rule: "some/anyは可算名詞・不可算名詞の両方に使える", kp: ["肯定文では some", "some は可算名詞複数形にも使える"] },
  { id: "g436", diff: "lv1", axis: "form", tags: ["grammar", "some", "any", "quantifier"], stem: "We didn't find ___ useful information in the report.", ja: "私たちはレポートの中に有益な情報を何も見つけられませんでした。", answer: "any", choices: ["any", "some", "much", "many", "no"], expl: "否定文では any を使います。not ... any で「まったく～ない」を表します。", rule: "some/anyは可算名詞・不可算名詞の両方に使える", kp: ["否定文では any", "any は不可算名詞にも使える"] },
  { id: "g437", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "She made ___ unusual decision that surprised everyone in the office.", ja: "彼女は職場の全員を驚かせた、珍しい決断をしました。", answer: "an", choices: ["an", "a", "the", "some", "any"], expl: "unusual の頭文字は u ですが、発音は /ʌn-/ と母音音で始まるため an を使います。", rule: "不定冠詞 a vs. an：音に基づく選択", kp: ["発音が母音で始まる語の前は an", "unusual は /ʌn/ と母音音で始まる"] },
  { id: "g438", diff: "lv1", axis: "trap", tags: ["eiken4", "eiken3", "juken"], stem: "My grandfather was ___ honorable judge who served for thirty years.", ja: "私の祖父は30年間勤めた立派な裁判官でした。", answer: "an", choices: ["an", "a", "the", "one", "some"], expl: "honorable の h は発音されないため、/ɒn-/ と母音音で始まります。そのため a ではなく an を使います。", rule: "不定冠詞 a vs. an：音に基づく選択", kp: ["サイレント h の語の前は an", "honorable は /ɒn/ と発音される"] },
  { id: "g439", diff: "lv1", axis: "form", tags: ["grammar", "present progressive", "ing", "ongoing action"], stem: "Please don't interrupt him. He ___ an important phone call at the moment.", ja: "彼の邪魔をしないでください。彼は今、大事な電話をしています。", answer: "is making", choices: ["is making", "makes", "make", "was making", "has made"], expl: "at the moment（今この瞬間）という信号語があるため、現在進行形 is making を使います。", rule: "現在進行形は今進行中の動作または近い将来の予定を表す", kp: ["at the moment → 現在進行形", "is/am/are + V-ing で今進行中の動作を表す"] },
  { id: "g440", diff: "lv1", axis: "form", tags: ["grammar", "adverb", "form"], stem: "The athlete ran ___ and broke the school record.", ja: "その選手は速く走り、学校の記録を破りました。", answer: "fast", choices: ["fast", "fastly", "good", "well-done", "quick"], expl: "ran（動詞）を修飾するには副詞が必要です。fast は形容詞・副詞ともに同形で正しく使えます。fastly という語は存在しません。", rule: "副詞の基本：動詞・形容詞・副詞を修飾する", kp: ["動詞を修飾するのは副詞", "fast は副詞としても使える（fastly は誤り）"] },
  { id: "g441", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "The annual flower festival is held ___ April in this region.", ja: "この地域では毎年4月に花まつりが開催されます。", answer: "in", choices: ["in", "on", "at", "by", "during"], expl: "月（April）の前には前置詞 in を使います。on は曜日・特定の日付、at は時刻や noon などに使います。", rule: "前置詞 on/at/in：時間の使い分け", kp: ["月・年・季節・時間帯には in", "曜日には on、時刻には at"] },
  { id: "g442", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "Our weekly team meeting always starts ___ nine o'clock sharp.", ja: "私たちの週1回のチームミーティングは常に9時ちょうどに始まります。", answer: "at", choices: ["at", "in", "on", "by", "from"], expl: "時刻（nine o'clock）の前には前置詞 at を使います。", rule: "前置詞 on/at/in：時間の使い分け", kp: ["時刻・noon・night の前は at", "in は月・年・季節に使う"] },
  { id: "g443", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "She always goes jogging ___ Sunday mornings before breakfast.", ja: "彼女はいつも日曜日の朝、朝食前にジョギングに行きます。", answer: "on", choices: ["on", "in", "at", "during", "for"], expl: "曜日（Sunday）の前には前置詞 on を使います。Sunday mornings のように時間帯が続く場合も on を使います。", rule: "前置詞 on/at/in：時間の使い分け", kp: ["曜日の前は on", "on Sunday / on Monday のように使う"] },
  { id: "g444", diff: "lv2", axis: "vocab", tags: ["eiken3", "eikenpre2", "toeic"], stem: "Could you ___ me on which career path I should choose?", ja: "どのキャリアパスを選ぶべきか、アドバイスしてもらえますか？", answer: "advise", choices: ["advise", "advice", "adviced", "advising", "advisement"], expl: "動詞の位置（Could you ___）には動詞 advise を使います。advice は名詞なので動詞位置には使えません。", rule: "advise と advice の区別", kp: ["advise = 動詞（助言する）", "advice = 名詞（助言）"] },
  { id: "g445", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "She wasted ___ time worrying about things she couldn't control.", ja: "彼女はコントロールできないことを心配して多くの時間を無駄にしました。", answer: "much", choices: ["much", "many", "few", "any", "several"], expl: "time は不可算名詞なので much を使います。many は可算名詞の複数形に使います。", rule: "可算名詞と不可算名詞：much vs. many", kp: ["much + 不可算名詞", "many + 可算名詞（複数形）"] },
  { id: "g446", diff: "lv2", axis: "tense", tags: ["grammar", "modal", "auxiliary", "invariant form"], stem: "No matter how difficult the task is, she ___ handle it on her own.", ja: "どんなに難しい仕事でも、彼女は一人でこなすことができます。", answer: "can", choices: ["can", "cans", "is canning", "canned", "to can"], expl: "助動詞（modal）は主語の人称・数に関わらず形が変わりません。she に合わせて cans とするのは誤りです。", rule: "助動詞（can, will, shall, may, could, would, should, might, must）は主語に関わらず形が変わらない", kp: ["助動詞は主語に関わらず原形のまま", "she cans は誤り → she can が正しい"] },
  { id: "g447", diff: "lv2", axis: "logic", tags: ["grammar", "relative pronoun", "relative clause", "antecedent"], stem: "The bridge ___ connects the two islands was completed just last year.", ja: "二つの島をつないでいる橋は、ちょうど昨年完成しました。", answer: "that", choices: ["that", "who", "whom", "what", "where"], expl: "先行詞が「物」（bridge）で、関係節が主語の役割を果たす制限用法では that を使います。", rule: "関係代名詞は先行詞を修飾する従属節（関係節）を導く", kp: ["制限用法で先行詞が物 → that が自然", "who は人に使う"] },
  { id: "g448", diff: "lv3", axis: "logic", tags: ["grammar", "verb", "subject", "or", "nor", "proximity"], stem: "Neither the director nor the producers ___ satisfied with the final cut of the film.", ja: "監督も制作者たちも映画の最終カットには満足していませんでした。", answer: "were", choices: ["were", "was", "are", "is", "have been"], expl: "nor で結ばれた場合、動詞は直前の名詞（producers = 複数）に一致するため were を使います。", rule: "or/norで単数・複数の名詞が結ばれる場合、動詞は動詞に近い方の主語に一致させる", kp: ["nor の後の動詞は直前の名詞に一致", "producers（複数）→ were"] },
  { id: "g449", diff: "lv3", axis: "form", tags: ["grammar", "verb", "subject", "or", "nor", "proximity"], stem: "Either the students or the teacher ___ responsible for setting up the classroom.", ja: "生徒か先生のどちらかが教室のセッティングをする担当です。", answer: "is", choices: ["is", "are", "were", "have been", "be"], expl: "or で結ばれた場合、動詞は直前の名詞（teacher = 単数）に一致するため is を使います。", rule: "or/norで単数・複数の名詞が結ばれる場合、動詞は動詞に近い方の主語に一致させる", kp: ["or の後の動詞は直前の名詞に一致", "teacher（単数）→ is"] },
  { id: "g450", diff: "lv3", axis: "form", tags: ["grammar", "pronoun", "singular they", "gender-neutral"], stem: "If a customer has a complaint, ___ should contact our support team directly.", ja: "お客様にご不満がある場合は、直接サポートチームにご連絡ください。", answer: "they", choices: ["they", "he", "she", "it", "he or she"], expl: "性別が不明な個人を指す場合、現代英語では単数の they が広く認められています。", rule: "単数のtheyは性別を特定しない個人または非二元的な性自認を持つ人を指す代名詞として使える", kp: ["性別不明の個人 → 単数 they", "he を汎用デフォルトにするのは現代では避けられる"] },
  { id: "g451", diff: "lv3", axis: "logic", tags: ["grammar", "relative clause", "non-restrictive", "non-defining", "comma", "that"], stem: "My hometown, ___ I visited last summer, has changed dramatically since I left.", ja: "昨夏に訪れた私の故郷は、去ってから劇的に変わっていました。", answer: "which", choices: ["which", "that", "who", "where", "what"], expl: "コンマで区切られた非制限用法の関係節では that は使えません。先行詞が場所でも物として捉える場合は which を使います。", rule: "非制限用法の関係節（非定義節）はコンマで区切り、thatは使えない", kp: ["非制限用法（コンマあり）では that 不可", "コンマ + which で追加情報を付加"] },
  { id: "g452", diff: "lv3", axis: "vocab", tags: ["eikenpre2", "eiken2", "toeic"], stem: "The heavy rainfall last month ___ the quality of the wheat harvest significantly.", ja: "先月の大雨は小麦の収穫の品質に大きな影響を与えました。", answer: "affected", choices: ["affected", "effected", "effect", "affecting", "affect on"], expl: "「影響を与えた」という動詞には affect（過去形 affected）を使います。effect は名詞、または「もたらす」という意味の動詞です。", rule: "affect と effect の区別（RAVEN）", kp: ["affect = 動詞（影響する）", "effect = 名詞（影響・結果）"] },
  { id: "g453", diff: "lv3", axis: "trap", tags: ["eikenpre2", "eiken2", "toeic"], stem: "The new diet had a noticeable ___ on her energy levels within just two weeks.", ja: "新しい食事法はわずか2週間で彼女のエネルギーレベルに顕著な効果をもたらしました。", answer: "effect", choices: ["effect", "affect", "effecting", "affecting", "affection"], expl: "冠詞 a の後は名詞が来ます。「影響・効果」を表す名詞は effect です。affect は動詞です。", rule: "affect と effect の区別（RAVEN）", kp: ["effect = 名詞（効果・影響）", "a の直後は名詞 → affect（動詞）は不可"] },
  { id: "g454", diff: "lv3", axis: "logic", tags: ["eikenpre2", "eiken2", "toeic"], stem: "She carefully poured the hot coffee ___ the mug without spilling a drop.", ja: "彼女は一滴もこぼさずに熱いコーヒーをマグカップの中に丁寧に注ぎました。", answer: "into", choices: ["into", "onto", "to", "in", "on"], expl: "液体をカップの「内部」に移動させる場合は into を使います。onto は表面への移動、to は目的地への方向を示します。", rule: "方向の前置詞 to/onto/into の使い分け", kp: ["内部への移動 → into", "表面への移動 → onto、目的地への方向 → to"] },
  { id: "g455", diff: "lv4", axis: "form", tags: ["toeic", "eiken2"], stem: "The survey results showed that the three departments had four, ___, and nine employees respectively.", ja: "調査結果によると、3つの部署にはそれぞれ4人、___人、9人の従業員がいることがわかりました。", answer: "seven", choices: ["seven", "7", "7th", "the seventh", "seventh"], expl: "同一文中で数字の表記形式を統一する必要があります。four と nine がスペルアウトされているので、seven とスペルアウトするのが正しいです。", rule: "同一文中の数字の一貫性", kp: ["同じ文では数字の表記形式を統一する", "four, nine とスペルアウト → seven も同様に"] },
  { id: "g456", diff: "lv4", axis: "logic", tags: ["eiken2", "eikenpre1", "toeic"], stem: "The prime minister, ___ the most influential figure of his era, is remembered for his economic reforms.", ja: "その時代で最も影響力のある人物であった首相は、経済改革によって記憶されています。", answer: "the most influential figure of his era", choices: ["the most influential figure of his era", "the most influential figure of his era,", ", the most influential figure of his era", "who the most influential figure of his era", "which the most influential figure of his era"], expl: "「首相」はそれだけで特定できるため、同格語は非制限的（追加情報）です。コンマで区切る必要がありますが、この問題では同格語そのものの選択として、コンマなしの語句を空欄に入れる形式です（文全体でコンマが既に付与されています）。", rule: "同格語のコンマ：制限的vs非制限的", kp: ["固有名詞など単独で特定できる名詞の同格語は非制限的 → コンマあり", "同格語を取り除いても文の意味が通るかを確認する"] },
  { id: "g457", diff: "lv4", axis: "tense", tags: ["eiken2", "toeic", "juken"], stem: "If he ___ more time to prepare, his presentation would be far more convincing.", ja: "もし準備する時間がもっとあれば、彼のプレゼンテーションははるかに説得力があるでしょう。", answer: "had", choices: ["had", "has", "would have", "will have", "have"], expl: "現在の事実に反する仮定（仮定法過去）では、If 節の動詞は過去形を使います。主語が he でも were や had など過去形を用います。", rule: "仮定法過去", kp: ["仮定法過去：If + 過去形, would + 原形", "現在の事実に反する仮定 → If 節に過去形"] },
  { id: "g458", diff: "lv4", axis: "form", tags: ["toeic", "eiken2"], stem: "The report listed the following error rates: two percent, ___, and eight percent across the three divisions.", ja: "報告書には、3つの部門にわたるエラー率として、2パーセント、___パーセント、8パーセントが記載されていました。", answer: "five", choices: ["five", "5", "5th", "the fifth", "fifth"], expl: "同じ文中で two と eight がスペルアウトされているため、表記の一貫性を保つために five もスペルアウトします。", rule: "同一文中の数字の一貫性", kp: ["同一文内では数字の書き方を統一する", "スペルアウトか数字かを揃えること"] },
  { id: "g459", diff: "lv5", axis: "tense", tags: ["eikenpre1", "toeic"], stem: "___ the committee reviewed the proposal more carefully, the critical errors would have been caught before publication.", ja: "委員会がより慎重に提案書を審査していたなら、出版前に重大なエラーが発見されていたでしょう。", answer: "Had", choices: ["Had", "If", "Were", "Should", "Would"], expl: "仮定法の倒置形では If を省略して Had + S + 過去分詞 の語順にします。ここでは Had the committee reviewed ... が正しい倒置形です。", rule: "仮定法の倒置 (Had S pp)", kp: ["If 省略 → Had + S + 過去分詞（倒置）", "帰結節は would have + 過去分詞"] },
  { id: "g460", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "The dog barked ___ at the stranger near the gate.", ja: "その犬は門の近くにいた見知らぬ人に向かって激しく吠えた。", answer: "loudly", choices: ["loudly", "loud", "louder", "loudness", "loudest"], expl: "動詞 barked（吠えた）を修飾するには副詞が必要です。loud は形容詞なので動詞を修飾できず、副詞形 loudly を使います。", rule: "副詞の基本：動詞・形容詞・副詞を修飾する", kp: ["動詞を修飾するときは副詞（-ly形）を使う", "loud（形容詞）→ loudly（副詞）"] },
  { id: "g461", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "She finished the race ___ and won first place.", ja: "彼女はレースを素早く終え、1位になった。", answer: "quickly", choices: ["quickly", "quick", "quicker", "quicken", "quickest"], expl: "動詞 finished を修飾するには副詞が必要です。quick は形容詞なので副詞形の quickly を使う必要があります。", rule: "副詞の基本：動詞・形容詞・副詞を修飾する", kp: ["動詞を修飾するには副詞（-ly形）を使う", "quick（形容詞）→ quickly（副詞）"] },
  { id: "g462", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "He is a very ___ person and always helps others.", ja: "彼はとても親切な人で、いつも他の人を助けます。", answer: "kind", choices: ["kind", "kindly", "kindness", "kinder", "kindest"], expl: "名詞 person を修飾するには形容詞が必要です。kindly は副詞なので名詞を修飾できません。形容詞 kind を使います。", rule: "形容詞の基本：名詞を修飾する", kp: ["名詞を修飾するときは形容詞を使う", "kindly は副詞なので名詞の前には置けない"] },
  { id: "g463", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "That was a ___ decision by the manager.", ja: "それはマネージャーによる賢明な決断だった。", answer: "wise", choices: ["wise", "wisely", "wisdom", "wiser", "wisest"], expl: "名詞 decision を修飾するには形容詞が必要です。wisely は副詞なので名詞を修飾できず、形容詞 wise を使います。", rule: "形容詞の基本：名詞を修飾する", kp: ["名詞の前に置くのは形容詞", "wisely（副詞）は名詞を修飾できない"] },
  { id: "g464", diff: "lv1", axis: "form", tags: ["eiken4", "eiken3", "juken"], stem: "The teacher explained the lesson ___ so all the students understood.", ja: "先生はレッスンをわかりやすく説明したので、生徒全員が理解した。", answer: "clearly", choices: ["clearly", "clear", "clearer", "clearness", "clearest"], expl: "動詞 explained を修飾するには副詞が必要です。clear は形容詞なので、副詞形の clearly を使います。", rule: "副詞の基本：動詞・形容詞・副詞を修飾する", kp: ["動詞を修飾するには副詞（-ly形）を使う", "clear（形容詞）→ clearly（副詞）"] },
  { id: "g465", diff: "lv2", axis: "vocab", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "The small café is located ___ the bookstore and the pharmacy.", ja: "その小さなカフェは書店と薬局の間にある。", answer: "between", choices: ["between", "among", "beside", "behind", "through"], expl: "書店と薬局という2つのものの間を表すには between を使います。among は3つ以上のものの間に使います。", rule: "空間的前置詞の一覧（above/below/between等）", kp: ["2者の間 → between", "3者以上の間 → among"] },
  { id: "g466", diff: "lv2", axis: "tense", tags: ["grammar", "present perfect", "have", "has", "past participle"], stem: "She ___ this company for over fifteen years and still enjoys her job.", ja: "彼女はこの会社に15年以上勤めており、今でも仕事を楽しんでいる。", answer: "has worked for", choices: ["has worked for", "worked for", "is working for", "had worked for", "works for"], expl: "過去から現在まで続いている状況を表すには現在完了形（have/has + 過去分詞）を使います。still enjoys という現在の継続を示す表現がヒントです。", rule: "現在完了形は過去に始まり現在まで続く動作・状態、または効果が今も残る完了した行為を表す", kp: ["現在まで続く動作・状態 → 現在完了形（has/have + 過去分詞）", "for と共に使われることが多い"] },
  { id: "g467", diff: "lv2", axis: "logic", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "Could you pass me ___ salt, please? It's right next to you.", ja: "その塩を取ってもらえますか？あなたのすぐ隣にありますよ。", answer: "the", choices: ["the", "a", "an", "some", "any"], expl: "話し手と聞き手が「どの塩か」を共有しており（目の前にある特定の塩）、特定のものを指すときは定冠詞 the を使います。", rule: "定冠詞 the と不定冠詞 a/an の使い分け", kp: ["話し手と聞き手が同じものを指していると分かる場合 → the", "不特定のものを指す場合 → a/an"] },
  { id: "g468", diff: "lv2", axis: "form", tags: ["grammar", "little", "few", "quantifier", "count", "noncount"], stem: "There are very ___ tickets left for the championship game, so buy them soon.", ja: "チャンピオンシップゲームのチケットはほとんど残っていないので、早めに買ってください。", answer: "few", choices: ["few", "little", "less", "much", "any"], expl: "tickets は可算名詞の複数形なので、few を使います。little は不可算名詞を修飾するときに使います。", rule: "littleは不可算名詞、fewは可算名詞を修飾する", kp: ["可算名詞（複数形）→ few", "不可算名詞 → little"] },
  { id: "g469", diff: "lv2", axis: "form", tags: ["eiken3", "eikenpre2", "toeic", "juken"], stem: "The annual book fair is held ___ October every year in this city.", ja: "年次ブックフェアはこの都市で毎年10月に開催される。", answer: "in", choices: ["in", "on", "at", "during", "by"], expl: "月（October）の前には前置詞 in を使います。on は曜日、at は時刻に使います。", rule: "前置詞 on/at/in：時間の使い分け", kp: ["月の前 → in", "曜日の前 → on、時刻の前 → at"] },
  { id: "g470", diff: "lv2", axis: "form", tags: ["grammar", "noun", "count", "noncount", "plural"], stem: "We need to buy new ___ for the conference room before the big meeting.", ja: "大きな会議の前に会議室に新しい家具を購入する必要がある。", answer: "furniture", choices: ["furniture", "furnitures", "furniturings", "a furniture", "some furnitures"], expl: "furniture（家具）は不可算名詞なので複数形にすることはできません。furnitures という形は存在しません。", rule: "可算名詞は複数形になれるが、不可算名詞は原則として複数形にならない", kp: ["furniture は不可算名詞 → 複数形不可", "不可算名詞には -s をつけない"] },
  { id: "g471", diff: "lv3", axis: "tense", tags: ["grammar", "past perfect", "had", "past participle"], stem: "By the time the police arrived at the scene, the suspect ___ already ___.", ja: "警察が現場に到着したとき、容疑者はすでに逃げていた。", answer: "had escaped", choices: ["had escaped", "escaped", "has escaped", "was escaping", "would escape"], expl: "警察の到着（過去）より前に完了した出来事を表すには過去完了形（had + 過去分詞）を使います。by the time と already がヒントです。", rule: "過去完了形は過去の別の出来事よりも前に完了した行為・状態を表す", kp: ["過去の出来事より前の完了 → 過去完了形（had + 過去分詞）", "by the time / before / after などと共に使われる"] },
  { id: "g472", diff: "lv3", axis: "tense", tags: ["grammar", "modal perfect", "could have", "would have", "must have"], stem: "She ___ the flight; her boarding pass was found at the gate.", ja: "彼女はフライトに乗ったに違いない。搭乗券がゲートで見つかった。", answer: "must have taken", choices: ["must have taken", "must of taken", "must took", "must has taken", "must take"], expl: "過去の出来事についての強い推測を表すには must have + 過去分詞を使います。must of という形は誤りです。", rule: "could have / would have / must haveの後には過去分詞を置く（'of'は誤り）", kp: ["過去の推測・後悔 → must/could/would + have + 過去分詞", "'of' は 'have' の代わりに使えない（誤り）"] },
  { id: "g473", diff: "lv4", axis: "logic", tags: ["grammar", "which", "non-defining", "clause reference"], stem: "He missed the deadline for the report, ___ disappointed his supervisor greatly.", ja: "彼は報告書の締め切りに間に合わなかった。それは上司をとても失望させた。", answer: "which", choices: ["which", "that", "what", "this", "it"], expl: "前の節全体（締め切りに間に合わなかったこと）を先行詞とする非制限用法の関係節では which を使います。that はこの用法では使えません。", rule: "節全体を先行詞とする非制限用法の関係節にはwhichを使う", kp: ["前の節全体を指す非制限用法 → which", "that は節全体を先行詞にする非制限用法には使えない"] },
  { id: "g474", diff: "lv4", axis: "trap", tags: ["eiken2", "toeic"], stem: "The doctor recommended that the patient ___ more physical activity each week.", ja: "医師は患者が毎週もっと身体活動をするよう勧めた。", answer: "do", choices: ["do", "does", "did", "to do", "doing"], expl: "recommend that の後の節では仮定法現在（動詞の原形）を使います。主語が the patient（三人称単数）でも does ではなく原形の do が正しいです。", rule: "suggest/recommend + that S + 原形", kp: ["recommend / suggest / insist + that + S + 動詞の原形（仮定法現在）", "三人称単数でも -s はつけない"] },
  { id: "g475", diff: "lv4", axis: "form", tags: ["toeic", "eiken2"], stem: "The survey results showed sales of ten, ___, and twenty units across the three regions.", ja: "調査結果は3地域での販売数がそれぞれ10、15、20個であることを示した。", answer: "fifteen", choices: ["fifteen", "15", "the 15", "a fifteen", "15th"], expl: "同一文内で数字を列挙するときは、表記形式（スペルアウトか数字か）を統一する必要があります。ten と twenty がスペルアウトなので、fifteen と書くのが正しいです。", rule: "同一文中の数字の一貫性", kp: ["同一文・同一文脈の数字は表記形式を統一する", "ten, twenty と並ぶなら fifteen（スペルアウト）"] }
];
